  '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "jeju-southern-top-unesco-spots-tour", "locale": "ja", "product_id": "jeju-southern-top-unesco-spots-tour", "seo": {"pageTitle": "済州南部ソギポ シグネチャー日帰りツアー｜AtoC Korea", "metaDescription": "9時間の済州南部少人数日帰りツアー：正房瀑布（チョンバン滝、アジア唯一の海岸直落瀑布）、外突き岩（オェドルゲ）＆オルレ7コース、薬泉寺（ヤクチョンサ）、オソルロックティーミュージアム、漢拏山御乗生岳（オスンセンアク）。", "primaryKeywords": ["済州南部日帰りツアー", "正房瀑布ツアー", "外突き岩 オルレ7コース", "薬泉寺ツアー", "オソルロックティーミュージアムツアー", "漢拏山御乗生岳"], "ogImage": "https://www.atockorea.com/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "title": "済州南部ソギポ シグネチャー日帰りツアー・ほぼ全コース入場無料｜AtoC", "description": "済州南部ソギポ少人数日帰りツアー：正房瀑布 → 外突き岩＆オルレ7コース → 薬泉寺 → ランチ → オソルロックティーミュージアム → 漢拏山御乗生岳。ほぼ全コース入場無料、少人数で進行。"}, "catalog_card": {"thumbnail": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "title": "済州南部ソギポ シグネチャー日帰りツアー", "priceLabel": "", "shortCardDescription": "済州南部ソギポの定番スポットを少人数で巡る日帰りツアー — アジアで唯一海へ直接落ちる正房瀑布、外突き岩の奇岩とオルレ7コースの海岸散策、東アジア最大の寺院・薬泉寺、オソルロックティーミュージアム、そして漢拏山御乗生岳の登山道。済州市内全域と空港を含む4か所のピックアップポイント、英語・中国語の認定ガイド同行、正房瀑布以外はほぼ全コース入場無料、買い物の押し売りなし。", "tags": ["少人数グループ", "済州", "済州南部", "ソギポ", "コスパ抜群", "買い物コースなし"], "rating": 0, "reviewCount": 0, "slug": "jeju-southern-top-unesco-spots-tour", "subtitle": "済州南部ソギポ海岸コース — 正房瀑布、外突き岩のオルレ道、薬泉寺、漢拏山。", "region": "済州南部", "duration": "9時間", "stopsCount": 8, "badges": ["少人数グループ", "済州", "済州南部", "ソギポ", "お手頃価格", "買い物なし"], "heroImage": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp"}, "headlineLine1": "済州南部ソギポ シグネチャー", "headlineLine2": "日帰りツアー", "price": {"amountLabel": "", "originalPriceUsd": null, "salePriceUsd": null, "discountPercent": null, "currency": "USD", "per": "person"}, "hero": {"imageUrl": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "imagePosition": "center 45%", "tagline": "済州南部ソギポ海岸の定番スポットを一日で — 正房瀑布、外突き岩のオルレ道、薬泉寺、オソルロック、漢拏山。ほぼ全コース入場無料。", "pills": ["少人数グループ", "済州"], "meta": {"duration": "約9時間（08:30 最初のお迎え、約18:00 送り届け）", "region": "済州南部", "stops": "8スポット", "rating": 0, "ratingStars": 5}}, "subnavItems": [{"id": "overview", "label": "概要"}, {"id": "itinerary", "label": "旅程"}, {"id": "details", "label": "詳細"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "レビュー"}], "glanceItems": [{"icon": "camera", "label": "撮影スポット評価", "value": "高い", "level": 5}, {"icon": "mountain", "label": "景色", "value": "高い", "level": 5}, {"icon": "footprints", "label": "徒歩", "value": "普通", "level": 3}, {"icon": "cloud-rain", "label": "雨天適性", "value": "限定的", "level": 2}, {"icon": "users", "label": "ファミリー適性", "value": "普通", "level": 3}, {"icon": "gauge", "label": "ペース", "value": "バランス良好", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 1", "caption": "正房瀑布 — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "薬泉寺", "alt": "薬泉寺 — gallery image 2", "caption": "薬泉寺 — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 3", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "漢拏山御乗生岳の登山道", "alt": "漢拏山御乗生岳の登山道 — gallery image 4", "caption": "漢拏山御乗生岳の登山道 — photo 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 5", "caption": "正房瀑布 — photo 5"}, {"id": 6, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 6", "caption": "正房瀑布 — photo 6"}, {"id": 7, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 7", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 7"}, {"id": 8, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 8", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 8"}, {"id": 9, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 9", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 9"}, {"id": 10, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "漢拏山御乗生岳の登山道", "alt": "漢拏山御乗生岳の登山道 — gallery image 10", "caption": "漢拏山御乗生岳の登山道 — photo 10"}, {"id": 11, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "漢拏山御乗生岳の登山道", "alt": "漢拏山御乗生岳の登山道 — gallery image 11", "caption": "漢拏山御乗生岳の登山道 — photo 11"}, {"id": 12, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "漢拏山1100高地", "alt": "漢拏山1100高地 — gallery image 12", "caption": "漢拏山1100高地 — photo 12"}, {"id": 13, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "漢拏山1100高地", "alt": "漢拏山1100高地 — gallery image 13", "caption": "漢拏山1100高地 — photo 13"}, {"id": 14, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "漢拏山1100高地", "alt": "漢拏山1100高地 — gallery image 14", "caption": "漢拏山1100高地 — photo 14"}], "itineraryStops": [{"number": 1, "time": "09:00", "duration": "30分", "name": "ピックアップ（済州市内4か所）", "category": "ピックアップ — 済州市ホテル／ハブ順序", "description": "**ピックアップは済州市中心部の4か所に集約**して運営され、朝の移動動線を最小限に抑えます：当日到着のゲスト向け**済州国際空港（제주공항）**、蓮洞／老衡／旧市街のホテル街向け**済州市庁（제주시청）**、最西端のピックアップポイント**下貴洞（하귀동）**、そしてタプドン海岸近くの済州市東部のオプションピックアップポイント**東門伝統市場（동문시장）**。\n\n順序は下貴 → 空港 → 市庁 → 東門で進んだ後、**国道5.16号（1131号線）に沿って漢拏山の東側を越え、ソギポ南部海岸へ**南下します。ミニコーチは英語ガイドが同行する**少人数制（最大約14名）**で運営されます。\n\n**韓英印刷済みの旅程カード**はピックアップ時に配布し、最初の立ち寄り地で天気の案内を行います。本日のコースはソギポ海岸からスタートし、**一日の最後に国道1100号で漢拏山を越えて済州市へ戻る**ため、**1100号線の通行止め確認**を出発前に実施します — 雪・凍結で閉鎖される場合、最後の漢拏山御乗生岳の立ち寄り地は低地の代替地（通常はミステリーロードまたは済州国立博物館）に変更となります。", "image": null, "highlights": ["**4か所のピックアップ地点** — 空港、市庁、下貴、東門", "西→東の順序で朝のコーチ移動距離を最小化", "英語ガイド同行の**少人数制ミニコーチ（最大14名）**", "バイリンガル旅程カード＋最初の立ち寄りスポットでの天気ブリーフィング", "**1100号線通行止め確認** — 出発前（帰路の漢拏山区間に備えて）", "済州市 → ソギポ正房瀑布の午前の移動時間：約60分（国道5.16号経由）"], "timeUsed": ["下貴ピックアップ 約09:00 — 5分", "空港ピックアップ 約09:10 — 5分", "市庁ピックアップ 約09:20 — 5分", "東門ピックアップ 約09:30 — 5分", "国道5.16号を南下しソギポ海岸方面へ — 約60分"], "whyOnRoute": "4か所のピックアップ地点が済州市の主要ホテル・交通拠点（空港、市中心部、旧市街、市場エリア）をカバーし、ゲストが市内を移動する手間を最小限に抑えます。コースは朝にまずソギポ海岸へ下りて正房瀑布・外突き岩を日中の混雑前に巡り、一日の終わりに国道1100号で漢拏山を越えて済州市へ戻る、効率的な反時計回りの動線です。**1100号線通行止めプロトコル**により、出発前に冬季の帰路状況をご案内します。", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "pickup"}, {"number": 2, "time": "≈ 10:10", "duration": "50分", "name": "正房瀑布（アジア唯一の海岸直落瀑布）", "category": "海岸瀑布 — 瀛州十景・ソギポ地名の由来", "description": "**正房瀑布（チョンバン、正房）は断崖から海へ直接落ちるアジア唯一の瀑布**として知られるソギポの定番スポットです。高さ**23m、幅約8m**の水流が玄武岩の海壁を伝って濃い青の海へ流れ落ち、晴れた日には**森島（ソプソム）と蚊島（ムンソム）**が背景に一緒に収まります。\n\n正房瀑布は漢拏山・天帝淵とともに朝鮮時代の文人が選んだ**瀛州十景（ヨンジュシッキョン、済州の十大絶景）**の一つであり、断崖には**「徐巿過此（ソブルグァチャ）」**の伝説が刻まれています — 秦の始皇帝の命を受けて不老草を探しに来た徐巿（じょふつ）がこの地を過ぎて西へ帰ったという話で、「西帰浦（ソギポ）」という地名の由来となりました。\n\nチケット売り場から瀑布の下までは**約130段の階段**を下りる必要があり、地面は丸い小石と岩で構成されているため、滑りにくい靴が必須です。瀑布の下では水しぶきと海を背景にした記念撮影が人気で、断崖の上の展望台からは森島・蚊島を一望できます。", "image": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "highlights": ["**アジアで唯一海へ直接落ちる瀑布** — 高さ23m／幅約8m", "**瀛州十景（済州十大絶景）**の一つ — 漢拏山・天帝淵とともに選定", "**「徐巿過此」の伝説** — 「西帰浦」地名の由来となった秦始皇・不老草の説話", "晴れた日には**森島・蚊島**を背景にした海岸絶景", "瀑布の下まで**約130段の階段** — 滑り止めの靴が必須", "入場料 **大人 ₩2,000 ／ 青少年 ₩1,000 ／ 7歳未満・65歳以上 無料**", "営業 **09:00–17:40**（閉場30分前に入場締切）、年中開放", "岩場での撮影時は波・滑りに注意 — 安全最優先"], "timeUsed": ["チケット購入＋入口案内 — 約5分", "約130段の階段下り — 約10分", "瀑布＋海岸の岩場での撮影 — 約20分", "階段の上り復帰＋断崖の展望台 — 約15分"], "whyOnRoute": "**ソギポ海岸のオープニングハイライト。** 正房瀑布は午前の早い時間に訪れると、観光バスが押し寄せる前に静かに瀑布の下を楽しめます。外突き岩・オルレ7コースとは車で15分の距離にあり、ソギポ海岸沿いを効率よくつなぎ、一日を力強い海の景色で始めるスポットです。", "_poi_meta": {"poi_key": "jeongbang_falls", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["VisitJeju — Jeongbang Falls official listing", "Seogwipo-si cultural tourism office — Jeongbang Falls", "Jeju Special Self-Governing Province — Yeongjusipgyeong registry", "Cultural Heritage Administration — Seobulgwacha inscription records"]}, "smartNotes": {"photo": "瀑布の下の岩場で水流＋海を一つのフレームに；断崖の上の展望台から森島・蚊島の遠景", "facilities": "トイレ・チケット売り場は入口（階段を下りる前）にあり；瀑布の下には施設なし", "tip": "階段と岩が濡れると非常に滑りやすい — 滑り止めの靴を推奨；ソギポの天地淵瀑布と混同しないようご注意ください"}, "convenience": {"restroom": "入口／チケット売り場エリアで利用可能", "parking": "入口駐車場が利用可能"}, "visitBasics": {"hours": "毎日 09:00–17:40（閉場30分前に入場締切、季節により小幅変動）", "closed": "年中開放（満潮・台風時に臨時通行止めあり）", "admission": "大人 2,000ウォン ／ 青少年 1,000ウォン（7歳未満・65歳以上 無料）", "walking": "普通 — 瀑布の下まで約130段の階段、地面は不揃いな岩；滑りに注意"}, "images": ["/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp"], "imageCredits": [{"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布（アジア唯一の海岸直落瀑布）", "caption": "正房瀑布（アジア唯一の海岸直落瀑布） — photo 1", "alt": "正房瀑布（アジア唯一の海岸直落瀑布） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布（アジア唯一の海岸直落瀑布）", "caption": "正房瀑布（アジア唯一の海岸直落瀑布） — photo 2", "alt": "正房瀑布（アジア唯一の海岸直落瀑布） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布（アジア唯一の海岸直落瀑布）", "caption": "正房瀑布（アジア唯一の海岸直落瀑布） — photo 3", "alt": "正房瀑布（アジア唯一の海岸直落瀑布） — gallery image 3"}]}, {"number": 3, "time": "≈ 11:10", "duration": "50分", "name": "外突き岩（オェドルゲ）＆オルレ7コース海岸散策", "category": "海岸奇岩＋オルレ道 — 済州世界ジオパークのジオサイト", "description": "**外突き岩（オェドルゲ）は約150万年前の火山噴火で形成された高さ約20mの海岸の岩柱**で、大海原に一つだけそびえ立つことから「外（ひとり）・突き（岩）」という名が付きました。「将軍岩」または「ハルマン岩」とも呼ばれ、**ドラマ『宮廷女官チャングムの誓い（大長今）』のロケ地**として広く知られています。外突き岩とソギポの層理海岸断崖は、**済州世界ジオパーク（ユネスコ世界ジオパーク）の公式ジオサイト**の一つです。\n\n外突き岩は**済州オルレ7コース**の上に位置します — 7コースは済州オルレ旅行者センターを出発し法環浦口を経て月坪まで続く約17.6kmの代表的な海岸オルレで、オルレ愛好者に最も愛される「スボンロ」区間が外突き岩付近を通ります。\n\nこのコースでは外突き岩の展望ポイントとともに、**オルレ7コースの海岸散策路の一部を短く歩きます。** 松林の間を抜ける道から外突き岩と森島・蚊島、果てしなく広がる南の海を眺めることができ、正房瀑布の瀑布の景色とはまた違った開放的な海岸景観を楽しめます。**無料開放**、散策路はおおむね平坦ですが一部に自然石の区間があります。", "image": null, "highlights": ["**外突き岩** — 約150万年前に形成された高さ約20mの海岸の岩柱（「将軍岩」）", "ドラマ**『大長今』のロケ地**として有名なソギポ海岸の絶景", "**済州世界ジオパーク（ユネスコ世界ジオパーク）のジオサイト**", "**オルレ7コース**の上 — オルレ愛好者に最も愛される「スボンロ」海岸区間", "松林の道から**外突き岩＋森島・蚊島＋南の海**を眺望", "**無料開放**、年中常時 — 正房瀑布から車で約15分", "散策路はおおむね平坦、一部に自然石の区間 — 歩きやすい靴を推奨"], "timeUsed": ["駐車＋オルレ道への進入 — 約5分", "オルレ7コースの海岸散策路 — 約25分", "外突き岩の展望ポイント＋撮影 — 約15分", "バスへの復帰 — 約5分"], "whyOnRoute": "**ソギポ海岸の2番目のスポットであり、オルレ道体験。** 正房瀑布から車で15分の距離で動線が自然につながり、瀑布（垂直の景色）→ 外突き岩（開放的な海岸パノラマ）へと景色の趣が変わります。短いオルレ7コースの散策は「歩いて出会う済州」の真髄を気軽に味わわせてくれます。", "_poi_meta": {"poi_key": "oedolgae_olle7", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Jeju Olle Foundation — Olle Route 7 official (jejuolle.org)", "VisitJeju — Oedolgae Rock official listing", "Jeju Global Geopark — Oedolgae & Seogwipo layered cliff geosite", "KTO — Dae Jang Geum filming location records"]}, "smartNotes": {"photo": "松林の間の外突き岩＋海のフレーム；展望デッキから森島・蚊島の遠景", "facilities": "入口駐車場にトイレ；海岸散策路の区間には施設が少ない", "tip": "風の強い日が多いので上着を準備；自然石の区間は滑りに注意"}, "convenience": {"restroom": "外突き岩の駐車場エリアで利用可能", "parking": "外突き岩の公営駐車場が利用可能"}, "visitBasics": {"hours": "常時開放（海岸散策路）", "closed": "年中開放（強風・高波時に一部区間の通行止めあり）", "admission": "無料", "walking": "易しい〜普通 — 海岸散策路はおおむね平坦、一部に自然石・階段の区間"}, "images": [], "imageCredits": [], "galleryItems": []}, {"number": 4, "time": "≈ 12:10", "duration": "40分", "name": "薬泉寺（東アジア最大の寺院）", "category": "寺院 — 東アジア最大規模の大寂光殿", "description": "**薬泉寺（ヤクチョンサ、藥泉寺）は敷地122,100㎡の規模で東アジア最大の寺院の一つ**に数えられるソギポ大浦洞の大型寺院です。名前は「薬になる湧き水が流れる寺」という意味で、四季を通じて枯れない薬水が湧く旧「薬水庵」の跡地に建てられました — **慧印（ヘイン）和尚が1981年に着工し1996年に完成**させました。\n\n中心となる法堂の**大寂光殿（テジョックァンジョン）は高さ約30m、延床面積約3,305㎡**に及ぶ東洋最大級の単一法堂で、朝鮮初期の寺院建築様式に倣っています。内部には**高さ5mの毘盧遮那仏（国内最大の木造坐仏）**が4mの台座の上に祀られており、多層の壁面を埋め尽くす数万体の小さな金仏像が圧倒的な壮観を成しています。法堂の前には**18トン規模の梵鐘**があります。\n\n薬泉寺は**済州オルレ7コース（終点）と8コース（始点）が出会う地点**にあり、オルレ愛好者と観光客がともに訪れ、**2006年からテンプルステイ**を運営しています。**入場無料**で、平坦な境内は比較的巡りやすいです。", "image": "/images/tours/yakcheonsa/photo-001.webp", "highlights": ["**東アジア最大級の寺院** — 敷地約122,100㎡", "**大寂光殿** 高さ約30m／延床面積約3,305㎡ — 東洋最大級の単一法堂", "**高さ5mの毘盧遮那仏** — 国内最大の木造坐仏（4mの台座の上）", "多層の壁面を埋める**数万体の金仏像**＋法堂前の**18トンの梵鐘**", "**慧印和尚 1981年着工 → 1996年完成**；「薬水庵」の跡地（薬水が湧く泉）", "**オルレ7コース終点＋8コース始点**が出会う地点", "**2006年からテンプルステイ**を運営", "**入場無料**、平坦な境内 — 正房瀑布エリアから車で約15分"], "timeUsed": ["駐車＋一柱門への進入 — 約5分", "大寂光殿＋毘盧遮那仏＋金仏像の鑑賞 — 約20分", "梵鐘＋境内散策＋薬水 — 約12分", "バスへの復帰 — 約3分"], "whyOnRoute": "**ランチ直前の文化ハイライト。** 正房瀑布・外突き岩の海岸の景色の後に、薬泉寺の圧倒的な大寂光殿の内部がまた違った趣の見どころを加えます。外突き岩から近くランチのレストランに隣接しているため動線が効率的で、入場無料なので負担もありません。寺院の作法（静粛・服装）はガイドがご案内します。", "_poi_meta": {"poi_key": "yakcheonsa_temple", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Yakcheonsa Temple official records", "VisitJeju — Yakcheonsa Temple official listing", "Jeju Olle Foundation — Route 7/8 junction at Yakcheonsa", "Korean Buddhism Templestay — Yakcheonsa program (since 2006)"]}, "smartNotes": {"photo": "大寂光殿の外観の巨大なスケール感；内部の毘盧遮那仏と金仏像の壁面（撮影可否は現地案内で確認）", "facilities": "境内にトイレ・駐車場を完備；薬水は飲用可能", "tip": "法堂の内部は静粛を保ち、帽子を脱ぐなど作法を守る；露出の多い服装は避けてください"}, "convenience": {"restroom": "境内で利用可能", "parking": "寺院の無料駐車場が利用可能"}, "visitBasics": {"hours": "日の出〜日の入り（法堂は常時開放）", "closed": "年中開放", "admission": "無料", "walking": "易しい — 平坦な境内；法堂への進入時に一部階段"}, "images": ["/images/tours/yakcheonsa/photo-001.webp"], "imageCredits": [{"url": "/images/tours/yakcheonsa/photo-001.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "薬泉寺（東アジア最大の寺院）", "caption": "薬泉寺（東アジア最大の寺院） — photo 1", "alt": "薬泉寺（東アジア最大の寺院） — gallery image 1"}]}, {"number": 5, "time": "≈ 13:00", "duration": "60分", "name": "ランチ — 済州南部のローカルグルメ", "category": "昼の休憩 — ソギポ／大浦の地元料理", "description": "**薬泉寺とオソルロックの間の60分の休憩** — ソギポ南部海岸は韓国有数の水産物水揚げ地帯の一つであり、大浦〜安徳エリアは次の目的地から近い距離にあります。基本の食事構成：**ガルチジョリム（タチウオの煮付け）** — 済州は韓国を代表するタチウオの産地で、南の海岸では最も新鮮なタチウオを味わえます；夏季（6〜9月）には**ムルフェ（冷たい刺身スープ）**；または年間を通じて楽しめる**黒豚の炭火焼き**（2015年に**郷土文化遺産第5号**に指定された済州在来の黒豚）。\n\n**ベジタリアン向け代替メニュー**：旬の済州野菜のビビムグクス。ローテーションのレストランのうち1か所で**ハラール対応オプション**を提供 — ピックアップ時にあらかじめお知らせください。ランチのレストランから**オソルロックまでバスで約25分**の距離です。", "image": null, "highlights": ["**済州南部シーフードコリドー** — ソギポ・大浦海岸のレストラン街", "**ガルチジョリム** — 済州は韓国最大のタチウオの産地", "夏季は**ムルフェ**；年間を通じて**黒豚**が選択可能", "黒豚は**郷土文化遺産第5号（2015年）**に指定された品種", "ご要望に応じて**ベジタリアン＋ハラール対応**オプションを提供（ピックアップ時にあらかじめお知らせください）", "**オソルロックまでバスで約25分** — ランチ後は内陸の茶苑へ移動"], "timeUsed": ["ランチのレストランまでバスで約10分", "注文＋食事 — 約45分", "オソルロックまでバスで約25分"], "whyOnRoute": "ソギポ海岸のスポットを巡った後の自然な食事のタイミングです。ランチは午前の海岸散策・寺院見学と午後の茶畑・漢拏山の日程の間に実質的な休憩時間をもたらし、食後は内陸の西広茶苑へ移動します。", "smartNotes": {}, "convenience": {}, "visitBasics": {}}, {"number": 6, "time": "≈ 14:25", "duration": "60分", "name": "オソルロックティーミュージアム＋緑茶畑", "category": "茶文化博物館 — 国内最大の緑茶畑（西広茶苑）", "description": "**オソルロックティーミュージアム（O''Sulloc、「雪と緑の出会い」）**は、韓国最大の化粧品企業**アモーレパシフィック**の茶文化フラッグシップ空間です。創業者**徐成煥（ソ・ソンファン）会長が1979年**に自らこのプロジェクトを切り拓き、済州・西広高原の火山灰農地を茶畑として蘇らせました。今日、**西広茶苑（ソグァンダウォン）**はアモーレパシフィックの済州3つの農場にわたって**年間約700トン**を生産する**国内最大の緑茶畑**です。\n\n博物館の建物は茶畑の真ん中に**2001年に開館**し、ミニマルなデザインで**designboom（デザインブーム）世界10大美術館**に選ばれました。**入場無料**、毎日営業、年間来館者数は約**200万人**。見学は3つのパートに分かれます：**（1）博物館内部** — お茶の製造工程・古代の茶器コレクション・屋上展望台；**（2）ティーハウスカフェ** — 定番の**緑茶ロールケーキ**と**緑茶アイスクリーム**；**（3）茶畑の散策路** — 茶の木の間の砂利道（夕日の撮影スポット）。\n\n**イニスフリー済州ハウス**（アモーレパシフィックのナチュラルブランド）は徒歩5分の距離にあり入場無料、みかん石けんDIYワークショップへの任意参加（₩15,000）が可能です。", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**アモーレパシフィック**の代表ブランド — 創業者・徐成煥が**1979年**に済州での茶栽培を開拓", "**西広茶苑 ＝ 国内最大の緑茶畑**；年間約700トン生産", "博物館**2001年開館** — designboom選出 世界10大美術館（建築部門）", "**入場無料**、年間来館者数約200万人", "**緑茶ロールケーキ**＋**緑茶アイスクリーム** ＝ カフェの定番メニュー", "**イニスフリー済州ハウス**徒歩5分 — 入場無料、みかん石けんDIY 任意 ₩15,000", "茶畑の散策路は**ゴールデンアワー（16:00–17:00）**が撮影に最適", "屋上展望台＋地上の茶畑 — 2つの高さから緑茶畑の構図を楽しめる"], "timeUsed": ["駐車＋入場 — 約5分", "博物館内部＋茶器コレクション — 約20分", "ティーハウスカフェ（ロールケーキ＋アイスクリーム） — 約20分", "緑茶畑の散策路 — 約15分"], "whyOnRoute": "**午後の茶文化のハイライト。** 海岸のスポットと寺院を巡った後、オソルロックの茶畑とカフェが日程に穏やかな休息を加えます。ランチのレストランから内陸へ25分の距離にあり、続いて国道1100号で漢拏山へ向かうのに好都合な立地です — 緑茶畑の間を歩きながらティーデザートを味わうのにちょうど良い午後の時間です。", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Osulloc Tea Museum official site (osulloc.com)", "Amorepacific Corporation — Suh Sung-whan tea reclamation history (1979)", "designboom — Top 10 art museums feature", "VisitJeju — Osulloc Tea Museum official listing"]}, "smartNotes": {"photo": "ティーカップ型のミュージアム棟＋緑茶畑の全景；屋上展望台；茶苑の砂利道の夕日", "facilities": "カフェ（緑茶アイスクリームは必食）、ギフトショップ、隣のイニスフリー済州ハウス、展望デッキ", "tip": "団体バスが押し寄せる前の早い午後が空いている；カフェ・散策を含めて1〜1.5時間の余裕を"}, "convenience": {"restroom": "ミュージアム全域によく整備", "parking": "無料駐車場あり"}, "visitBasics": {"hours": "夏季（4〜10月）09:00–19:00 ／ 冬季（11〜3月）09:00–18:00", "closed": "年中無休（悪天候時に一時的な変動あり）", "admission": "ミュージアム・茶苑は無料；カフェの飲み物・デザート・クラスは別途有料", "walking": "易しい — 平坦な舗装路、ベビーカー・車椅子利用可能"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 1", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 2", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 3", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "オソルロックティーミュージアム＋緑茶畑", "caption": "オソルロックティーミュージアム＋緑茶畑 — photo 4", "alt": "オソルロックティーミュージアム＋緑茶畑 — gallery image 4"}]}, {"number": 7, "time": "≈ 15:55", "duration": "75分", "name": "漢拏山御乗生岳（ユネスコ世界自然遺産）", "category": "ユネスコ火山地質 — 漢拏山御乗生岳の登山道（三重自然指定）", "description": "**御乗生岳（オスンセンアク、1,169m）**は、於里牧（オリモク）登山案内所付近からスタートする漢拏山中腹の短い火山スコリア丘（オルム）の登山道です。漢拏山は韓国最高峰であり、**ユネスコ世界自然遺産（2007年）・生物圏保護区（2002年）**で、このコースは山頂登山をせずとも漢拏山を体験できる手頃な方法です。\n\n本日のコースはオソルロックから**国道1100号（済州最高標高の国道）に沿って漢拏山を越えて済州市へ戻る**道筋に御乗生岳を配置しました。登山道は城板岳・観音寺の山頂コースよりはるかに短く**山頂予約制が適用されず**、広い階段と木製デッキで構成されているためスニーカーでも十分です（片道1.3km／標高差約200m）。\n\n晴れた日には上部デッキの展望台から**漢拏山の高地の斜面、済州のオルム群、北の海**を眺めることができ、山頂には**1945年の旧日本軍のトーチカ（陣地）**が残っています。山の天気は急変するため上着の準備を推奨します。**入場無料**で、一日を締めくくる涼しい山の空気が印象的なフィナーレとなります。", "image": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "highlights": ["**漢拏山 ＝ 三重自然指定**：ユネスコ世界自然遺産2007年 ＋ 生物圏保護区2002年 ＋ 国立公園1970年", "**御乗生岳 1,169m** — 漢拏山中腹のオルム（寄生火山）", "**片道1.3km／標高差約200m** — 広い階段＋木製デッキ、スニーカーで十分", "デッキの展望台から**漢拏山の斜面・オルム群・北の海**を眺望", "山頂に**1945年の旧日本軍のトーチカ（陣地）**が残存 — 珍しい高地の遺構", "**入場無料**＋無料駐車；山頂予約不要（白鹿潭コースは1日1,000名制限）", "往復約**60–75分** — 国道1100号で漢拏山を越えて済州市へ戻る動線", "高地の気象変化が速い — 上着の準備を推奨"], "timeUsed": ["於里牧駐車場＋トイレ＋登山道案内 — 約10分", "片道1.3kmのデッキ区間の登り — 約25分", "山頂デッキ＋撮影＋トーチカ見学 — 約15分", "下山 — 約20分", "余裕時間／集合 — 約5分"], "whyOnRoute": "**済州南部コースの漢拏山フィナーレ。** 御乗生岳は日帰りツアーの規模に適した本格的な山の体験をもたらし、オソルロックから国道1100号で漢拏山を越えて済州市へ戻る道筋に自然に位置します。海岸で始まった一日をユネスコの火山景観で締めくくります。冬季の積雪で1100号線が通行止めになる場合、低地の代替地に変更されることがあります。", "_poi_meta": {"poi_key": "hallasan_eoseungsaengak", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)", "UNESCO Biosphere Reserve — Jeju Island (2002 designation)", "Hallasan National Park Administration — Eoseungsaengak trail official", "Korea National Park Service — Hallasan visitor management records"]}, "smartNotes": {"photo": "上部展望台の広角撮影が効果的；晴れた日には済州市まで眺望；トーチカ遺構の記録ショット", "facilities": "施設は於里牧入口に集中；コースの途中にはなし", "tip": "ゆったりした散策よりも景観に集中した探訪コース；高地の気象変化が速い — 出発前に1100号線・天気を確認"}, "convenience": {"restroom": "於里牧入口エリアで利用可能", "parking": "於里牧駐車場が利用可能（無料）"}, "visitBasics": {"hours": "登山道入場 05:00から（季節により変動、夏季は延長）", "closed": "天候により変動（11〜3月は積雪・濃霧・強風による通行止めが多い）", "admission": "無料", "walking": "普通 — 距離は短いが階段・登りの区間あり"}, "images": ["/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "/images/tours/hallasan-eoseungsaengak/photo-003.webp"], "imageCredits": [{"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "漢拏山御乗生岳（ユネスコ世界自然遺産）", "caption": "漢拏山御乗生岳（ユネスコ世界自然遺産） — photo 1", "alt": "漢拏山御乗生岳（ユネスコ世界自然遺産） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "漢拏山御乗生岳（ユネスコ世界自然遺産）", "caption": "漢拏山御乗生岳（ユネスコ世界自然遺産） — photo 2", "alt": "漢拏山御乗生岳（ユネスコ世界自然遺産） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "漢拏山御乗生岳（ユネスコ世界自然遺産）", "caption": "漢拏山御乗生岳（ユネスコ世界自然遺産） — photo 3", "alt": "漢拏山御乗生岳（ユネスコ世界自然遺産） — gallery image 3"}]}, {"number": 8, "time": "≈ 17:40", "duration": "40分", "name": "降車（済州市内5か所）", "category": "降車 — 済州市ハブ順序", "description": "**降車は午前のピックアップと同じ順序で進行し、1つのオプションが追加されます**：東門伝統市場 → 済州市庁 → 下貴洞 → 済州国際空港、市庁の前に蓮洞／老衡のホテルエリアのゲスト向けオプション停車を含む（5番目の降車地点）。御乗生岳から**国道1100号で漢拏山を下りて済州市へ戻ります**。到着予定：東門 〜18:30、市庁 〜18:40、蓮洞 〜18:45、下貴 〜18:55、空港 〜19:05。\n\n**済州国際空港発の同日夜のフライト**は通常ご利用可能です（最終出発 〜21:30）。車内Wi-Fiは全区間利用可能で、ドライバーがお客様のご希望のショップ・ホテルへの調整に対応します。", "image": null, "highlights": ["**5か所の降車地点** — 東門、市庁、蓮洞／老衡、下貴、空港", "**東門伝統市場** — 任意のディナー＋みかん関連商品のショッピング", "到着予定：東門 〜18:30 → 空港 〜19:05", "**済州国際空港発の同日夜のフライト**は通常ご利用可能（最終出発 〜21:30）", "車内Wi-Fi＋ホテル・ショップへの柔軟なドライバー調整"], "timeUsed": ["御乗生岳 → 国道1100号 → 東門 — 約40分", "東門降車 — 5分", "→ 市庁 — 10分、降車 — 5分", "→ 蓮洞 → 下貴 → 空港 — 順次進行"], "whyOnRoute": "降車は国道1100号で漢拏山を下りて済州市内へ戻る帰路に沿って進行します。夜のフライトをご利用のお客様は、ガイドにあらかじめお知らせいただければ、最終停車時間をスムーズに調整いたします。", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "dropoff"}], "routeFlowStops": [{"name": "済州市内＋空港ピックアップ", "type": "origin", "theme": "出発"}, {"name": "正房瀑布", "type": "primary", "theme": "瀑布"}, {"name": "外突き岩＆オルレ7コース", "type": "primary", "theme": "海岸"}, {"name": "薬泉寺", "type": "primary", "theme": "寺院"}, {"name": "昼食", "type": "meal", "theme": "食事"}, {"name": "オソルロックティーミュージアム", "type": "secondary", "theme": "文化"}, {"name": "漢拏山御乗生岳（ユネスコ）", "type": "primary", "theme": "火山"}, {"name": "済州市内での降車（5か所選択可）", "type": "return", "theme": "帰着"}], "routePhases": [{"phase": "ソギポ海岸の朝", "duration": "約2時間", "description": "正房瀑布（アジア唯一の海岸直落瀑布）と外突き岩・オルレ7コースの海岸散策。"}, {"phase": "寺院＋昼食", "duration": "約1時間40分", "description": "東アジア最大の寺院・薬泉寺を見学後、済州南部の地元ランチ。"}, {"phase": "お茶でフィナーレ", "duration": "約1時間", "description": "オソルロックティーミュージアムと国内最大の西広茶苑。"}, {"phase": "漢拏山フィナーレ", "duration": "約1時間15分", "description": "国道1100号で漢拏山を越えながら御乗生岳の登山道（ユネスコ）。"}, {"phase": "帰路", "duration": "約40分", "description": "国道1100号 → 5か所の降車地点を経由して済州市へ。"}], "routeShapeIntro": {"title": "この日の流れ", "subtitle": "朝にソギポ南部海岸へ下りて正房瀑布と外突き岩・オルレ道を巡り、東アジア最大の寺院・薬泉寺とランチ、オソルロックティーミュージアムを経て、一日の終わりに国道1100号で漢拏山を越えながら御乗生岳の登山道で締めくくる反時計回りのコースです。瀑布・海岸・寺院・茶畑・火山を一度に体験できるよう設計された一日です。"}, "whyTourWorks": {"bestFor": ["この地域への初めての訪問者", "カップル・新婚旅行者", "大人連れのご家族", "海岸散策とオルレ道を楽しむ活動的な旅行者", "寺院・茶文化など韓国文化に関心のある旅行者"], "lessIdealFor": ["歩行を最小限に抑えたい旅行者", "ベビーカーを使うグループ", "当日のフライトまで時間的余裕がない旅行者"], "routeLogicSections": [{"title": "このコースがこのように構成されている理由", "icon": "route", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "items": [{"label": "ほぼ全コース入場無料 — 正房瀑布のみ ₩2,000", "detail": "外突き岩・オルレ7コース、薬泉寺、オソルロック、漢拏山御乗生岳はすべて無料で、正房瀑布の入場料（大人 ₩2,000）のみが基本料金に含まれます。ほとんどの済州団体ツアーが1人あたり ₩15,000〜₩20,000 の入場料を別途徴収するのとは対照的に、当日の唯一の実質的な追加費用はランチ（約 ₩15,000）のみです。"}, {"label": "明確な「ショッピングなし」ポリシー", "detail": "運営者は明確なショッピングなし条項を公表しています — 高麗人参店やコスメショッピングモールへの寄り道、コミッション型のランチ場所はありません。コース上のすべての立ち寄り地は実際の観光スポットです。東門市場での降車はツアー終了後の自由見学であり、強制的な立ち寄りではありません。"}, {"label": "海岸で始まり漢拏山で締めくくる動線", "detail": "朝の早い時間にソギポ海岸（正房瀑布・外突き岩）を団体バスが押し寄せる前に巡り、寺院・ランチ・茶畑を経て、一日の終わりに国道1100号で漢拏山を越えて済州市へ戻ります。反時計回りのループで同じ道を引き返しません。"}, {"label": "40人乗りバスではなくミニバス形式", "detail": "相乗りミニバス形式はグループ規模を小さく保ち、外突き岩のオルレ道や薬泉寺の境内でガイドのきめ細かなケアを受けられます。大型コミッションバスツアー（30〜40名）とは異なり12〜18名規模で運営され、プライベート料金なしで十分なケアを受けられる最適な人数規模です。"}]}]}, "practicalAccordionItems": [{"id": "inclusions", "title": "含まれるもの", "preview": "エアコン付きミニバス、英語・中国語認定ガイド、正房瀑布入場料…", "content": ["エアコン付きミニバス、英語・中国語認定の通訳ガイド、正房瀑布入場料、燃料費・通行料・駐車料金。", "外突き岩・オルレ7コース、薬泉寺、オソルロック、漢拏山御乗生岳はすべて入場無料です。", "含まれないもの：昼食（約 ₩15,000）、飲み物、チップ。", "当日の唯一の実質的な追加費用はランチのみ — ほぼ全コース入場無料の構成です。"]}, {"id": "pickup", "title": "乗降場所", "preview": "4か所での順次ピックアップ：オーシャンスイーツ済州（08:30）→ 済州空港 第3ゲート、3階…", "content": ["4か所での順次ピックアップ：オーシャンスイーツ済州（08:30）→ 済州空港 第3ゲート・3階国内線出発ロビー（08:45）→ ロッテシティホテル済州（08:55）→ 新羅免税店済州店（09:05）。", "ご予約時に最寄りの乗車場所をお選びください。", "出発10分前にはご集合ください。10分以上の遅刻は返金不可となります。", "出発前日にWhatsAppにて確認のご連絡をいたします。"]}, {"id": "walking", "title": "徒歩・地形について", "preview": "普通の難易度。", "content": ["普通の難易度。", "正房瀑布は瀑布の下まで約130段の階段を下りて上ります（岩場の滑りに注意）。", "外突き岩・オルレ7コースはおおむね平坦な海岸散策路で、一部に自然石の区間があります。", "薬泉寺は平坦な境内、法堂への進入時に一部階段。", "オソルロックは平坦な地形でベビーカー利用が可能です。", "漢拏山御乗生岳は片道1.3kmの木製階段の登りで、往復約60〜75分かかります。", "徒歩合計約4km。", "歩きやすいつま先の閉じた靴が必須；滑り止めのトレッキングシューズを推奨します。"]}, {"id": "cancellation", "title": "キャンセルについて", "preview": "ピックアップの24時間前まで無料キャンセル可能。", "content": ["ピックアップの24時間前まで無料キャンセル可能。", "当日キャンセルおよび無断欠席は返金不可。", "漢拏山御乗生岳は大雪または登山道・1100号線の通行止め時に、漢拏山の低地の代替地（ミステリーロードまたは済州国立博物館）に変更される場合があります。"]}, {"id": "drop", "title": "降車オプション", "preview": "5か所の降車地点：新羅免税店（≈17:30）、ロッテシティホテル（≈17:35）、済州空港…", "content": ["5か所の降車地点：新羅免税店（≈17:30）、ロッテシティホテル（≈17:35）、済州空港（≈17:40）、オーシャンスイーツ（≈17:45）、東門伝統市場（≈18:00）。", "東門市場は降車のみ可能で、オペレーターは市場内へは同行しません。", "黒豚通りは東門市場から徒歩5分です。"]}, {"id": "children", "title": "お子様とアクセシビリティ", "preview": "全年齢のお子様歓迎。", "content": ["全年齢のお子様歓迎。", "正房瀑布（階段）と漢拏山御乗生岳（連続した木製階段）はベビーカー利用が不可です。", "外突き岩・オルレ道、薬泉寺、オソルロックはおおむね利用可能です。", "正房瀑布・御乗生岳は階段により車椅子のアクセスが制限され、薬泉寺・オソルロックはおおむね利用可能です。", "ご予約の際に移動に関するご事情をあらかじめお知らせください。"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "季節の注意事項をご参照ください"}, "tomorrow": {"temp": "—", "label": "季節の注意事項をご参照ください"}, "_seasonalSummary": "Jeju has Korea''s mildest climate — coastal areas rarely freeze in winter, and summers are humid but moderated by sea breeze. The Hallasan trailhead is 5–10°C colder than coastal Jeju year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "8–22°C", "notes": "Cherry blossoms in early April. Great season for the Hallasan Eoseungsaengak trail and the Seogwipo coastal walks (Jeongbang Falls, Oedolgae, Olle 7)."}, {"season": "Summer (Jun–Aug)", "range": "22–30°C", "notes": "Humid; afternoon showers common. Jeongbang Falls and the Oedolgae coast stay cooler with the sea breeze."}, {"season": "Autumn (Sep–Nov)", "range": "10–24°C", "notes": "Best season — clear and mild, with the sharpest Oedolgae coast and Hallasan summit views."}, {"season": "Winter (Dec–Feb)", "range": "3–10°C", "notes": "Mild on the coast; Hallasan upper slopes can have snow and the 1100 Road may close."}]}, "seasonalVariations": [{"season": "春", "description": "ソギポ海岸やコースの各所に桜・菜の花が咲き、漢拏山御乗生岳の探訪に最適な季節です。"}, {"season": "夏", "description": "正房瀑布と外突き岩の海岸は涼しい海風で人気の避暑地です。午後のにわか雨が多いので雨具をご準備ください。"}, {"season": "秋", "description": "晴れて涼しく、撮影に最適な季節です。外突き岩の海岸と漢拏山の眺望が最も鮮明です。"}, {"season": "冬", "description": "海岸は温和ですが、漢拏山の高地には雪が降ることがあります。積雪時には1100号線・御乗生岳が通行止めになる場合があります。"}], "bookingTrustItems": [{"icon": "check-circle", "title": "現地認定オペレーター", "description": "完全保険付き公認韓国ツアーオペレーター", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600", "body": "現地認定オペレーター — 済州南部ソギポ海岸の定番スポットを少人数で巡るコスパの良いコースです。"}, {"icon": "route", "title": "ルートスペシャリスト", "description": "画一的な周遊コースではなく、自ら設計したオリジナル日程", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "body": "ほぼ全コース入場無料：外突き岩・オルレ7コース（無料）、薬泉寺（無料）、オソルロック（無料）、漢拏山御乗生岳（無料） — 正房瀑布（₩2,000）のみ基本料金に含む。"}, {"icon": "users", "title": "快適なグループ規模", "description": "ルートに最適な人数構成", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600", "body": "少人数制ミニコーチで進行し、外突き岩のオルレ道や薬泉寺の境内、正房瀑布の階段道を快適に楽しめます — 大型バスツアーとは大きく異なります。"}], "bookingSupportSteps": [{"timing": "即時", "title": "即時予約確定", "detail": "日程概要付きの予約確認書を送付", "description": "済州市内ホテルのピックアップ情報付きで即時予約確定（市内は無料；市外は +₩70,000）。"}, {"timing": "12時間前", "title": "12時間前リマインダー", "detail": "天気情報およびルート変更のお知らせ", "description": "正房瀑布・外突き岩の海岸コンディションおよび漢拏山1100号線の状況の事前案内。"}, {"timing": "前日の夜", "title": "最終ピックアップ案内", "detail": "正確なピックアップ時間とドライバーの連絡先を確認", "description": "前日の夜に最終ピックアップ時間の確定をご案内。"}, {"timing": "ツアー当日の朝", "title": "当日のルート案内", "detail": "リアルタイムの状況に基づく朝のブリーフィング", "description": "朝の天気案内および漢拏山御乗生岳・1100号線の状況のお知らせ。"}, {"timing": "ツアー中", "title": "各スポットでのヒント", "detail": "各スポットでのリアルタイム案内", "description": "ガイドが正房瀑布の「徐巿過此」の地名伝説、外突き岩の形成と『大長今』のロケ地、東アジア最大の寺院・薬泉寺、1979年のアモーレパシフィックによるオソルロック設立の背景、漢拏山の楯状火山の特性を解説します。"}, {"timing": "ツアー後", "title": "ツアー後のサポート", "detail": "フォローアップとおすすめ情報", "description": "降車後にツアー満足度アンケートのご依頼が送付されます。"}], "staticQuestions": [{"id": "q1", "question": "このツアーは年間を通じて運行していますか？", "answer": "はい。このルートは年間を通じて毎日運行しています。季節によってソギポ海岸の雰囲気や漢拏山の眺望は変わりますが、一日の日程の流れは同じです。冬季の積雪時には漢拏山御乗生岳が低地の代替地に変更される場合があります。"}, {"id": "q2", "question": "正房瀑布と漢拏山での歩行は大変ですか？", "answer": "正房瀑布は瀑布の下まで約130段の階段を下りて上り、漢拏山御乗生岳は片道1.3kmの木製階段の登り（往復約60〜75分）です。つま先の閉じた歩きやすいスニーカーがあれば十分で、専門的な登山装備は不要です。このルートには漢拏山の山頂（白鹿潭）登山は含まれません。"}, {"id": "q3", "question": "このコースにはどのようなスポットが含まれますか？", "answer": "正房瀑布（アジア唯一の海岸直落瀑布）、外突き岩とオルレ7コースの海岸散策、東アジア最大の寺院・薬泉寺、オソルロックティーミュージアム、そして漢拏山御乗生岳の登山道を巡ります。ソギポ海岸で始まり漢拏山で締めくくる済州南部のシグネチャーコースです。"}, {"id": "q4", "question": "入場料は含まれますか？", "answer": "はい。正房瀑布の入場料（大人 ₩2,000）が基本料金に含まれます。外突き岩・オルレ7コース、薬泉寺、オソルロック、漢拏山御乗生岳はすべて入場無料です。当日の唯一の実質的な追加費用はランチ（約 ₩15,000）のみです。"}, {"id": "q5", "question": "昼食は含まれますか？", "answer": "いいえ — 昼食はお客様のご負担となります（約15,000ウォン）。ガイドが地元のレストランをご紹介し、ご予約時にお知らせいただければベジタリアン・ビーガン・ハラール・アレルギーへの食事のご要望にも対応いたします。"}, {"id": "q6", "question": "空港ピックアップの際に荷物を持ち込むことはできますか？", "answer": "はい。事前にオペレーターへ荷物量をお知らせください。ミニコーチには専用の荷物スペースが設けられており、早朝便でご到着の旅行者も荷物を持ったままそのままツアーにご参加いただけます。"}, {"id": "first-time", "question": "済州南部を初めて訪れる方に良い選択ですか？", "answer": "はい — 一日でソギポ海岸、寺院、茶畑、漢拏山まで、このエリアの最も個性的なスポットをバランスよく巡ることができます。"}, {"id": "walking", "question": "徒歩の移動は大変ですか？", "answer": "正房瀑布の階段と漢拏山御乗生岳の登りがある活動的な一日の日程ですが、外突き岩のオルレ道や薬泉寺・オソルロックは比較的平坦です。"}, {"id": "family", "question": "このツアーはファミリー向けですか？", "answer": "終日の移動に対応できるお子様がいるご家族には適しています。海岸散策と寺院・茶畑はお子様も気軽に楽しめます。"}, {"id": "seniors", "question": "高齢者も快適に参加できますか？", "answer": "正房瀑布の階段と御乗生岳の登りに慣れた、アクティブなシニアの方にお勧めします。外突き岩・薬泉寺・オソルロックは比較的快適です。"}, {"id": "children", "question": "推奨される最低年齢は何歳ですか？", "answer": "10歳以上が目安で、終日続く日程と上記の徒歩に関するご案内に対応できるお子様に適しています。"}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "日程と参加人数を選択して、空き状況をリアルタイムで確認し、ご予約を完了してください。", "price": {"amountLabel": "", "originalPriceUsd": null, "salePriceUsd": null, "discountPercent": null, "currency": "USD", "per": "person"}}, "pickup_dropoff": {"departure": [{"order": 1, "time": "08:30", "name": "オーシャンスイーツ済州ホテル", "type": "hotel", "note": "ホテルのロビーでお待ちください。ガイドはアトックコリアのサインを持っています。", "lat": 33.51823, "lng": 126.52317}, {"order": 2, "time": "08:45", "name": "済州国際空港（3階、ゲート3）", "type": "airport", "note": "3階出発エリアです。ゲート3の案内表示に従ってください。", "lat": 33.50708, "lng": 126.49343}, {"order": 3, "time": "08:55", "name": "ロッテシティホテル済州", "type": "hotel", "note": "メインロビーでお待ちください。ガイドがお名前でお呼びします。", "lat": 33.4906, "lng": 126.48643}, {"order": 4, "time": "09:05", "name": "新羅免税店（済州店）", "type": "shopping", "note": "新羅免税店済州店のメインエントランス外でお待ちください。", "lat": 33.48631, "lng": 126.48739}], "return": [{"order": 1, "name": "オーシャンスイーツ済州ホテル", "type": "hotel", "lat": 33.51823, "lng": 126.52317}, {"order": 2, "name": "済州国際空港（3階、ゲート3）", "type": "airport", "lat": 33.50708, "lng": 126.49343}, {"order": 3, "name": "ロッテシティホテル済州", "type": "hotel", "lat": 33.4906, "lng": 126.48643}, {"order": 4, "name": "新羅免税店（済州店）", "type": "shopping", "lat": 33.48631, "lng": 126.48739}, {"order": 5, "name": "東門伝統市場", "type": "market", "lat": 33.51204, "lng": 126.52828}], "notes": ["帰着は通常17:30〜18:00頃です。"]}, "matching_profile": {"profile_version": 7, "is_active": true, "product_id": "jeju-southern-top-unesco-spots-tour", "product_type": "small_group", "route_type": "