  '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "jeju-southern-top-unesco-spots-tour", "locale": "zh", "product_id": "jeju-southern-top-unesco-spots-tour", "seo": {"pageTitle": "济州南部西归浦招牌一日游 | AtoC Korea", "metaDescription": "9小时济州南部小团一日游：正房瀑布（亚洲唯一直落入海的瀑布）、外突岩与偶来7号路线、药泉寺、雪绿茶博物馆（Osulloc）、汉拿山御乘生岳。", "primaryKeywords": ["济州南部一日游", "正房瀑布游览", "外突岩偶来7号路线", "药泉寺游览", "雪绿茶博物馆游览", "汉拿山御乘生岳"], "ogImage": "https://www.atockorea.com/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "title": "济州南部西归浦招牌一日游 · 几乎全程免费入场 | AtoC", "description": "济州南部西归浦小团一日游：正房瀑布 → 外突岩与偶来7号路线 → 药泉寺 → 午餐 → 雪绿茶博物馆 → 汉拿山御乘生岳。几乎全程免费入场，小团出行。"}, "catalog_card": {"thumbnail": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "title": "济州南部西归浦招牌一日游", "priceLabel": "", "shortCardDescription": "畅游济州南部西归浦标志性景点的小团一日游——亚洲唯一直落入海的正房瀑布、外突岩奇岩与偶来7号路线海岸漫步、东亚最大寺院药泉寺、雪绿茶博物馆，以及汉拿山御乘生岳步道。提供济州市区及机场四处上车地点，配备持证英语/中文导游，除正房瀑布外几乎全程免费入场，无购物压力。", "tags": ["小团出行", "济州", "济州南部", "西归浦", "性价比高", "无购物环节"], "rating": 0, "reviewCount": 0, "slug": "jeju-southern-top-unesco-spots-tour", "subtitle": "济州南部西归浦海岸线——正房瀑布、外突岩偶来路线、药泉寺、汉拿山。", "region": "济州南部", "duration": "9小时", "stopsCount": 8, "badges": ["小团出行", "济州", "济州南部", "西归浦", "价格实惠", "无购物"], "heroImage": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp"}, "headlineLine1": "济州南部西归浦招牌", "headlineLine2": "一日游", "price": {"amountLabel": "", "originalPriceUsd": null, "salePriceUsd": null, "discountPercent": null, "currency": "USD", "per": "person"}, "hero": {"imageUrl": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "imagePosition": "center 45%", "tagline": "一天畅游济州南部西归浦海岸的标志性景点——正房瀑布、外突岩偶来路线、药泉寺、雪绿茶、汉拿山。几乎全程免费入场。", "pills": ["小团游", "济州"], "meta": {"duration": "约9小时（08:30首次接送，约18:00返回）", "region": "济州南部", "stops": "8个景点", "rating": 0, "ratingStars": 5}}, "subnavItems": [{"id": "overview", "label": "概览"}, {"id": "itinerary", "label": "行程安排"}, {"id": "details", "label": "详情"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "评价"}], "glanceItems": [{"icon": "camera", "label": "拍照适宜度", "value": "高", "level": 5}, {"icon": "mountain", "label": "风景", "value": "高", "level": 5}, {"icon": "footprints", "label": "步行强度", "value": "适中", "level": 3}, {"icon": "cloud-rain", "label": "雨天适宜度", "value": "有限", "level": 2}, {"icon": "users", "label": "家庭适宜度", "value": "适中", "level": 3}, {"icon": "gauge", "label": "行程节奏", "value": "均衡", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 1", "caption": "正房瀑布 — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "药泉寺", "alt": "药泉寺 — gallery image 2", "caption": "药泉寺 — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪绿茶博物馆 + 绿茶田", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 3", "caption": "雪绿茶博物馆 + 绿茶田 — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "汉拿山御乘生岳步道", "alt": "汉拿山御乘生岳步道 — gallery image 4", "caption": "汉拿山御乘生岳步道 — photo 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 5", "caption": "正房瀑布 — photo 5"}, {"id": 6, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 6", "caption": "正房瀑布 — photo 6"}, {"id": 7, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪绿茶博物馆 + 绿茶田", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 7", "caption": "雪绿茶博物馆 + 绿茶田 — photo 7"}, {"id": 8, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪绿茶博物馆 + 绿茶田", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 8", "caption": "雪绿茶博物馆 + 绿茶田 — photo 8"}, {"id": 9, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪绿茶博物馆 + 绿茶田", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 9", "caption": "雪绿茶博物馆 + 绿茶田 — photo 9"}, {"id": 10, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "汉拿山御乘生岳步道", "alt": "汉拿山御乘生岳步道 — gallery image 10", "caption": "汉拿山御乘生岳步道 — photo 10"}, {"id": 11, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "汉拿山御乘生岳步道", "alt": "汉拿山御乘生岳步道 — gallery image 11", "caption": "汉拿山御乘生岳步道 — photo 11"}, {"id": 12, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "汉拿山1100高地", "alt": "汉拿山1100高地 — gallery image 12", "caption": "汉拿山1100高地 — photo 12"}, {"id": 13, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "汉拿山1100高地", "alt": "汉拿山1100高地 — gallery image 13", "caption": "汉拿山1100高地 — photo 13"}, {"id": 14, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "汉拿山1100高地", "alt": "汉拿山1100高地 — gallery image 14", "caption": "汉拿山1100高地 — photo 14"}], "itineraryStops": [{"number": 1, "time": "09:00", "duration": "30分钟", "name": "接送（济州市4个接送点）", "category": "接送 — 济州市酒店/集合点顺序", "description": "**接送点集中在济州市四个中心位置**，以减少早晨的往返绕行：**济州国际机场（제주공항）**供当日抵达的宾客使用；**济州市政厅（제주시청）**毗邻莲洞/老岘洞/旧城区酒店群；**下贵洞（하귀동）**为最西端的接送点；**东门传统市场（동문시장）**为塔洞海滨附近的可选东部济州市接送点。\n\n接送顺序为：下贵 → 机场 → 市政厅 → 东门，随后**沿5.16号公路（1131号国道）翻越汉拿山东侧，南下前往西归浦南部海岸**。迷你巴士为**小团体（最多约14人）**，配备英语导游。\n\n**双语印刷行程卡**于接送时发放，并在第一站进行天气简报。今日行程从西归浦海岸开始，**在一天结束时沿1100号公路翻越汉拿山返回济州市**，因此出发前会进行**1100号公路封路确认**——若因降雪/结冰封路，最后一站汉拿山御乘生岳将改为较低海拔的备选地点（通常为神秘道路或济州国立博物馆）。", "image": null, "highlights": ["**4个接送点** — 机场、市政厅、下贵、东门", "西→东的顺序可最大限度减少早晨的巴士行驶距离", "**小团体迷你巴士（最多14人）**，配备英语导游", "双语行程卡 + 第一站天气简报", "出发前**1100号公路封路检查**（应对返程汉拿山路段）", "济州市 → 西归浦正房瀑布上午车程：约60分钟（经5.16号公路）"], "timeUsed": ["下贵上车约09:00 — 5分钟", "机场上车约09:10 — 5分钟", "市政厅上车约09:20 — 5分钟", "东门上车约09:30 — 5分钟", "经5.16号公路南行前往西归浦海岸 — 约60分钟"], "whyOnRoute": "四个上车点覆盖济州市的主要酒店及交通枢纽（机场、市中心、旧城区、市场区），最大限度减少客人横跨市区的不便。行程上午先南下至西归浦海岸，趁正午人群高峰前游览正房瀑布与外突岩，再在一天结束时沿1100号公路翻越汉拿山返回济州市，是一条高效的逆时针环线。**1100号公路封路应急预案**会在出发前告知客人冬季返程路况。", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "pickup"}, {"number": 2, "time": "≈ 10:10", "duration": "50分钟", "name": "正房瀑布（亚洲唯一直落入海的瀑布）", "category": "海岸瀑布 — 瀛洲十景 · 西归浦地名由来", "description": "**正房瀑布（정방，正房）以瀑布从悬崖直接跌落入海而闻名，是亚洲唯一的此类瀑布**，也是西归浦的标志性景点。**高23米、宽约8米**的水流沿玄武岩海壁倾泻入深蓝大海，晴天时**森岛（섶섬）与蚊岛（문섬）**也一同映入背景。\n\n正房瀑布与汉拿山、天帝渊并列入选朝鲜时代文人评定的**瀛洲十景（영주십경，济州十大名胜）**，崖壁上刻有**\"徐市过此（徐市過此）\"传说**——传说受秦始皇之命寻找长生不老药的徐福曾途经此地，再向西归返，\"西归浦（西歸浦）\"地名便由此而来。\n\n从售票处下到瀑布底部需走**约130级台阶**，地面由圆润的鹅卵石和岩石构成，因此防滑鞋必不可少。瀑布底部以水雾和大海为背景的打卡照颇受欢迎，崖顶观景台则可一览森岛与蚊岛。", "image": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "highlights": ["**亚洲唯一直接跌落入海的瀑布** — 高23米 / 宽约8米", "**瀛洲十景（济州十大名胜）之一** — 与汉拿山、天帝渊一同入选", "**\"徐市过此\"传说** — 衍生出\"西归浦\"地名的秦始皇·长生不老药传说", "晴天可见以**森岛·蚊岛**为背景的海岸绝景", "下至瀑布底部需走**约130级台阶** — 防滑鞋必备", "门票 **成人₩2,000 / 青少年₩1,000 / 7岁以下及65岁以上免费**", "开放时间 **09:00–17:40**（闭园前30分钟停止入场），全年开放", "在岩石地带拍照请留意海浪与湿滑 — 安全第一"], "timeUsed": ["购票 + 入口讲解 — 约5分钟", "下行约130级台阶 — 约10分钟", "瀑布 + 海岸岩石拍照 — 约20分钟", "登台阶返回 + 崖顶观景台 — 约15分钟"], "whyOnRoute": "**西归浦海岸的开篇亮点。** 上午早些时候游览正房瀑布，可趁旅游大巴尚未涌入时从容欣赏瀑布底部。这里距外突岩·偶来7号路线仅15分钟车程，沿西归浦海岸高效衔接，以震撼的海景为一天揭开序幕。", "_poi_meta": {"poi_key": "jeongbang_falls", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["VisitJeju — Jeongbang Falls official listing", "Seogwipo-si cultural tourism office — Jeongbang Falls", "Jeju Special Self-Governing Province — Yeongjusipgyeong registry", "Cultural Heritage Administration — Seobulgwacha inscription records"]}, "smartNotes": {"photo": "在瀑布底部岩石地带将水流与大海收入同一画面；崖顶观景台远眺森岛·蚊岛", "facilities": "卫生间·售票处位于入口（下台阶前）；瀑布底部无配套设施", "tip": "台阶与岩石被打湿后极为湿滑 — 建议穿防滑鞋；请勿与西归浦的天地渊瀑布混淆"}, "convenience": {"restroom": "入口/售票区域可使用", "parking": "入口停车场可使用"}, "visitBasics": {"hours": "每日09:00–17:40（闭园前30分钟停止入场，随季节略有变动）", "closed": "全年开放（满潮·台风时可能临时管制）", "admission": "成人2,000韩元 / 青少年1,000韩元（7岁以下·65岁以上免费）", "walking": "中等 — 下至瀑布底部约130级台阶，地面为不平整岩石；注意湿滑"}, "images": ["/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp"], "imageCredits": [{"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布（亚洲唯一直落入海的瀑布）", "caption": "正房瀑布（亚洲唯一直落入海的瀑布） — photo 1", "alt": "正房瀑布（亚洲唯一直落入海的瀑布） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布（亚洲唯一直落入海的瀑布）", "caption": "正房瀑布（亚洲唯一直落入海的瀑布） — photo 2", "alt": "正房瀑布（亚洲唯一直落入海的瀑布） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布（亚洲唯一直落入海的瀑布）", "caption": "正房瀑布（亚洲唯一直落入海的瀑布） — photo 3", "alt": "正房瀑布（亚洲唯一直落入海的瀑布） — gallery image 3"}]}, {"number": 3, "time": "≈ 11:10", "duration": "50分钟", "name": "外突岩与偶来7号路线海岸漫步", "category": "海岸奇岩 + 偶来路线 — 济州世界地质公园地质名胜", "description": "**外突岩（외돌개）是约150万年前火山喷发形成的高约20米海岸石柱**，孤零零地耸立于茫茫大海之中，因\"外（独自）·突（岩石）·岩\"而得名。它又被称为\"将军岩\"或\"奶奶岩\"，并因**电视剧《大长今》拍摄地**而广为人知。外突岩与西归浦层理海岸断崖是**济州世界地质公园（UNESCO世界地质公园）的官方地质名胜**之一。\n\n外突岩位于**济州偶来7号路线**上——7号路线从济州偶来旅行者中心出发，经法还浦口直至月坪，全长约17.6公里，是最具代表性的海岸偶来路线，偶来徒步者最钟爱的\"秀峰路\"路段便从外突岩附近经过。\n\n本站将在外突岩观景点之外，**短距离步行体验偶来7号路线的部分海岸步道。** 在松林间的小路上，可眺望外突岩与森岛·蚊岛，以及一望无际的南部大海，呈现出与正房瀑布瀑布景观截然不同的开阔海岸风光。**免费开放**，步道大体平坦，部分为天然石路段。", "image": null, "highlights": ["**外突岩** — 约150万年前形成、高约20米的海岸石柱（\"将军岩\"）", "因电视剧 **《大长今》拍摄地** 而闻名的西归浦海岸绝景", "**济州世界地质公园（UNESCO世界地质公园）地质名胜**", "位于 **偶来7号路线** 上 — 偶来徒步者最钟爱的\"秀峰路\"海岸路段", "在松林小径眺望 **外突岩 + 森岛·蚊岛 + 南部大海**", "**免费开放**，全年常开 — 距正房瀑布约15分钟车程", "步道大体平坦，部分天然石路段 — 建议穿舒适鞋履"], "timeUsed": ["停车 + 进入偶来路线 — 约5分钟", "偶来7号路线海岸步道 — 约25分钟", "外突岩观景点 + 拍照 — 约15分钟", "返回大巴 — 约5分钟"], "whyOnRoute": "**西归浦海岸的第二处名胜，也是偶来路线的体验。** 距正房瀑布15分钟车程，动线自然衔接，景致从瀑布（垂直景观）转为外突岩（开阔海岸全景）。短途的偶来7号路线漫步，让人轻松领略\"用脚步邂逅济州\"的精髓。", "_poi_meta": {"poi_key": "oedolgae_olle7", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Jeju Olle Foundation — Olle Route 7 official (jejuolle.org)", "VisitJeju — Oedolgae Rock official listing", "Jeju Global Geopark — Oedolgae & Seogwipo layered cliff geosite", "KTO — Dae Jang Geum filming location records"]}, "smartNotes": {"photo": "松林间外突岩 + 大海的取景；观景台远眺森岛·蚊岛", "facilities": "入口停车场设有卫生间；海岸步道路段配套设施较少", "tip": "多有大风天气，请备外套；天然石路段注意湿滑"}, "convenience": {"restroom": "外突岩停车场区域可使用", "parking": "外突岩公营停车场可使用"}, "visitBasics": {"hours": "常时开放（海岸步道）", "closed": "全年开放（强风·大浪时部分路段可能管制）", "admission": "免费", "walking": "轻松~中等 — 海岸步道大体平坦，部分天然石·台阶路段"}, "images": [], "imageCredits": [], "galleryItems": []}, {"number": 4, "time": "≈ 12:10", "duration": "40分钟", "name": "药泉寺（东亚最大寺院）", "category": "寺院 — 东亚最大规模大寂光殿", "description": "**药泉寺（약천사，藥泉寺）占地122,100平方米，是东亚最大的寺院之一**，位于西归浦大浦洞。寺名意为\"流淌着可入药泉水的寺院\"，建于四季不涸的药泉涌出的旧\"药水庵\"原址之上——**由慧仁法师于1981年动工、1996年竣工**。\n\n中心法堂**大寂光殿（大寂光殿）高约30米、建筑面积约3,305平方米**，是东方最大级别的单体法堂之一，沿袭朝鲜初期寺院建筑风格。殿内供奉着**高5米的毗卢遮那佛（韩国最大木雕坐佛）**，安坐于4米高的莲座之上，多层墙面布满数万尊小型金佛，气势恢宏、蔚为壮观。法堂前还安放着**重达18吨的梵钟**。\n\n药泉寺位于**济州偶来7号路线（终点）与8号路线（起点）的交汇处**，偶来徒步者与游客纷至沓来，并自**2006年起开展寺院寄宿（templestay）**。**免费入场**，寺内地势平坦，游览较为轻松。", "image": "/images/tours/yakcheonsa/photo-001.webp", "highlights": ["**东亚最大级别寺院** — 占地约122,100平方米", "**大寂光殿** 高约30米 / 建筑面积约3,305平方米 — 东方最大级别单体法堂", "**高5米毗卢遮那佛** — 韩国最大木雕坐佛（安坐于4米莲座之上）", "布满多层墙面的 **数万尊金佛** + 法堂前 **18吨梵钟**", "**慧仁法师1981年动工 → 1996年竣工**；建于\"药水庵\"原址（涌出药泉之处）", "**偶来7号路线终点 + 8号路线起点** 的交汇处", "自 **2006年起开展寺院寄宿（templestay）**", "**免费入场**，寺内地势平坦 — 距正房瀑布一带约15分钟车程"], "timeUsed": ["停车 + 进入一柱门 — 约5分钟", "大寂光殿 + 毗卢遮那佛 + 金佛参观 — 约20分钟", "梵钟 + 寺内漫步 + 药泉 — 约12分钟", "返回大巴 — 约3分钟"], "whyOnRoute": "**午餐前的文化亮点。** 在正房瀑布·外突岩的海岸风光之后，药泉寺气势磅礴的大寂光殿内景带来另一番韵味的看点。这里距外突岩很近，又毗邻午餐餐厅，动线高效，且免费入场，毫无负担。导游会讲解寺院礼仪（保持安静·着装）。", "_poi_meta": {"poi_key": "yakcheonsa_temple", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Yakcheonsa Temple official records", "VisitJeju — Yakcheonsa Temple official listing", "Jeju Olle Foundation — Route 7/8 junction at Yakcheonsa", "Korean Buddhism Templestay — Yakcheonsa program (since 2006)"]}, "smartNotes": {"photo": "大寂光殿外观的宏大体量感；殿内毗卢遮那佛与金佛墙面（可否拍摄请以现场指引为准）", "facilities": "寺内卫生间·停车场齐全；药泉可饮用", "tip": "法堂内请保持安静·脱帽等遵守礼仪；请勿穿着过于暴露的服装"}, "convenience": {"restroom": "寺内可使用", "parking": "寺院免费停车场可使用"}, "visitBasics": {"hours": "日出~日落（法堂常时开放）", "closed": "全年开放", "admission": "免费", "walking": "轻松 — 寺内地势平坦；进入法堂时有部分台阶"}, "images": ["/images/tours/yakcheonsa/photo-001.webp"], "imageCredits": [{"url": "/images/tours/yakcheonsa/photo-001.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "药泉寺（东亚最大寺院）", "caption": "药泉寺（东亚最大寺院） — photo 1", "alt": "药泉寺（东亚最大寺院） — gallery image 1"}]}, {"number": 5, "time": "≈ 13:00", "duration": "60分钟", "name": "午餐 — 济州南部本地料理", "category": "午间休憩 — 西归浦 / 大浦本地料理", "description": "**药泉寺与雪绿茶之间60分钟的休憩时间** — 西归浦南部海岸是韩国顶级的海产集散地之一，大浦–安德一带距下一站很近。默认餐食构成：**红烧带鱼** — 济州是韩国主要的带鱼产地，南部海岸可品尝到最新鲜的带鱼；夏季（6~9月）供应**凉拌生鱼片汤（물회）**；或全年皆可享用的**黑猪烤肉**（2015年被指定为**乡土文化遗产第5号**的济州本土黑猪）。\n\n**素食替代选项**：配时令济州蔬菜的韩式拌面。轮换餐厅中的一家提供**清真友好选项** — 请于接送时提前告知。从午餐餐厅**乘车约25分钟即可抵达雪绿茶**。", "image": null, "highlights": ["**济州南部海鲜走廊** — 西归浦·大浦海岸餐厅带", "**红烧带鱼** — 济州是韩国最大的带鱼产地", "夏季供应**凉拌生鱼片汤（물회）**；**黑猪**全年可选", "黑猪为**乡土文化遗产第5号（2015年）**指定品种", "可按需提供**素食 + 清真友好**选项（请于接送时提前告知）", "**乘车约25分钟抵达雪绿茶** — 午餐后前往内陆茶园"], "timeUsed": ["乘车前往午餐餐厅约10分钟", "点餐 + 用餐 — 约45分钟", "乘车前往雪绿茶约25分钟"], "whyOnRoute": "游览西归浦海岸名胜后顺势进入用餐时段。午餐为上午的海岸漫步·寺院参观与下午的茶园·汉拿山行程之间提供了实质的休息时间，餐后便前往内陆的西光茶园。", "smartNotes": {}, "convenience": {}, "visitBasics": {}}, {"number": 6, "time": "≈ 14:25", "duration": "60分钟", "name": "雪绿茶博物馆 + 绿茶田", "category": "茶文化博物馆 — 韩国最大绿茶田（西光茶园）", "description": "**雪绿茶博物馆（O''Sulloc，意为\"邂逅雪与绿\"）**是韩国最大美妆企业**爱茉莉太平洋**的茶文化旗舰空间。创始人**徐成焕会长于1979年**亲自开创这一项目，将济州西光高原的火山灰农地重新开垦为茶田。如今，**西光茶园**已成为爱茉莉太平洋旗下三处济州茶园合计**年产约700吨**的**韩国最大绿茶田**。\n\n博物馆建筑坐落于茶园中央，**2001年开馆**，以极简设计入选**designboom（设计杂志）全球十大美术馆**。**免费入场**，每日运营，年访客量约**200万人次**。参观分为三个部分：**(1) 博物馆室内** — 制茶工艺·古典茶具收藏·屋顶观景台；**(2) 茶屋咖啡厅** — 招牌**绿茶卷蛋糕**与**绿茶冰淇淋**；**(3) 茶园步道** — 茶丛间的砾石小路（日落摄影胜地）。\n\n**悦诗风吟济州之家**（爱茉莉太平洋自然主义品牌）步行5分钟即达，免费入场，并可选择参加橘皮香皂DIY工作坊（₩15,000）。", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**爱茉莉太平洋**旗舰品牌 — 创始人徐成焕于**1979年**开创济州茶叶种植", "**西光茶园 = 韩国最大绿茶田**；年产约700吨", "博物馆 **2001年开馆** — designboom评选全球十大美术馆（建筑类）", "**免费入场**，年访客量约200万人次", "**绿茶卷蛋糕** + **绿茶冰淇淋** = 咖啡厅招牌单品", "**悦诗风吟济州之家**步行5分钟 — 免费入场，可选橘皮香皂DIY₩15,000", "茶园步道在**黄金时段（16:00–17:00）**最适合摄影", "屋顶观景台 + 地面茶田 — 两种高度演绎绿茶田构图"], "timeUsed": ["停车 + 入场 — 约5分钟", "博物馆室内 + 茶具收藏 — 约20分钟", "茶屋咖啡厅（卷蛋糕 + 冰淇淋）— 约20分钟", "绿茶田步道 — 约15分钟"], "whyOnRoute": "**午后茶文化亮点。** 游览海岸名胜与寺院之后，雪绿茶的茶田与咖啡厅为行程增添一段舒缓的休憩。这里距午餐餐厅向内陆25分钟车程，又是接着沿1100号公路前往汉拿山的绝佳位置——正适合午后漫步绿茶田间、品尝茶点甜品。", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Osulloc Tea Museum official site (osulloc.com)", "Amorepacific Corporation — Suh Sung-whan tea reclamation history (1979)", "designboom — Top 10 art museums feature", "VisitJeju — Osulloc Tea Museum official listing"]}, "smartNotes": {"photo": "茶杯造型的博物馆建筑 + 绿茶田全景；屋顶观景台；茶园砾石小路日落", "facilities": "咖啡厅（必尝绿茶冰淇淋）、礼品店、紧邻的悦诗风吟济州之家、观景平台", "tip": "旅游大巴涌入前的午后较为清静；含咖啡厅·漫步建议预留1~1.5小时"}, "convenience": {"restroom": "博物馆各处设施完善", "parking": "提供免费停车"}, "visitBasics": {"hours": "夏季（4~10月）09:00–19:00 / 冬季（11~3月）09:00–18:00", "closed": "全年无休（天气恶劣时可能临时变动）", "admission": "博物馆·茶园免费；咖啡厅饮品·甜点·课程另行收费", "walking": "轻松 — 平坦铺装道路，可通行婴儿车·轮椅"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪绿茶博物馆 + 绿茶田", "caption": "雪绿茶博物馆 + 绿茶田 — photo 1", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪绿茶博物馆 + 绿茶田", "caption": "雪绿茶博物馆 + 绿茶田 — photo 2", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪绿茶博物馆 + 绿茶田", "caption": "雪绿茶博物馆 + 绿茶田 — photo 3", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪绿茶博物馆 + 绿茶田", "caption": "雪绿茶博物馆 + 绿茶田 — photo 4", "alt": "雪绿茶博物馆 + 绿茶田 — gallery image 4"}]}, {"number": 7, "time": "≈ 15:55", "duration": "75分钟", "name": "汉拿山御乘生岳（UNESCO世界自然遗产）", "category": "UNESCO火山地质 — 汉拿山御乘生岳步道（三重自然认定）", "description": "**御乘生岳（1,169米）**是一条始于御里牧游客中心附近的汉拿山侧短途火山锥（岳）步道。汉拿山是韩国最高峰，也是**UNESCO世界自然遗产（2007年）·生物圈保护区（2002年）**，此条路线无需登顶即可体验汉拿山，十分适合。\n\n今日行程将御乘生岳安排在从雪绿茶**沿1100号公路（济州海拔最高的国道）翻越汉拿山返回济州市**的途中。步道远短于城板岳·观音寺登顶路线，且**无需顶峰预约制**，由宽阔台阶与木栈道构成，穿运动鞋即可（单程1.3公里 / 爬升约200米）。\n\n晴天时，从上方观景台可眺望**汉拿山高地山坡、济州的岳丘群、北部大海**，山顶还保存有**1945年日本帝国军碉堡（阵地）**。山地天气变化迅速，建议备好外套。**免费入场**，以清凉的山间空气为一天画上令人难忘的尾声。", "image": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "highlights": ["**汉拿山 = 三重自然认定**：UNESCO世界自然遗产2007 + 生物圈保护区2002 + 国家公园1970", "**御乘生岳1,169米** — 汉拿山侧岳（寄生火山）", "**单程1.3公里 / 爬升约200米** — 宽阔台阶 + 木栈道，穿运动鞋即可", "从栈道观景台眺望 **汉拿山山坡·岳丘群·北部大海**", "山顶保存 **1945年日本帝国军碉堡（阵地）** — 罕见的高地遗迹", "**免费入场** + 免费停车；无需顶峰预约（白鹿潭路线每日限额1,000人）", "往返约 **60–75分钟** — 沿1100号公路翻越汉拿山返回济州市的动线", "高地气候变化迅速 — 建议备外套"], "timeUsed": ["御里牧停车场 + 卫生间 + 步道讲解 — 约10分钟", "单程1.3公里栈道路段上坡 — 约25分钟", "山顶栈道 + 拍照 + 碉堡参观 — 约15分钟", "下山 — 约20分钟", "缓冲时间 / 集合 — 约5分钟"], "whyOnRoute": "**济州南部行程的汉拿山压轴。** 御乘生岳为一日游规模带来真切的登山体验，自然地坐落于从雪绿茶沿1100号公路翻越汉拿山返回济州市的途中。以UNESCO火山景观为始于海岸的一天收尾。若冬季积雪封闭1100号公路，可能改为较低海拔的备选地点。", "_poi_meta": {"poi_key": "hallasan_eoseungsaengak", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)", "UNESCO Biosphere Reserve — Jeju Island (2002 designation)", "Hallasan National Park Administration — Eoseungsaengak trail official", "Korea National Park Service — Hallasan visitor management records"]}, "smartNotes": {"photo": "上方观景台广角拍摄效果佳；晴天可远眺济州市；碉堡遗迹纪念照", "facilities": "配套设施集中在御里牧入口；途中无设施", "tip": "属专注欣赏风景的探访路线，而非悠闲漫步；高地气候变化迅速 — 出发前请确认1100号公路·天气"}, "convenience": {"restroom": "御里牧入口区域可使用", "parking": "御里牧停车场可使用（免费）"}, "visitBasics": {"hours": "步道入场05:00起（随季节变动，夏季延长）", "closed": "视天气而定（11~3月常因积雪·雾·强风管制）", "admission": "免费", "walking": "中等 — 距离虽短，但有台阶·上坡路段"}, "images": ["/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "/images/tours/hallasan-eoseungsaengak/photo-003.webp"], "imageCredits": [{"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "汉拿山御乘生岳（UNESCO世界自然遗产）", "caption": "汉拿山御乘生岳（UNESCO世界自然遗产） — photo 1", "alt": "汉拿山御乘生岳（UNESCO世界自然遗产） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "汉拿山御乘生岳（UNESCO世界自然遗产）", "caption": "汉拿山御乘生岳（UNESCO世界自然遗产） — photo 2", "alt": "汉拿山御乘生岳（UNESCO世界自然遗产） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "汉拿山御乘生岳（UNESCO世界自然遗产）", "caption": "汉拿山御乘生岳（UNESCO世界自然遗产） — photo 3", "alt": "汉拿山御乘生岳（UNESCO世界自然遗产） — gallery image 3"}]}, {"number": 8, "time": "≈ 17:40", "duration": "40分钟", "name": "送客点（济州市内5处）", "category": "送客 — 济州市内枢纽顺序", "description": "**送客路线与上午接客顺序相同，并增设一个选项**：东门传统市场 → 济州市政厅 → 下贵洞 → 济州国际机场，在市政厅前增设一处供莲洞/老岘洞酒店区域住客使用的可选停靠点（第5送客点）。从御乘生岳**沿1100号公路下山返回济州市**。预计到达时间：东门约18:30，市政厅约18:40，莲洞约18:45，下贵约18:55，机场约19:05。\n\n**当天济州国际机场晚班航班**通常可赶上（末班约21:30）。全程提供大巴Wi-Fi，司机会就客人事先提出的商店/酒店调整需求进行协调。", "image": null, "highlights": ["**5个送客点** — 东门、市政厅、莲洞/老岘洞、下贵、机场", "**东门传统市场** — 可选晚餐 + 购买柑橘类产品", "预计到达时间：东门约18:30 → 机场约19:05", "**当天济州国际机场晚班航班**通常可赶上（末班约21:30）", "大巴Wi-Fi + 司机灵活协调酒店/商店调整事宜"], "timeUsed": ["御乘生岳 → 1100号公路 → 东门 — 约40分钟", "东门送客 — 5分钟", "→ 市政厅 — 10分钟，送客 — 5分钟", "→ 莲洞 → 下贵 → 机场 — 依次进行"], "whyOnRoute": "送客沿1100号公路下山返回济州市区的返程进行。有晚班航班的客人请提前告知导游，以便顺利协调最后一站的停靠时间。", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "dropoff"}], "routeFlowStops": [{"name": "济州市区 + 机场接客", "type": "origin", "theme": "出发"}, {"name": "正房瀑布", "type": "primary", "theme": "瀑布"}, {"name": "外突岩与偶来7号路线", "type": "primary", "theme": "海岸"}, {"name": "药泉寺", "type": "primary", "theme": "寺院"}, {"name": "午餐", "type": "meal", "theme": "餐食"}, {"name": "雪绿茶博物馆", "type": "secondary", "theme": "文化"}, {"name": "汉拿山御乘生岳（UNESCO）", "type": "primary", "theme": "火山"}, {"name": "济州市下车（5个选项）", "type": "return", "theme": "返回"}], "routePhases": [{"phase": "西归浦海岸清晨", "duration": "约2小时", "description": "正房瀑布（亚洲唯一直落入海的瀑布）与外突岩·偶来7号路线海岸漫步。"}, {"phase": "寺院 + 午餐", "duration": "约1小时40分钟", "description": "参观东亚最大寺院药泉寺，随后享用济州南部本地午餐。"}, {"phase": "茶（茶）收尾", "duration": "约1小时", "description": "雪绿茶博物馆与韩国最大的西光茶园。"}, {"phase": "汉拿山压轴", "duration": "约1小时15分钟", "description": "沿1100号公路翻越汉拿山，游览御乘生岳步道（UNESCO）。"}, {"phase": "返回", "duration": "约40分钟", "description": "1100号公路 → 经5个下车点返回济州市。"}], "routeShapeIntro": {"title": "全日行程概览", "subtitle": "这是一条逆时针线路：上午南下至西归浦南部海岸，游览正房瀑布与外突岩·偶来路线，途经东亚最大寺院药泉寺与午餐、雪绿茶博物馆，最后在一天结束时沿1100号公路翻越汉拿山，以御乘生岳步道收尾。全天行程精心设计，让您一次尽览瀑布、海岸、寺院、茶田与火山。"}, "whyTourWorks": {"bestFor": ["初次到访当地的游客", "情侣·蜜月旅客", "成人家庭", "喜爱海岸漫步与偶来路线的活跃型旅行者", "对寺院·茶文化等韩国文化感兴趣的旅行者"], "lessIdealFor": ["希望尽量减少步行的旅行者", "携带婴儿车的团体", "当天航班缓冲时间紧张的旅行者"], "routeLogicSections": [{"title": "为何如此规划此路线", "icon": "route", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "items": [{"label": "几乎全程免费入场 — 仅正房瀑布₩2,000", "detail": "外突岩·偶来7号路线、药泉寺、雪绿茶、汉拿山御乘生岳均免费，仅正房瀑布门票（成人₩2,000）计入基础价格。多数济州跟团游会另收每人₩15,000–₩20,000的门票，相比之下，本行程当天唯一的实质额外开销仅为午餐（约₩15,000）。"}, {"label": "明确的\"不购物\"政策", "detail": "运营商明确公布无购物条款——没有人参店、化妆品商城绕道，也没有收取提成的午餐安排。行程中的每一站均为正式景点。东门市场的下车点为行程结束后的自由参观，并非强制停留。"}, {"label": "从海岸出发、以汉拿山收尾的动线", "detail": "上午早早趁旅游大巴涌入前游览西归浦海岸（正房瀑布·外突岩），途经寺院·午餐·茶田，最后在一天结束时沿1100号公路翻越汉拿山返回济州市。逆时针环线，不走回头路。"}, {"label": "迷你巴士模式，而非40人大巴", "detail": "共享迷你巴士模式将团队规模控制在较小水平，让您在外突岩偶来路线与药泉寺寺内都能获得导游的细致关照。不同于大型提成巴士团（30~40人），本模式以12~18人左右运营，在无需支付私人导游费用的前提下，恰到好处地保证了充分关照。"}]}]}, "practicalAccordionItems": [{"id": "inclusions", "title": "费用包含", "preview": "空调迷你巴士、持证英语/中文导游、正房瀑布门票……", "content": ["空调迷你巴士、持证英语/中文翻译导游、正房瀑布门票，含油费/过路费/停车费。", "外突岩·偶来7号路线、药泉寺、雪绿茶、汉拿山御乘生岳均为免费入场。", "不含：午餐（约₩15,000）、饮品、小费。", "当天唯一的实质额外开销仅为午餐——几乎全程免费入场的套餐结构。"]}, {"id": "pickup", "title": "接送地点", "preview": "依次在四个地点接客：济州海洋套房酒店（08:30）→ 济州机场3号门，3楼……", "content": ["依次在四个地点接客：济州海洋套房酒店（08:30）→ 济州机场3号门，3楼国内出发大厅（08:45）→ 济州乐天城市酒店（08:55）→ 济州新罗免税店（09:05）。", "预订时请选择最近的上车点。", "请提前10分钟到达；迟到超过10分钟视为放弃，不予退款。", "出发前一天将通过WhatsApp进行确认。"]}, {"id": "walking", "title": "步行与地形", "preview": "中等难度。", "content": ["中等难度。", "正房瀑布需下行约130级台阶至瀑布底部再返回（岩石地带注意湿滑）。", "外突岩·偶来7号路线大体为平坦的海岸步道，部分为天然石路段。", "药泉寺寺内地势平坦，进入法堂时有部分台阶。", "雪绿茶地势平坦，可通行婴儿车。", "汉拿山御乘生岳为单程1.3公里的木质台阶上坡，往返约60~75分钟。", "步行总距离约4公里。", "请务必穿着舒适的包头鞋；建议穿防滑徒步鞋。"]}, {"id": "cancellation", "title": "取消政策", "preview": "出发前24小时内可免费取消。", "content": ["出发前24小时内可免费取消。", "当天取消及未到场均不予退款。", "如遇大雪或步道·1100号公路封闭，汉拿山御乘生岳可改为汉拿山较低海拔的备选地点（神秘道路或济州国立博物馆）。"]}, {"id": "drop", "title": "下车选项", "preview": "五个下车地点：新罗免税店（≈17:30）、乐天城市酒店（≈17:35）、济州机场……", "content": ["五个下车地点：新罗免税店（≈17:30）、乐天城市酒店（≈17:35）、济州机场（≈17:40）、Ocean Suites（≈17:45）、东门传统市场（≈18:00）。", "东门市场仅为下车点，运营方不会陪同进入市场内部。", "黑猪肉街距东门市场步行约5分钟。"]}, {"id": "children", "title": "儿童及无障碍出行", "preview": "欢迎所有年龄段儿童参加。", "content": ["欢迎所有年龄段儿童参加。", "正房瀑布（台阶）与汉拿山御乘生岳（连续木质台阶）不适合推婴儿车。", "外突岩·偶来路线、药泉寺、雪绿茶大致可通行。", "正房瀑布·御乘生岳因台阶而轮椅通行受限，药泉寺·雪绿茶大致可通行。", "预订时请提前告知行动不便需求。"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "请参阅季节说明"}, "tomorrow": {"temp": "—", "label": "请参阅季节说明"}, "_seasonalSummary": "Jeju has Korea''s mildest climate — coastal areas rarely freeze in winter, and summers are humid but moderated by sea breeze. The Hallasan trailhead is 5–10°C colder than coastal Jeju year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "8–22°C", "notes": "Cherry blossoms in early April. Great season for the Hallasan Eoseungsaengak trail and the Seogwipo coastal walks (Jeongbang Falls, Oedolgae, Olle 7)."}, {"season": "Summer (Jun–Aug)", "range": "22–30°C", "notes": "Humid; afternoon showers common. Jeongbang Falls and the Oedolgae coast stay cooler with the sea breeze."}, {"season": "Autumn (Sep–Nov)", "range": "10–24°C", "notes": "Best season — clear and mild, with the sharpest Oedolgae coast and Hallasan summit views."}, {"season": "Winter (Dec–Feb)", "range": "3–10°C", "notes": "Mild on the coast; Hallasan upper slopes can have snow and the 1100 Road may close."}]}, "seasonalVariations": [{"season": "春季", "description": "西归浦海岸及沿途各处樱花·油菜花盛开，是游览汉拿山御乘生岳的最佳季节。"}, {"season": "夏季", "description": "正房瀑布与外突岩海岸凉爽的海风使其成为热门避暑地。午后多阵雨，请备好雨具。"}, {"season": "秋季", "description": "天气晴朗凉爽，是拍照的最佳季节。外突岩海岸与汉拿山的视野最为清晰。"}, {"season": "冬季", "description": "海岸温和，但汉拿山高地可能降雪。积雪时1100号公路·御乘生岳可能管制。"}], "bookingTrustItems": [{"icon": "check-circle", "title": "持牌本地运营商", "description": "已投保全险，持牌韩国旅游运营商", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600", "body": "持牌本地运营商——以小团形式畅游济州南部西归浦海岸标志性景点的高性价比线路。"}, {"icon": "route", "title": "路线专家", "description": "精心定制的行程，而非千篇一律的环线", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "body": "几乎全程免费入场：外突岩·偶来7号路线（免费）、药泉寺（免费）、雪绿茶（免费）、汉拿山御乘生岳（免费）——仅正房瀑布（₩2,000）计入基础价格。"}, {"icon": "users", "title": "舒适的团队规模", "description": "最适合该路线的团队人数", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600", "body": "以小团迷你巴士出行，让您在外突岩偶来路线、药泉寺寺内及正房瀑布台阶都能从容游览——与大巴团游体验截然不同。"}], "bookingSupportSteps": [{"timing": "立即", "title": "即时确认预订", "detail": "发送含行程摘要的预订确认", "description": "即时确认预订，含济州市酒店接送详情（市区内免费；市区外加收₩70,000）。"}, {"timing": "出发前12小时", "title": "12小时提醒", "detail": "天气更新及路线调整通知", "description": "提前告知正房瀑布·外突岩海岸状况及汉拿山1100号公路路况。"}, {"timing": "前一天晚上", "title": "最终接送信息", "detail": "确切的接送时间及司机联系方式", "description": "前一天晚上确认最终接送时间。"}, {"timing": "游览当天早晨", "title": "当日路线说明", "detail": "根据实时情况进行晨间简报", "description": "早晨天气信息及汉拿山御乘生岳·1100号公路路况通知。"}, {"timing": "游览途中", "title": "各景点小贴士", "detail": "每个地点的实时导览", "description": "导游会讲解正房瀑布\"徐市过此\"地名传说、外突岩的形成与《大长今》拍摄地、东亚最大寺院药泉寺、1979年爱茉莉太平洋创立雪绿茶的背景，以及汉拿山的盾状火山特征。"}, {"timing": "游览结束后", "title": "行程后续支持", "detail": "跟进服务与推荐建议", "description": "下车后将发送行程满意度调查请求。"}], "staticQuestions": [{"id": "q1", "question": "此行程全年均可参加吗？", "answer": "是的。该路线全年每天运营。西归浦海岸的氛围与汉拿山的视野会随季节变化，但全天行程的安排保持不变。冬季积雪时，汉拿山御乘生岳可能改为较低海拔的备选地点。"}, {"id": "q2", "question": "在正房瀑布与汉拿山步行很吃力吗？", "answer": "正房瀑布需下行约130级台阶至瀑布底部再返回，汉拿山御乘生岳为单程1.3公里的木质台阶上坡（往返约60~75分钟）。穿一双包头的舒适运动鞋即可，无需专业登山装备。本路线不包含汉拿山顶峰（白鹿潭）攀登。"}, {"id": "q3", "question": "此行程包含哪些景点？", "answer": "游览正房瀑布（亚洲唯一直落入海的瀑布）、外突岩与偶来7号路线海岸漫步、东亚最大寺院药泉寺、雪绿茶博物馆，以及汉拿山御乘生岳步道。这是一条从西归浦海岸出发、以汉拿山收尾的济州南部招牌线路。"}, {"id": "q4", "question": "包含门票吗？", "answer": "是的。正房瀑布门票（成人₩2,000）计入基础价格。外突岩·偶来7号路线、药泉寺、雪绿茶、汉拿山御乘生岳均为免费入场。当天唯一的实质额外开销仅为午餐（约₩15,000）。"}, {"id": "q5", "question": "包含午餐吗？", "answer": "不含——午餐费用自理（约15,000韩元）。导游将推荐当地餐厅，如您在预订时提前告知，可协助安排素食、纯素、清真或过敏饮食需求。"}, {"id": "q6", "question": "机场接机时可以携带行李吗？", "answer": "可以。请提前告知运营商行李数量。迷你巴士设有专用行李空间，乘坐早班机抵达的游客也可携带行李直接加入行程。"}, {"id": "first-time", "question": "这条线路适合初次游览济州南部的游客吗？", "answer": "非常适合——一天之内即可均衡地游览该地区最具特色的景点：西归浦海岸、寺院、茶田，直至汉拿山。"}, {"id": "walking", "question": "步行困难吗？", "answer": "这是充实的一天，包含正房瀑布的台阶和汉拿山御乘生岳的上坡，但外突岩偶来路线与药泉寺·雪绿茶相对平坦。"}, {"id": "family", "question": "这条线路适合家庭参加吗？", "answer": "适合有能够承受全天活动孩子的家庭。海岸漫步与寺院·茶田，孩子们也能轻松愉快地游览。"}, {"id": "seniors", "question": "老年人可以舒适地参加吗？", "answer": "推荐给习惯正房瀑布台阶与御乘生岳上坡的活跃老年人。外突岩·药泉寺·雪绿茶则相对轻松。"}, {"id": "children", "question": "建议的最低年龄是多少？", "answer": "最适合10岁及以上的儿童——能够适应全天行程节奏且符合上述步行要求的孩子。"}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "请选择日期和人数，查看实时空位并完成预订。", "price": {"amountLabel": "", "originalPriceUsd": null, "salePriceUsd": null, "discountPercent": null, "currency": "USD", "per": "person"}}, "pickup_dropoff": {"departure": [{"order": 1, "time": "08:30", "name": "济州海洋套房酒店", "type": "hotel", "note": "在酒店大堂集合——导游手持 AtoCKorea 指示牌。", "lat": 33.51823, "lng": 126.52317}, {"order": 2, "time": "08:45", "name": "济州国际机场（3楼，3号登机口）", "type": "airport", "note": "3楼出发大厅，请按指示牌前往3号登机口。", "lat": 33.50708, "lng": 126.49343}, {"order": 3, "time": "08:55", "name": "济州乐天城市酒店", "type": "hotel", "note": "在主大堂等候——导游将点名确认。", "lat": 33.4906, "lng": 126.48643}, {"order": 4, "time": "09:05", "name": "新罗免税店（济州店）", "type": "shopping", "note": "在新罗免税店济州分店正门外集合。", "lat": 33.48631, "lng": 126.48739}], "return": [{"order": 1, "name": "济州海洋套房酒店", "type": "hotel", "lat": 33.51823, "lng": 126.52317}, {"order": 2, "name": "济州国际机场（3楼，3号登机口）", "type": "airport", "lat": 33.50708, "lng": 126.49343}, {"order": 3, "name": "济州乐天城市酒店", "type": "hotel", "lat": 33.4906, "lng": 126.48643}, {"order": 4, "name": "新罗免税店（济州店）", "type": "shopping", "lat": 33.48631, "lng": 126.48739}, {"order": 5, "name": "东门传统市场", "type": "market", "lat": 33.51204, "lng": 126.52828}], "notes": ["返回时间通常在17:30至18:00左右。"]}, "matching_profile": {"profile_version": 7, "is_active": true, "product_id": "jeju-southern-top-unesco-spots-tour", "product_type": "small_group", "route_type": "fixed_route", "destination_region": "jeju", "region_type": "jeju_south", "vehicle_type": "minicoach", "duration_hours": 9, "region_tags": ["jeju_south", "jeju_seogwipo"], "theme_tags": ["coastal_scenery", "waterfall", "temple_culture", "tea_culture", "hallasan_unesco"], "poi_tags": ["jeongbang_falls", "yakcheonsa_temple", "osulloc_tea_museum", "hallasan_eoseungsaengak"], "pace_level": 0.6, "walking_level": 0.6, "scenic_level": 0.9, "photo_level": 0.95, "culture_level": 0.7, "relax_level": 0.65, "first_time_fit": 0.9, "family_fit": 0.65, "senior_fit": 0.6, "couple_fit": 1, "solo_traveler_fit": 0.9, "active_traveler_fit": 0.8, "adult_family_fit": 0.8, "family_with_teens_fit": 1, "young_kids_fit": 0.6, "senior_active_fit": 0.6, "senior_general_fit": 0.45, "mobility_friendly_fit": 0.55, "stroller_fit": 0.5, "one_day_fit": 1, "same_day_flight_fit": 0.7, "rain_fit": 0.4, "value_for_money_fit": 0.95, "iconic_landmark_fit": 0.85, "cafe_fit": 0.4, "food_fit": 0.6, "nature_fit": 1, "beach_fit": 0.2, "nightlife_fit": 0.2, "shopping_fit": 0.2, "no_shopping_fit": 1, "local_culture_fit": 0.75, "storytelling_fit": 1, "unesco_fit": 0.7, "intangible_heritage_fit":