  '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "jeju-southern-top-unesco-spots-tour", "locale": "zh-TW", "product_id": "jeju-southern-top-unesco-spots-tour", "seo": {"pageTitle": "濟州南部西歸浦招牌一日遊 | AtoC Korea", "metaDescription": "9小時濟州南部小團一日遊：正房瀑布（亞洲唯一直落入海的瀑布）、外突岩＆偶來7號路線、藥泉寺、雪綠茶博物館（Osulloc）、漢拏山御乘生岳。", "primaryKeywords": ["濟州南部一日遊", "正房瀑布之旅", "外突岩偶來7號路線", "藥泉寺之旅", "雪綠茶博物館之旅", "漢拏山御乘生岳"], "ogImage": "https://www.atockorea.com/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "title": "濟州南部西歸浦招牌一日遊・幾乎全程免費入場 | AtoC", "description": "濟州南部西歸浦小團一日遊：正房瀑布 → 外突岩＆偶來7號路線 → 藥泉寺 → 午餐 → 雪綠茶博物館（Osulloc）→ 漢拏山御乘生岳。幾乎全程免費入場，小團出發。"}, "catalog_card": {"thumbnail": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "title": "濟州南部西歸浦招牌一日遊", "priceLabel": "", "shortCardDescription": "小團一日遊，深度遊覽濟州南部西歸浦的經典景點——亞洲唯一直落入海的正房瀑布、外突岩奇岩與偶來7號路線海岸漫步、東亞最大寺院藥泉寺、雪綠茶博物館（Osulloc），以及漢拏山御乘生岳步道。濟州市全區及機場設有四個接送地點，持證英語・中文導遊全程陪同，除正房瀑布外幾乎全程免費入場，絕無購物壓力。", "tags": ["小團出發", "濟州", "濟州南部", "西歸浦", "超值之選", "無購物行程"], "rating": 0, "reviewCount": 0, "slug": "jeju-southern-top-unesco-spots-tour", "subtitle": "濟州南部西歸浦海岸路線——正房瀑布、外突岩偶來步道、藥泉寺、漢拏山。", "region": "濟州南部", "duration": "9小時", "stopsCount": 8, "badges": ["小團出發", "濟州", "濟州南部", "西歸浦", "價格實惠", "無購物"], "heroImage": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp"}, "headlineLine1": "濟州南部西歸浦招牌", "headlineLine2": "一日遊", "price": {"amountLabel": "", "originalPriceUsd": null, "salePriceUsd": null, "discountPercent": null, "currency": "USD", "per": "person"}, "hero": {"imageUrl": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "imagePosition": "center 45%", "tagline": "一天遊覽濟州南部西歸浦海岸的經典景點——正房瀑布、外突岩偶來步道、藥泉寺、Osulloc、漢拏山。幾乎全程免費入場。", "pills": ["小型團體", "濟州"], "meta": {"duration": "約9小時（08:30首次接送，約18:00送回）", "region": "濟州南部", "stops": "8個景點", "rating": 0, "ratingStars": 5}}, "subnavItems": [{"id": "overview", "label": "概覽"}, {"id": "itinerary", "label": "行程規劃"}, {"id": "details", "label": "詳細資訊"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "評論"}], "glanceItems": [{"icon": "camera", "label": "拍照適合度", "value": "高", "level": 5}, {"icon": "mountain", "label": "景色", "value": "高", "level": 5}, {"icon": "footprints", "label": "步行難度", "value": "中等", "level": 3}, {"icon": "cloud-rain", "label": "雨天適合度", "value": "有限", "level": 2}, {"icon": "users", "label": "家庭適合度", "value": "中等", "level": 3}, {"icon": "gauge", "label": "行程節奏", "value": "均衡", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 1", "caption": "正房瀑布 — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "藥泉寺", "alt": "藥泉寺 — gallery image 2", "caption": "藥泉寺 — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪綠茶博物館 + 綠茶田", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 3", "caption": "雪綠茶博物館 + 綠茶田 — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "漢拏山御乘生岳步道", "alt": "漢拏山御乘生岳步道 — gallery image 4", "caption": "漢拏山御乘生岳步道 — photo 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 5", "caption": "正房瀑布 — photo 5"}, {"id": 6, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 6", "caption": "正房瀑布 — photo 6"}, {"id": 7, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪綠茶博物館 + 綠茶田", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 7", "caption": "雪綠茶博物館 + 綠茶田 — photo 7"}, {"id": 8, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪綠茶博物館 + 綠茶田", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 8", "caption": "雪綠茶博物館 + 綠茶田 — photo 8"}, {"id": 9, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪綠茶博物館 + 綠茶田", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 9", "caption": "雪綠茶博物館 + 綠茶田 — photo 9"}, {"id": 10, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "漢拏山御乘生岳步道", "alt": "漢拏山御乘生岳步道 — gallery image 10", "caption": "漢拏山御乘生岳步道 — photo 10"}, {"id": 11, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "漢拏山御乘生岳步道", "alt": "漢拏山御乘生岳步道 — gallery image 11", "caption": "漢拏山御乘生岳步道 — photo 11"}, {"id": 12, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "漢拏山1100高地", "alt": "漢拏山1100高地 — gallery image 12", "caption": "漢拏山1100高地 — photo 12"}, {"id": 13, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "漢拏山1100高地", "alt": "漢拏山1100高地 — gallery image 13", "caption": "漢拏山1100高地 — photo 13"}, {"id": 14, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "漢拏山1100高地", "alt": "漢拏山1100高地 — gallery image 14", "caption": "漢拏山1100高地 — photo 14"}], "itineraryStops": [{"number": 1, "time": "09:00", "duration": "30分鐘", "name": "接送（濟州市4個集合點）", "category": "接送 — 濟州市飯店／集散點順序", "description": "**接送集中於濟州市四個核心集合點**，以減少早晨來回奔波：供當日抵達旅客使用的**濟州國際機場（제주공항）**；服務蓮洞／老衡／舊市區飯店群的**濟州市政廳（제주시청）**；最西端的上車點**河貴洞（하귀동）**；以及靠近塔洞海濱、位於濟州市東側的可選上車點**東門傳統市場（동문시장）**。\n\n路線順序為河貴 → 機場 → 市政廳 → 東門，接著**沿5.16號公路（1131號國道）越過漢拏山東側，南下前往西歸浦南部海岸**。此行程採用配有英語導遊的**小型包廂巴士（最多約14人）**運營。\n\n**雙語印刷行程卡**於上車時發放，並於第一站進行天氣簡報。今日路線自西歸浦海岸出發，**於一天結束時沿1100號公路越過漢拏山返回濟州市**，因此出發前將進行**1100號公路封閉確認** — 若因積雪或結冰而封閉，最後的漢拏山御乘生岳停靠站將改至較低海拔的替代景點（通常為神秘道路或濟州國立博物館）。", "image": null, "highlights": ["**4個接送點** — 機場、市政廳、河貴、東門", "由西向東的順序可減少早晨的巴士行車距離", "配有英語導遊的**小型包廂巴士（最多14人）**", "雙語行程卡 + 第一站天氣簡報", "**確認1100號公路封閉狀況** — 出發前（為返程漢拏山路段做準備）", "濟州市 → 西歸浦正房瀑布上午車程：約60分鐘（經5.16號公路）"], "timeUsed": ["河貴接送 約09:00 — 5分鐘", "機場接送 約09:10 — 5分鐘", "市政廳接送 約09:20 — 5分鐘", "東門接送 約09:30 — 5分鐘", "沿5.16號公路南下前往西歸浦海岸 — 約60分鐘"], "whyOnRoute": "四個接送點涵蓋濟州市主要的飯店及交通樞紐（機場、市中心、舊城區、市場區），讓旅客無需橫越市區奔波。路線於早晨先南下至西歸浦海岸，趁正午人潮湧現前遊覽正房瀑布・外突岩，再於一天結束時沿1100號公路越過漢拏山返回濟州市，形成高效的逆時針環線。**1100號公路封閉應變流程**確保旅客在出發前獲知冬季返程狀況。", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "pickup"}, {"number": 2, "time": "≈ 10:10", "duration": "50分鐘", "name": "正房瀑布（亞洲唯一直落入海的瀑布）", "category": "海岸瀑布 — 瀛洲十景・西歸浦地名由來", "description": "**正房瀑布（정방，正房）以從懸崖直落入海、為亞洲唯一直落入海的瀑布**而聞名，是西歸浦的代表性景點。高**23公尺、寬約8公尺**的水流沿玄武岩海壁傾瀉入深藍大海，晴天時背景還可一併納入**森島（섶섬）與蚊島（문섬）**。\n\n正房瀑布與漢拏山、天帝淵並列為朝鮮時代文人選定的**瀛洲十景（영주십경，濟州十大絕景）**之一，懸崖上刻有**「徐市過此（서불과차）」傳說** — 相傳奉秦始皇之命尋找長生不老草的徐市曾路過此地後向西返回，這也是「西歸浦（西歸浦）」地名的由來。\n\n從售票處到瀑布下方須走**約130級階梯**，地面由圓潤的卵石與岩石構成，因此務必穿著防滑鞋。瀑布下方以水霧與大海為背景的留影十分熱門，懸崖上的觀景台則可一覽森島・蚊島。", "image": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "highlights": ["**亞洲唯一直落入海的瀑布** — 高23公尺／寬約8公尺", "**瀛洲十景（濟州十大絕景）**之一 — 與漢拏山・天帝淵一同入選", "**「徐市過此」傳說** — 成為「西歸浦」地名由來的秦始皇・長生不老草傳說", "晴天時以**森島・蚊島**為背景的海岸絕景", "通往瀑布下方須走**約130級階梯** — 務必穿著防滑鞋", "門票 **成人 ₩2,000／青少年 ₩1,000／7歲以下・65歲以上免費**", "開放時間 **09:00–17:40**（閉園前30分鐘停止入場），全年開放", "於岩石地帶拍照時請注意海浪・濕滑 — 安全優先"], "timeUsed": ["購票 + 入口說明 — 約5分鐘", "下行約130級階梯 — 約10分鐘", "瀑布 + 海岸岩石拍照 — 約20分鐘", "登階返回 + 懸崖觀景台 — 約15分鐘"], "whyOnRoute": "**西歸浦海岸的開場亮點。** 正房瀑布若於上午早早造訪，便能趕在團體觀光巴士湧入前，悠閒享受瀑布下方的清幽。它距外突岩・偶來7號路線僅15分鐘車程，沿西歸浦海岸高效串聯，是以壯麗海景揭開一天序幕的絕佳景點。", "_poi_meta": {"poi_key": "jeongbang_falls", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["VisitJeju — Jeongbang Falls official listing", "Seogwipo-si cultural tourism office — Jeongbang Falls", "Jeju Special Self-Governing Province — Yeongjusipgyeong registry", "Cultural Heritage Administration — Seobulgwacha inscription records"]}, "smartNotes": {"photo": "於瀑布下方岩石地帶將水流 + 大海納入同一畫面；於懸崖觀景台遠眺森島・蚊島", "facilities": "廁所・售票處位於入口（下階梯前）；瀑布下方無便利設施", "tip": "階梯與岩石濕滑時非常容易滑倒 — 建議穿著防滑鞋；請勿與西歸浦的天地淵瀑布混淆"}, "convenience": {"restroom": "入口／售票區域可使用", "parking": "入口停車場可使用"}, "visitBasics": {"hours": "每日 09:00–17:40（閉園前30分鐘停止入場，依季節略有變動）", "closed": "全年開放（滿潮・颱風時可能臨時封閉）", "admission": "成人 2,000韓元 / 青少年 1,000韓元（7歲以下・65歲以上免費）", "walking": "中等 — 通往瀑布下方須走約130級階梯，地面為崎嶇岩石；請注意濕滑"}, "images": ["/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp"], "imageCredits": [{"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布（亞洲唯一直落入海的瀑布）", "caption": "正房瀑布（亞洲唯一直落入海的瀑布） — photo 1", "alt": "正房瀑布（亞洲唯一直落入海的瀑布） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布（亞洲唯一直落入海的瀑布）", "caption": "正房瀑布（亞洲唯一直落入海的瀑布） — photo 2", "alt": "正房瀑布（亞洲唯一直落入海的瀑布） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布（亞洲唯一直落入海的瀑布）", "caption": "正房瀑布（亞洲唯一直落入海的瀑布） — photo 3", "alt": "正房瀑布（亞洲唯一直落入海的瀑布） — gallery image 3"}]}, {"number": 3, "time": "≈ 11:10", "duration": "50分鐘", "name": "外突岩＆偶來7號路線海岸漫步", "category": "海岸奇岩 + 偶來步道 — 濟州世界地質公園地質名勝", "description": "**外突岩（외돌개）是約150萬年前火山噴發形成、高約20公尺的海岸石柱**，獨自聳立於茫茫大海之中，因而得名「外（獨）突（岩）」。它又被稱為「將軍岩」或「老婆婆岩」，並因作為**《大長今》拍攝地**而廣為人知。外突岩與西歸浦的層理海岸懸崖是**濟州世界地質公園（UNESCO世界地質公園）的官方地質名勝**之一。\n\n外突岩座落於**濟州偶來7號路線**之上 — 7號路線自濟州偶來旅客中心出發，途經法還浦口直至月坪，是全長約17.6公里的代表性海岸偶來步道，偶來健行者最喜愛的「秀峰路」路段就行經外突岩附近。\n\n此站除了外突岩觀景點外，還會**短暫漫步偶來7號路線的部分海岸步道。** 在松林間的小徑上，可眺望外突岩與森島・蚊島，以及無垠延展的南方大海，帶來與正房瀑布瀑布風光截然不同的開闊海岸景致。**免費開放**，步道大致平坦，但部分為天然石路段。", "image": null, "highlights": ["**外突岩** — 約150萬年前形成、高約20公尺的海岸石柱（「將軍岩」）", "因作為**《大長今》拍攝地**而聞名的西歸浦海岸絕景", "**濟州世界地質公園（UNESCO世界地質公園）地質名勝**", "座落於**偶來7號路線**之上 — 偶來健行者最喜愛的「秀峰路」海岸路段", "於松林小徑眺望**外突岩 + 森島・蚊島 + 南方大海**", "**免費開放**，全年常態 — 距正房瀑布約15分鐘車程", "步道大致平坦，部分為天然石路段 — 建議穿著舒適鞋履"], "timeUsed": ["停車 + 進入偶來步道 — 約5分鐘", "偶來7號路線海岸步道 — 約25分鐘", "外突岩觀景點 + 拍照 — 約15分鐘", "返回巴士 — 約5分鐘"], "whyOnRoute": "**西歸浦海岸的第二處名勝兼偶來步道體驗。** 距正房瀑布僅15分鐘車程，動線自然銜接，景致也由瀑布（垂直風光）轉為外突岩（開闊海岸全景）。短程的偶來7號路線漫步，讓人得以輕鬆品味「以雙腳遇見濟州」的精髓。", "_poi_meta": {"poi_key": "oedolgae_olle7", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Jeju Olle Foundation — Olle Route 7 official (jejuolle.org)", "VisitJeju — Oedolgae Rock official listing", "Jeju Global Geopark — Oedolgae & Seogwipo layered cliff geosite", "KTO — Dae Jang Geum filming location records"]}, "smartNotes": {"photo": "於松林間構圖外突岩 + 大海；於觀景台遠眺森島・蚊島", "facilities": "入口停車場設有廁所；海岸步道路段便利設施較少", "tip": "強風天較多，請準備外套；天然石路段請注意濕滑"}, "convenience": {"restroom": "外突岩停車場區域可使用", "parking": "外突岩公營停車場可使用"}, "visitBasics": {"hours": "常態開放（海岸步道）", "closed": "全年開放（強風・大浪時部分路段可能封閉）", "admission": "免費", "walking": "輕鬆～中等 — 海岸步道大致平坦，部分為天然石・階梯路段"}, "images": [], "imageCredits": [], "galleryItems": []}, {"number": 4, "time": "≈ 12:10", "duration": "40分鐘", "name": "藥泉寺（東亞最大寺院）", "category": "寺院 — 東亞最大規模大寂光殿", "description": "**藥泉寺（약천사，藥泉寺）佔地122,100㎡，是東亞最大寺院之一**，為位於西歸浦大浦洞的大型寺院。其名意為「流淌著藥用泉水之寺」，建於四季不竭的藥水湧出的舊「藥水庵」遺址之上 — **由慧印法師於1981年動工，1996年竣工**。\n\n中心法堂**大寂光殿（大寂光殿）高約30公尺、總樓地板面積約3,305㎡**，是東洋最大級的單一法堂，沿襲朝鮮初期的寺院建築樣式。內部供奉**高5公尺的毗盧遮那佛（韓國最大木造坐佛）**於4公尺佛座之上，覆滿多層牆面的數萬尊小型金佛像構成壓倒性的壯觀景象。法堂前則設有**18噸規模的梵鐘**。\n\n藥泉寺位於**濟州偶來7號路線（終點）與8號路線（起點）的交會處**，偶來健行者與觀光客皆會造訪，並**自2006年起運營寺院寄宿（Templestay）**。**免費入場**，平坦的寺院境內相對便於遊覽。", "image": "/images/tours/yakcheonsa/photo-001.webp", "highlights": ["**東亞最大級寺院** — 佔地約122,100㎡", "**大寂光殿**高約30公尺／總樓地板面積約3,305㎡ — 東洋最大級的單一法堂", "**高5公尺毗盧遮那佛** — 韓國最大木造坐佛（於4公尺佛座上）", "覆滿多層牆面的**數萬尊金佛像** + 法堂前的**18噸梵鐘**", "**慧印法師1981年動工 → 1996年竣工**；建於「藥水庵」遺址（藥水湧出之泉）", "**偶來7號路線終點 + 8號路線起點**的交會處", "**自2006年起**運營寺院寄宿（Templestay）", "**免費入場**，平坦的寺院境內 — 距正房瀑布一帶約15分鐘車程"], "timeUsed": ["停車 + 進入一柱門 — 約5分鐘", "大寂光殿 + 毗盧遮那佛 + 金佛像參觀 — 約20分鐘", "梵鐘 + 境內漫步 + 藥水 — 約12分鐘", "返回巴士 — 約3分鐘"], "whyOnRoute": "**午餐前的文化亮點。** 在正房瀑布・外突岩的海岸風光之後，藥泉寺壓倒性的大寂光殿內部為行程增添另一種層次的看點。它距外突岩很近，又鄰近午餐餐廳，動線高效，加上免費入場，毫無負擔。導遊將為您講解寺院禮儀（肅靜・服裝）。", "_poi_meta": {"poi_key": "yakcheonsa_temple", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Yakcheonsa Temple official records", "VisitJeju — Yakcheonsa Temple official listing", "Jeju Olle Foundation — Route 7/8 junction at Yakcheonsa", "Korean Buddhism Templestay — Yakcheonsa program (since 2006)"]}, "smartNotes": {"photo": "大寂光殿外觀的宏偉規模感；內部毗盧遮那佛與金佛像牆面（可否拍攝請現場確認指示）", "facilities": "境內廁所・停車場齊備；藥水可飲用", "tip": "法堂內部請保持肅靜・脫帽等遵守禮儀；請避免穿著過於暴露的服裝"}, "convenience": {"restroom": "境內可使用", "parking": "寺院免費停車場可使用"}, "visitBasics": {"hours": "日出～日落（法堂常態開放）", "closed": "全年開放", "admission": "免費", "walking": "輕鬆 — 平坦的寺院境內；進入法堂時有部分階梯"}, "images": ["/images/tours/yakcheonsa/photo-001.webp"], "imageCredits": [{"url": "/images/tours/yakcheonsa/photo-001.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "藥泉寺（東亞最大寺院）", "caption": "藥泉寺（東亞最大寺院） — photo 1", "alt": "藥泉寺（東亞最大寺院） — gallery image 1"}]}, {"number": 5, "time": "≈ 13:00", "duration": "60分鐘", "name": "午餐 — 濟州南部在地料理", "category": "午間休憩 — 西歸浦／大浦在地料理", "description": "**藥泉寺與Osulloc之間的60分鐘休息** — 西歸浦南部海岸是韓國頂級的海鮮集散地之一，大浦－安德走廊距下一站很近。基本餐食組合：**白帶魚燉煮（갈치조림）** — 濟州是韓國代表性的白帶魚產地，南部海岸可品嚐最新鮮的白帶魚；夏季（6～9月）供應**冷生魚湯（물회）**；或全年皆可享用的**黑豬燒烤（흑돼지구이）**（於2015年指定為**鄉土文化遺產第5號**的濟州本土黑豬）。\n\n**素食替代選項**：當季濟州蔬菜拌麵。輪替餐廳中的一家提供**清真友善選項** — 請於上車時提前告知。從午餐餐廳到**Osulloc乘車約25分鐘**。", "image": null, "highlights": ["**濟州南部海鮮走廊** — 西歸浦・大浦海岸餐廳", "**白帶魚燉煮** — 濟州是韓國最大的白帶魚產地", "夏季供應**冷生魚湯**；全年皆可選擇**黑豬**", "黑豬為**鄉土文化遺產第5號（2015年）**指定品種", "可應需求提供**素食 + 清真友善**選項（請於上車時提前告知）", "**乘車約25分鐘至Osulloc** — 午餐後前往內陸茶園"], "timeUsed": ["乘車至午餐餐廳約10分鐘", "點餐 + 用餐 — 約45分鐘", "乘車至Osulloc約25分鐘"], "whyOnRoute": "遊覽西歸浦海岸名勝後的自然用餐時機。午餐在上午的海岸漫步・寺院參觀與下午的茶園・漢拏山行程之間，提供實質的休息時間，餐後即前往內陸的西廣茶園。", "smartNotes": {}, "convenience": {}, "visitBasics": {}}, {"number": 6, "time": "≈ 14:25", "duration": "60分鐘", "name": "雪綠茶博物館 + 綠茶田", "category": "茶文化博物館 — 韓國最大綠茶田（西廣茶園）", "description": "**雪綠茶博物館（O''Sulloc，意為「邂逅白雪與翠綠」）**是韓國最大美妝企業**愛茉莉太平洋**的茶文化旗艦空間。創辦人**徐成煥會長於1979年**親自開創這項計畫，將濟州西廣高原的火山灰農地重新開墾為茶園。時至今日，**西廣茶園**已成為橫跨愛茉莉太平洋在濟州三處莊園、**年產量約700噸**的**韓國最大綠茶田**。\n\n博物館建築坐落於茶園中心，**於2001年開幕**，以極簡設計入選**designboom全球十大藝術博物館**。**免費入場**，每日開放，年訪客量約**200萬人次**。參觀分為三個部分：**(1) 館內展覽** — 茶葉製程・古代茶器收藏・屋頂觀景台；**(2) 茶房咖啡廳** — 招牌**綠茶瑞士捲**與**綠茶冰淇淋**；**(3) 茶園步道** — 茶叢間的碎石小徑（夕陽攝影名勝）。\n\n**悅詩風吟濟州之家（Innisfree Jeju House）**（愛茉莉太平洋的自然主義品牌）步行5分鐘即達，免費入場，並可選擇參加柑橘皂DIY工作坊（₩15,000）。", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**愛茉莉太平洋**旗艦品牌 — 創辦人徐成煥於**1979年**開創濟州茶葉栽培", "**西廣茶園 = 韓國最大綠茶田**；年產量約700噸", "博物館**2001年開幕** — designboom入選全球十大藝術博物館（建築類）", "**免費入場**，年訪客量約200萬人次", "**綠茶瑞士捲** + **綠茶冰淇淋** = 咖啡廳招牌品項", "**悅詩風吟濟州之家**步行5分鐘 — 免費入場，柑橘皂DIY選配₩15,000", "茶園步道於**黃金時段（16:00–17:00）**最適合拍照", "屋頂觀景台 + 地面茶田 — 從兩種高度構圖綠茶田"], "timeUsed": ["停車 + 入場 — 約5分鐘", "館內 + 茶器收藏 — 約20分鐘", "茶房咖啡廳（瑞士捲 + 冰淇淋）— 約20分鐘", "綠茶田步道 — 約15分鐘"], "whyOnRoute": "**午後的茶文化亮點。** 遊覽海岸名勝與寺院後，Osulloc的茶園與咖啡廳為行程增添柔和的休憩。它距午餐餐廳往內陸25分鐘車程，接著恰好可沿1100號公路前往漢拏山 — 是漫步綠茶田間、品嚐茶點甜品的合適午後時段。", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Osulloc Tea Museum official site (osulloc.com)", "Amorepacific Corporation — Suh Sung-whan tea reclamation history (1979)", "designboom — Top 10 art museums feature", "VisitJeju — Osulloc Tea Museum official listing"]}, "smartNotes": {"photo": "茶杯造型的博物館建築 + 綠茶田全景；屋頂觀景台；茶園碎石小徑夕陽", "facilities": "咖啡廳（必試綠茶冰淇淋）、禮品店、隔鄰的悅詩風吟濟州之家、觀景平台", "tip": "團體巴士湧入前的午後較早時段較清幽；含咖啡廳・散步預留1～1.5小時"}, "convenience": {"restroom": "博物館全區設施完善", "parking": "提供免費停車"}, "visitBasics": {"hours": "夏季（4～10月）09:00–19:00 / 冬季（11～3月）09:00–18:00", "closed": "全年無休（惡劣天氣時可能臨時變動）", "admission": "博物館・茶園免費；咖啡廳飲品・甜點・課程另行收費", "walking": "輕鬆 — 平坦的鋪面道路，可推嬰兒車・輪椅通行"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪綠茶博物館 + 綠茶田", "caption": "雪綠茶博物館 + 綠茶田 — photo 1", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪綠茶博物館 + 綠茶田", "caption": "雪綠茶博物館 + 綠茶田 — photo 2", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪綠茶博物館 + 綠茶田", "caption": "雪綠茶博物館 + 綠茶田 — photo 3", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪綠茶博物館 + 綠茶田", "caption": "雪綠茶博物館 + 綠茶田 — photo 4", "alt": "雪綠茶博物館 + 綠茶田 — gallery image 4"}]}, {"number": 7, "time": "≈ 15:55", "duration": "75分鐘", "name": "漢拏山御乘生岳（UNESCO世界自然遺產）", "category": "UNESCO火山地質 — 漢拏山御乘生岳步道（三重自然認定）", "description": "**御乘生岳（1,169公尺）**是一條起點鄰近於御里牧遊客中心、位於漢拏山側面的短程火山錐（岳）步道。漢拏山是大韓民國最高峰，亦是**UNESCO世界自然遺產（2007年）・生物圈保護區（2002年）**，此路線讓旅客得以在無需登頂的情況下體驗漢拏山。\n\n今日路線將御乘生岳安排在從Osulloc**沿1100號公路（濟州最高海拔國道）越過漢拏山返回濟州市**的路途上。此步道比城板岳・觀音寺登頂路線短得多，**不適用登頂預約制**，由寬闊階梯與木棧道構成，穿運動鞋即可（單程1.3公里／海拔落差約200公尺）。\n\n晴天時，於上方棧道觀景台可眺望**漢拏山高地山坡、濟州的岳群與北部海域**，山頂部保存有**1945年日本帝國軍碉堡（陣地）**。山上天氣變化迅速，建議準備外套。**免費入場**，為一天劃下清涼山間空氣的深刻句點。", "image": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "highlights": ["**漢拏山 = 三重自然認定**：UNESCO世界自然遺產2007 + 生物圈保護區2002 + 國立公園1970", "**御乘生岳1,169公尺** — 漢拏山側面的岳（寄生火山）", "**單程1.3公里／海拔落差約200公尺** — 寬闊階梯 + 木棧道，穿運動鞋即可", "於棧道觀景台眺望**漢拏山山坡・岳群・北部海域**", "山頂部保存**1945年日本帝國軍碉堡（陣地）** — 罕見的高海拔遺跡", "**免費入場** + 免費停車；無需登頂預約（白鹿潭路線每日限額1,000人）", "來回約**60–75分鐘** — 沿1100號公路越過漢拏山返回濟州市的動線", "高地天氣變化迅速 — 建議準備外套"], "timeUsed": ["御里牧停車場 + 廁所 + 步道說明 — 約10分鐘", "單程1.3公里棧道路段登行 — 約25分鐘", "山頂棧道 + 拍照 + 碉堡參觀 — 約15分鐘", "下山 — 約20分鐘", "緩衝時間／集合 — 約5分鐘"], "whyOnRoute": "**濟州南部路線的漢拏山壓軸。** 御乘生岳為旅客提供規模適合一日遊的真實登山體驗，並自然地座落於從Osulloc沿1100號公路越過漢拏山返回濟州市的路途上。它以UNESCO火山景觀為自海岸展開的一天劃下句點。若因冬季積雪封閉1100號公路，可能改至低海拔替代地點。", "_poi_meta": {"poi_key": "hallasan_eoseungsaengak", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)", "UNESCO Biosphere Reserve — Jeju Island (2002 designation)", "Hallasan National Park Administration — Eoseungsaengak trail official", "Korea National Park Service — Hallasan visitor management records"]}, "smartNotes": {"photo": "上方觀景台廣角拍攝效果佳；晴天可遠眺至濟州市；碉堡遺跡記錄照", "facilities": "便利設施集中於御里牧入口；路線中途則無", "tip": "為專注享受風景的探訪路線，而非悠閒漫步；高地天氣變化迅速 — 出發前請確認1100號公路・天氣"}, "convenience": {"restroom": "御里牧入口區域可使用", "parking": "御里牧停車場可使用（免費）"}, "visitBasics": {"hours": "步道05:00起開放入場（依季節變動，夏季延長）", "closed": "視天氣而變動（11～3月常因降雪・濃霧・強風封閉）", "admission": "免費", "walking": "中等 — 路程雖短但有階梯・上坡路段"}, "images": ["/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "/images/tours/hallasan-eoseungsaengak/photo-003.webp"], "imageCredits": [{"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "漢拏山御乘生岳（UNESCO世界自然遺產）", "caption": "漢拏山御乘生岳（UNESCO世界自然遺產） — photo 1", "alt": "漢拏山御乘生岳（UNESCO世界自然遺產） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "漢拏山御乘生岳（UNESCO世界自然遺產）", "caption": "漢拏山御乘生岳（UNESCO世界自然遺產） — photo 2", "alt": "漢拏山御乘生岳（UNESCO世界自然遺產） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "漢拏山御乘生岳（UNESCO世界自然遺產）", "caption": "漢拏山御乘生岳（UNESCO世界自然遺產） — photo 3", "alt": "漢拏山御乘生岳（UNESCO世界自然遺產） — gallery image 3"}]}, {"number": 8, "time": "≈ 17:40", "duration": "40分鐘", "name": "送客下車（濟州市區5個站點）", "category": "送客下車 — 濟州市區樞紐順序", "description": "**送客下車路線與早晨接送順序相同，並新增一個選項**：東門傳統市場 → 濟州市政廳 → 河貴洞 → 濟州國際機場，並在市政廳前新增可選停靠點，供住宿於蓮洞／老衡飯店區的旅客使用（第5個下車站點）。從御乘生岳**沿1100號公路下行漢拏山返回濟州市**。預計抵達：東門約18:30、市政廳約18:40、蓮洞約18:45、河貴約18:55、機場約19:05。\n\n**當天於濟州國際機場搭乘晚班航班**通常可行（末班航班約21:30）。全程提供巴士Wi-Fi，司機將協調旅客指定的購物／飯店調整需求。", "image": null, "highlights": ["**5個下車站點** — 東門、市政廳、蓮洞／老衡、河貴、機場", "**東門傳統市場** — 可選晚餐 + 柑橘產品購物", "預計抵達：東門約18:30 → 機場約19:05", "**當天濟州國際機場晚班航班**通常可行（末班航班約21:30）", "巴士Wi-Fi + 司機彈性協調飯店／購物需求"], "timeUsed": ["御乘生岳 → 1100號公路 → 東門 — 約40分鐘", "東門下車 — 5分鐘", "→ 市政廳 — 10分鐘，下車 — 5分鐘", "→ 蓮洞 → 河貴 → 機場 — 依序進行"], "whyOnRoute": "送客下車沿1100號公路下行漢拏山、返回濟州市區的返程路線進行。有晚班機的旅客請提前告知導遊，以便妥善協調最後一個停靠站的時間。", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "dropoff"}], "routeFlowStops": [{"name": "濟州市區 + 機場接送", "type": "origin", "theme": "出發"}, {"name": "正房瀑布", "type": "primary", "theme": "瀑布"}, {"name": "外突岩＆偶來7號路線", "type": "primary", "theme": "海岸"}, {"name": "藥泉寺", "type": "primary", "theme": "寺院"}, {"name": "午餐", "type": "meal", "theme": "餐食"}, {"name": "雪綠茶博物館", "type": "secondary", "theme": "文化"}, {"name": "漢拏山御乘生岳（UNESCO）", "type": "primary", "theme": "火山"}, {"name": "濟州市下車（5個地點可選）", "type": "return", "theme": "返回"}], "routePhases": [{"phase": "西歸浦海岸早晨", "duration": "約2小時", "description": "正房瀑布（亞洲唯一直落入海的瀑布）與外突岩・偶來7號路線海岸漫步。"}, {"phase": "寺院 + 午餐", "duration": "約1小時40分鐘", "description": "參觀東亞最大寺院藥泉寺後，享用濟州南部在地午餐。"}, {"phase": "茶（茶）收尾", "duration": "約1小時", "description": "雪綠茶博物館與韓國最大的西廣茶園。"}, {"phase": "漢拏山壓軸", "duration": "約1小時15分鐘", "description": "沿1100號公路越過漢拏山，遊覽御乘生岳步道（UNESCO）。"}, {"phase": "返回", "duration": "約40分鐘", "description": "1100號公路 → 經由5個下車站點返回濟州市。"}], "routeShapeIntro": {"title": "今日行程的流程", "subtitle": "早晨南下至西歸浦南部海岸，遊覽正房瀑布與外突岩・偶來步道，途經東亞最大寺院藥泉寺與午餐、雪綠茶博物館，並於一天結束時沿1100號公路越過漢拏山，以御乘生岳步道作結的逆時針路線。這是一條經精心設計、讓旅客一次體驗瀑布・海岸・寺院・茶園・火山的行程。"}, "whyTourWorks": {"bestFor": ["初次造訪當地的旅客", "情侶・蜜月旅客", "成人家庭", "喜愛海岸漫步與偶來步道的活躍旅客", "對寺院・茶文化等韓國文化感興趣的旅客"], "lessIdealFor": ["希望減少步行的旅客", "需要推嬰兒車的團體", "當天航班緩衝時間緊湊的旅客"], "routeLogicSections": [{"title": "為何如此規劃這條路線", "icon": "route", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "items": [{"label": "幾乎全程免費入場 — 僅正房瀑布需₩2,000", "detail": "外突岩・偶來7號路線、藥泉寺、Osulloc、漢拏山御乘生岳皆為免費，僅正房瀑布門票（成人₩2,000）含於基本價格中。相較於多數濟州團體行程須每人另付₩15,000–₩20,000門票，本行程當天唯一的實質額外支出僅為午餐（約₩15,000）。"}, {"label": "明確的「禁止購物」政策", "detail": "營運商明確公告禁止購物條款 — 行程中不會繞道前往人蔘專賣店或化妝品商場，也沒有抽傭的午餐停留點。路線上的每一站皆為真正的觀光景點。東門市場下車為行程結束後的自由活動，並非強制停留。"}, {"label": "自海岸出發、以漢拏山作結的動線", "detail": "早晨趁團體巴士湧入前先遊覽西歸浦海岸（正房瀑布・外突岩），途經寺院・午餐・茶園，並於一天結束時沿1100號公路越過漢拏山返回濟州市。逆時針環線不走回頭路。"}, {"label": "迷你巴士形式，而非40人座大巴", "detail": "共乘迷你巴士形式使團體規模維持精簡，讓您在外突岩偶來步道與藥泉寺境內享有導遊的個人化關照。不同於大型抽傭巴士團（30～40人），本行程人數控制在12～18人左右，是在無需支付私人行程費用的前提下享有充足關照的最佳規模。"}]}]}, "practicalAccordionItems": [{"id": "inclusions", "title": "包含項目", "preview": "附空調小型巴士、持證英語／中文導遊、正房瀑布門票…", "content": ["附空調小型巴士、持證英語／中文翻譯導遊、正房瀑布門票、燃油費／過路費／停車費。", "外突岩・偶來7號路線、藥泉寺、Osulloc、漢拏山御乘生岳皆為免費入場。", "不含：午餐（約₩15,000）、飲料、小費。", "當天唯一的實質額外支出僅為午餐 — 為幾乎全程免費入場的行程結構。"]}, {"id": "pickup", "title": "上下車地點", "preview": "依序於四個地點接客：濟州海洋套房酒店（08:30）→ 濟州機場3號門、3樓國內出發大廳…", "content": ["依序於四個地點接客：濟州海洋套房酒店（08:30）→ 濟州機場3號門、3樓國內出發大廳（08:45）→ 濟州樂天城市酒店（08:55）→ 濟州新羅免稅店（09:05）。", "訂票時請選擇最近的上車地點。", "請提前10分鐘抵達；逾時10分鐘以上恕不退款。", "出發前一天將透過WhatsApp發送確認通知。"]}, {"id": "walking", "title": "步行與地形", "preview": "中等難度。", "content": ["中等難度。", "正房瀑布須下行再上行約130級階梯至瀑布下方（岩石地帶請注意濕滑）。", "外突岩・偶來7號路線大致為平坦的海岸步道，部分為天然石路段。", "藥泉寺為平坦的寺院境內，進入法堂時有部分階梯。", "Osulloc地形平坦，可推嬰兒車通行。", "漢拏山御乘生岳為單程1.3公里的木階梯上坡，來回約60～75分鐘。", "全程步行距離約4公里。", "務必穿著包覆腳趾的舒適鞋履；建議穿著防滑健行鞋。"]}, {"id": "cancellation", "title": "取消政策", "preview": "接送前24小時前可免費取消。", "content": ["接送前24小時前可免費取消。", "當日取消及未出現者恕不退款。", "若遇大雪或步道・1100號公路封閉，漢拏山御乘生岳可能改至漢拏山低海拔替代地點（神秘道路或濟州國立博物館）。"]}, {"id": "drop", "title": "下車選項", "preview": "五個下車地點：新羅免稅店（≈17:30）、樂天城市酒店（≈17:35）、濟州機場…", "content": ["五個下車地點：新羅免稅店（≈17:30）、樂天城市酒店（≈17:35）、濟州機場（≈17:40）、海洋套房（≈17:45）、東門傳統市場（≈18:00）。", "東門市場僅限下車，營運人員不會陪同您進入市場。", "黑豬肉街距東門市場步行約5分鐘。"]}, {"id": "children", "title": "兒童與無障礙設施", "preview": "歡迎所有年齡層的兒童。", "content": ["歡迎所有年齡層的兒童。", "正房瀑布（階梯）與漢拏山御乘生岳（連續木製階梯）不適合嬰兒車。", "外突岩・偶來步道、藥泉寺、Osulloc大致可進入。", "正房瀑布・御乘生岳因階梯而輪椅進入受限，藥泉寺・Osulloc大致可進入。", "預訂時請提前告知行動相關的不便需求。"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "請參閱季節性注意事項"}, "tomorrow": {"temp": "—", "label": "請參閱季節性注意事項"}, "_seasonalSummary": "Jeju has Korea''s mildest climate — coastal areas rarely freeze in winter, and summers are humid but moderated by sea breeze. The Hallasan trailhead is 5–10°C colder than coastal Jeju year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "8–22°C", "notes": "Cherry blossoms in early April. Great season for the Hallasan Eoseungsaengak trail and the Seogwipo coastal walks (Jeongbang Falls, Oedolgae, Olle 7)."}, {"season": "Summer (Jun–Aug)", "range": "22–30°C", "notes": "Humid; afternoon showers common. Jeongbang Falls and the Oedolgae coast stay cooler with the sea breeze."}, {"season": "Autumn (Sep–Nov)", "range": "10–24°C", "notes": "Best season — clear and mild, with the sharpest Oedolgae coast and Hallasan summit views."}, {"season": "Winter (Dec–Feb)", "range": "3–10°C", "notes": "Mild on the coast; Hallasan upper slopes can have snow and the 1100 Road may close."}]}, "seasonalVariations": [{"season": "春季", "description": "西歸浦海岸與沿途各處盛開櫻花・油菜花，是最適合遊覽漢拏山御乘生岳的季節。"}, {"season": "夏季", "description": "正房瀑布與外突岩海岸因涼爽的海風而成為人氣避暑地。午後陣雨頻繁，請準備雨衣。"}, {"season": "秋季", "description": "天氣晴朗涼爽，是攝影的最佳季節。外突岩海岸與漢拏山視野最為清晰。"}, {"season": "冬季", "description": "海岸溫和，但漢拏山高地可能降雪。積雪時1100號公路・御乘生岳可能封閉。"}], "bookingTrustItems": [{"icon": "check-circle", "title": "本地公認營運商", "description": "已投保完整保險的韓國公認旅行社", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600", "body": "本地公認營運商 — 以小團深度遊覽濟州南部西歸浦海岸代表性名勝的超值行程。"}, {"icon": "route", "title": "路線專家", "description": "並非制式循環路線，而是親自設計的客製行程", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "body": "幾乎全程免費入場：外突岩・偶來7號路線（免費）、藥泉寺（免費）、Osulloc（免費）、漢拏山御乘生岳（免費）— 僅正房瀑布（₩2,000）含於基本價格。"}, {"icon": "users", "title": "舒適的團體規模", "description": "依路線最佳化的人數配置", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600", "body": "以小型包廂巴士運營，讓您從容享受外突岩偶來步道與藥泉寺境內、正房瀑布階梯路 — 與大型巴士團截然不同。"}], "bookingSupportSteps": [{"timing": "立即", "title": "即時確認預訂", "detail": "發送含行程摘要的訂位確認", "description": "即時確認預訂，含濟州市飯店接送資訊（市區內免費；市區外加收₩70,000）。"}, {"timing": "出發前12小時", "title": "12小時前提醒", "detail": "天氣更新及路線調整通知", "description": "事先提供正房瀑布・外突岩海岸狀況及漢拏山1100號公路狀態說明。"}, {"timing": "前一天晚上", "title": "最終接送資訊", "detail": "確認確切接送時間及司機聯絡方式", "description": "前一天晚上確認最終接送時間。"}, {"timing": "旅遊當天早上", "title": "當日路線說明", "detail": "根據即時狀況進行的早晨簡報", "description": "早晨天氣說明及漢拏山御乘生岳・1100號公路狀態公告。"}, {"timing": "行程進行中", "title": "各站點貼心提示", "detail": "各景點即時導覽指引", "description": "導遊將介紹正房瀑布「徐市過此」地名傳說、外突岩的形成與《大長今》拍攝地、東亞最大寺院藥泉寺、1979年愛茉莉太平洋創立Osulloc的背景，以及漢拏山的盾狀火山特性。"}, {"timing": "行程結束後", "title": "行程後續服務", "detail": "後續跟進與推薦建議", "description": "下車後將發送行程滿意度問卷。"}], "staticQuestions": [{"id": "q1", "question": "此行程全年皆有運營嗎？", "answer": "是的。此路線全年每天均有運營。西歸浦海岸的氛圍與漢拏山視野會隨季節而有所不同，但全日行程的流程維持不變。冬季積雪時，漢拏山御乘生岳可能改至低海拔替代地點。"}, {"id": "q2", "question": "在正房瀑布與漢拏山步行會很吃力嗎？", "answer": "正房瀑布須下行再上行約130級階梯至瀑布下方，漢拏山御乘生岳則為單程1.3公里的木階梯上坡（來回約60～75分鐘）。穿著包覆腳趾的舒適運動鞋即可，無需專業登山裝備。此路線不包含漢拏山山頂（白鹿潭）攀登。"}, {"id": "q3", "question": "此行程包含哪些景點？", "answer": "遊覽正房瀑布（亞洲唯一直落入海的瀑布）、外突岩與偶來7號路線海岸漫步、東亞最大寺院藥泉寺、雪綠茶博物館，以及漢拏山御乘生岳步道。是一條自西歸浦海岸出發、以漢拏山作結的濟州南部招牌路線。"}, {"id": "q4", "question": "包含門票嗎？", "answer": "是的。正房瀑布門票（成人₩2,000）含於基本價格中。外突岩・偶來7號路線、藥泉寺、Osulloc、漢拏山御乘生岳皆為免費入場。當天唯一的實質額外支出僅為午餐（約₩15,000）。"}, {"id": "q5", "question": "包含午餐嗎？", "answer": "不包含 — 午餐費用自理（約15,000韓元）。導遊將推薦在地餐廳，並可協助有素食、純素、清真或過敏需求的旅客，請於訂購時提前告知。"}, {"id": "q6", "question": "機場接送時可以攜帶行李嗎？", "answer": "可以。請事先告知營運商行李數量。小型包廂巴士設有專屬行李空間，搭乘清晨班機抵達的旅客也可攜帶行李直接加入行程。"}, {"id": "first-time", "question": "對於初次造訪濟州南部的遊客，這是一個好選擇嗎？", "answer": "是的 — 一天之內即可均衡遊覽西歸浦海岸、寺院、茶園以至漢拏山，涵蓋該地區最具特色的景點。"}, {"id": "walking", "question": "步行移動會很吃力嗎？", "answer": "雖然是包含正房瀑布階梯與漢拏山御乘生岳上坡的活躍行程，但外突岩偶來步道與藥泉寺・Osulloc相對平坦。"}, {"id": "family", "question": "此行程適合家庭旅客參加嗎？", "answer": "若是孩子能應付全天移動的家庭便很適合。海岸漫步與寺院・茶園，孩子也能輕鬆愉快地享受。"}, {"id": "seniors", "question": "長者也能舒適地參加嗎？", "answer": "建議習慣正房瀑布階梯與御乘生岳上坡的活躍長者參加。外突岩・藥泉寺・Osulloc相對輕鬆。"}, {"id": "children", "question": "建議的最低年齡是幾歲？", "answer": "約10歲以上較為適合，適合能消化全日行程與上述步行說明的兒童。"}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "請選擇日期及人數，即時確認名額並完成預訂。", "price": {"amountLabel": "", "originalPriceUsd": null, "salePriceUsd": null, "discountPercent": null, "currency": "USD", "per": "person"}}, "pickup_dropoff": {"departure": [{"order": 1, "time": "08:30", "name": "Ocean Suites Jeju Hotel", "type": "hotel", "note": "於飯店大廳集合——導遊將手持 AtoCKorea 指示牌。", "lat": 33.51823, "lng": 126.52317}, {"order": 2, "time": "08:45", "name": "濟州國際機場（3樓，3號閘口）", "type": "airport", "note": "3樓出境大廳，請依指示前往3號閘口。", "lat": 33.50708, "lng": 126.49343}, {"order": 3, "time": "08:55", "name": "LOTTE City Hotel Jeju", "type": "hotel", "note": "於主大廳等候——導遊將點名呼叫您。", "lat": 33.4906, "lng": 126.48643}, {"order": 4, "time": "09:05", "name": "Shilla Duty Free（濟州店）", "type": "shopping", "note": "於新羅免稅店濟州分店正門外集合。", "lat": 33.48631, "lng": 126.48739}], "return": [{"order": 1, "name": "Ocean Suites Jeju Hotel", "type": "hotel", "lat": 33.51823, "lng": 126.52317}, {"order": 2, "name": "濟州國際機場（3樓，3號閘口）", "type": "airport", "lat": 33.50708, "lng": 126.49343}, {"order": 3, "name": "LOTTE City Hotel Jeju", "type": "hotel", "lat": 33.4906, "lng": 126.48643}, {"order": 4, "name": "Shilla Duty Free（濟州店）", "type": "shopping", "lat": 33.48631, "lng": 126.48739}, {"order": 5, "name": "東門傳統市場", "type": "market", "lat": 33.51204, "lng": 126.52828}], "notes": ["回程通常約於 17:30–18:00 左右。"]}, "matching_profile": {"profile_version": 7, "is_active": true, "product_id": "jeju-southern-top-unesco-spots-tour", "product_type": "small_group", "route_type": "fixed_route", "destination_region": "jeju", "region_type": "jeju_south", "vehicle_type": "minicoach", "duration_hours": 9, "region_tags": ["jeju_south", "jeju_seogwipo"], "theme_tags": ["coastal_scenery", "waterfall", "temple_culture", "tea_culture", "hallasan_unesco"], "poi_tags": ["jeongbang_falls", "yakcheonsa_temple", "osulloc_tea_museum", "hallasan_eoseungsaengak"], "pace_level": 0.6, "walking_level": 0.6, "scenic_level": 0.9, "photo_level": 0.95, "culture_level": 0.7, "relax_level": 0.65, "first_time_fit": 0.9, "family_fit": 0.65, "senior_fit": 0.6, "couple_fit": 1, "solo_traveler_fit": 0.9, "active_traveler_fit": 0.8, "adult_family_fit": 0.8, "family_with_teens_fit": 1, "young_kids_fit": 0.6, "senior_active_fit": 0.6, "senior_general_fit": 0.45, "mobility_friendly_fit": 0.55, "stroller_fit": 0.5, "one_day_fit": 1, "same_day_flight_fit": 0.7, "rain_fit": 0.4, "value_for_money_fit": 0.95, "iconic_land