tralia_market_fit": 0.85, "japan_market_fit": 0.85, "coastal_scenery_fit": 1, "sea_stack_fit": 1, "seogwipo_coast_fit": 1, "olle_trail_fit": 0.85, "oceanfront_fit": 1, "temple_fit": 1, "buddhist_temple_fit": 1, "largest_temple_east_asia_fit": 1, "templestay_anchor_fit": 0.6, "seobulgwacha_legend_fit": 1, "dae_jang_geum_filming_fit": 1}, "matching_metadata": {"primary_themes": ["jeju", "south_jeju", "seogwipo_coast", "waterfall", "temple_culture", "tea_culture", "olle_trail"], "secondary_themes": ["hallasan_unesco", "oedolgae", "sea_stack", "yeongjusipgyeong", "amorepacific", "jeju_geopark", "honeymoon_classic"], "best_for": ["first_time_jeju", "couples", "honeymooners", "senior_couples", "coastal_scenery_lovers", "temple_culture_travelers", "tea_enthusiasts", "olle_walkers"], "not_recommended_for": ["thrill_seekers", "private_tour_seekers", "guests_demanding_east_coast_coverage", "wheelchair_users_unable_to_climb_eoseungsaengak", "guests_wanting_minimal_walking"], "anchor_pois": ["Jeongbang Falls", "Oedolgae Rock & Olle Trail 7", "Yakcheonsa Temple", "Osulloc Tea Museum", "Hallasan Eoseungsaengak Trail"], "competing_products": ["jeju-west-south-full-day-authentic-tour", "southwest-hallasan-osulloc-aewol", "jeju-grand-highlights-loop", "jeju-eastern-unesco-spots-day-tour"], "anchor_poi_keys": ["jeongbang_falls", "yakcheonsa_temple", "osulloc_tea_museum", "hallasan_eoseungsaengak"], "audit_summary": "South Jeju (Seogwipo) coastal signature loop covering 5 distinct stops in one day: Jeongbang Falls (the only waterfall in Asia that plunges directly into the ocean; one of Jeju''s Yeongjusipgyeong 10 Scenic Wonders and origin of the Seogwipo place-name via the Seobulgwacha legend), Oedolgae sea stack + a short Olle Trail Route 7 coastal walk (Jeju Global Geopark geosite; Dae Jang Geum filming location), Yakcheonsa Temple (one of the largest Buddhist temple complexes in East Asia, 30 m Daejeokgwangjeon hall + 5 m Vairocana Buddha, free), Osulloc Tea Museum (Korea''s largest green-tea field, Seogwang Dawon, free), and Hallasan Eoseungsaengak Trail (UNESCO World Heritage 2007 + Biosphere 2002, free). Counter-clockwise loop: coast in the morning, finishing over the 1100 Road across Hallasan. Almost entirely free admission — only Jeongbang Falls charges (~₩2,000). Sister tours add Camellia Hill / Jusangjeolli (botanical + columnar emphasis) or Songaksan + Hyeopjae (volcano + beach emphasis).", "score_rationale": {"high_scores": {"ocean_falling_waterfall_fit=1.0": "Jeongbang Falls is the only waterfall in Asia falling directly into the ocean", "value_for_money_fit=0.95": "Almost all stops are free; only Jeongbang Falls charges ~₩2,000 — densest free-admission Jeju loop", "coastal_scenery_fit=1.0": "Jeongbang Falls + Oedolgae sea stack + Olle 7 coastal walk = strong Seogwipo coast focus", "tea_enthusiast_fit=1.0": "Osulloc + Seogwang Dawon = Korea''s tea-culture flagship destination", "temple_fit=1.0": "Yakcheonsa — one of the largest Buddhist temple complexes in East Asia", "yeongjusipgyeong_fit=0.85": "Jeongbang Falls + Hallasan are both among Jeju''s 10 Scenic Wonders"}, "low_scores": {"private_tour_fit=0.05": "Format is small-group fixed itinerary only", "east_jeju_fit=0.05": "Loop deliberately south + Seogwipo anchored", "rain_fit=0.4": "Only Osulloc interior and Yakcheonsa hall are reliable rain refuges; most stops are outdoor coast/trail", "botanical_garden_fit=0.0": "No botanical garden on this route (sister tour covers Camellia Hill)"}}, "differentiation_vs_west_south_authentic_sister": "Shares the Osulloc + Hallasan anchors, but leads with the **Seogwipo coastal trio** — Jeongbang Falls (Asia''s only ocean-plunging waterfall), Oedolgae sea stack + Olle Trail 7, and Yakcheonsa (East Asia''s largest temple) — instead of the sister tour''s Jusangjeolli columnar cliff + Cheonjeyeon + Camellia Hill botanical emphasis. This tour = coast + temple + tea + Hallasan UNESCO, almost entirely free admission; sister = waterfalls + columnar geology + year-round flower garden. Pair complementarily for guests with 2 days on Jeju.", "seasonal_window": {"best_months": ["April", "May", "October", "November", "March (cherry start)"], "good_months": ["June", "September", "December", "February"], "caveat_months": ["July (monsoon)", "August (heat + crowds)", "January (Hallasan/1100 Road ice)"], "peak_crowd_months": ["April (cherry)", "October (foliage)"]}, "kb_anchor_version": "1.29"}, "itinerary_variants": [], "_publication": {"schema_version": "v4_canonical", "last_modified": "2026-06-24", "version_history": ["v11", "v12", "v13", "v14", "v15", "v15.2", "v18"], "fix_passes": {"v12": "P0+P1 — pickup_dropoff Schema A unification, routeFlowStops type-based, competing_products → internal slugs, anchor_poi_keys aligned", "v13": "P1.5 — pickup_dropoff Schema A.2 → A.1; practicalAccordionItems / routePhases / seasonalVariations unified to V4 standard (no Tailwind in data)", "v14": "P2 — _publication uniform; duration formatting standardized; glanceItems Duration added where missing", "v15": "P3 round 1 — SEO trim. seo.pageTitle rewritten to ≤65 chars (was 14/25 over 70); seo.metaDescription rewritten to ≤168 chars (was 25/25 over 170). primaryKeywords and ogImage unchanged. Hero/OG images, POI verification, review imports, and routePhases enrichment deferred to later P3 rounds.", "v15.2_charter_consolidation": "Removed \"jeju-popular-sightseeing-private-car-charter-tour\" from competing_products per Jason''s one-charter-per-region rule (jeju-island-private-car-charter-tour remains as standard Jeju charter).", "v17_schema_unification": {"date": "2026-04-28", "description": "Phase 1: Standardized matching_profile scores to the current 0-1 float scale used by match_tours.matching_profile.", "fields_converted": 43, "fields_skipped": 0, "fields_already_float": 0}, "v17_batch3_enhancement": {"date": "2026-04-28", "description": "Batch 3 deep enhancement — descriptions raised to 700-1100+ chars; KB-backed metadata on all attraction stops; matching_profile recalibrated with verified-fact 0-1 float scores. Indoor ratio computed time-weighted using KB indoor_ratio_at_stop methodology established in Fix 1.", "_score_audit": {"_methodology": "0-1 float scale. Indoor ratio computed time-weighted from KB indoor_ratio_at_stop values per Jason''s correction methodology.", "deltas_applied": {"unesco_fit": {"old": 1, "new": 0.95, "reasoning": "Verified: 2 of 6 stops directly UNESCO — Hallasan UNESCO World Heritage (Eoseungsaengak gateway) + Daepo Jusangjeolli is on UNESCO Global Geopark list. Cheonjeyeon Falls + O''sulloc + Camellia Hill are non-UNESCO. 0.95 reflects strong UNESCO core but not pure UNESCO loop."}, "walking_level": {"old": 0.8, "new": 0.65, "reasoning": "Verified totals: Eoseungsaengak 1.3 km + 169 m gain (steep), Camellia Hill ~2 km flat, Cheonjeyeon ~0.5 km + stair section, Jusangjeolli ~0.5 km flat boardwalk, O''sulloc 1 km flat. Total ~5 km + Eoseungsaengak elevation. Mechanical 0.8 was overstated; verified 0.65 with one moderate climb."}, "scenic_level": {"old": 0.8, "new": 0.9, "reasoning": "Verified 6 distinct landscape types: alpine oreum summit (Eoseungsaengak), botanical color-themed garden (Camellia Hill), three-tier waterfall + nymph bridge (Cheonjeyeon), basalt columnar coast (Jusangjeolli), tea-field rolling hills (O''sulloc). High landscape diversity = 0.9."}, "photo_level": {"old": 0.8, "new": 0.95, "reasoning": "Verified: 6 hero-image spots — Hallasan summit ridge, window-frame camellia (Camellia Hill signature), Seonimgyo nymph bridge over Cheonjeyeon, hexagonal basalt columns, O''sulloc tea fields. 0.95 calibrated."}, "iconic_landmark_fit": {"old": 1, "new": 0.85, "reasoning": "Verified: 3 of 6 stops universally iconic (Hallasan, Jusangjeolli, O''sulloc); Camellia Hill regionally iconic; Cheonjeyeon Falls famous. 0.85 calibrated."}, "stroller_fit": {"old": 0.6, "new": 0.5, "reasoning": "Verified: Camellia Hill flat paved (good), Jusangjeolli boardwalk (good), O''sulloc flat (good), Cheonjeyeon has steep stairs (NOT stroller-friendly), Eoseungsaengak is a 169 m climb (NOT stroller-friendly). 3/5 stroller-friendly = 0.5."}, "mobility_friendly_fit": {"old": 0.6, "new": 0.55, "reasoning": "Same logic as stroller_fit — Eoseungsaengak elevation + Cheonjeyeon stairs limit access. 3/5 stops mobility-friendly = 0.55."}, "indoor_ratio": {"old": 0.6, "new": 0.2, "reasoning": "MAJOR CORRECTION using time-weighted method (per Jason''s methodology): Eoseungsaengak 5%, Camellia Hill 15%, Cheonjeyeon Falls 5%, Jusangjeolli 0%, O''sulloc 50%, time-weighted = 50.25/330 ≈ 0.15 excluding lunch. With lunch (80% indoor) included: 98.25/390 = 0.25. Catalog value 0.20 represents the substantive-attraction average. Mechanical Phase 1 conversion 0.6 was wildly off."}, "weather_sensitivity": {"old": 0.6, "new": 0.8, "reasoning": "UPGRADED — 80% of stop time is outdoor. Eoseungsaengak summit very wind-and-weather exposed. Camellia Hill garden weather-dependent. Songaksan-style. Verified high weather sensitivity."}, "rain_fit": {"old": 0.6, "new": 0.4, "reasoning": "DOWNGRADED — only O''sulloc Tea Museum interior is a reliable rain refuge. Eoseungsaengak, Cheonjeyeon, Jusangjeolli, and most of Camellia Hill are weather-exposed. Verified poor rain hedge."}, "intangible_heritage_fit": {"old": 0.8, "new": 0.55, "reasoning": "Verified: only Cheonjeyeon Falls has direct intangible heritage (Chilseonyeo Festival, Seven Nymphs legend). Hallasan and Jusangjeolli are natural heritage but not intangible. O''sulloc tea ceremony has cultural significance but not registered intangible heritage. 0.55 calibrated."}, "first_time_fit": {"old": 1, "new": 0.95, "reasoning": "Verified: covers Hallasan UNESCO + columnar geopark + iconic waterfall + tea culture + flower garden — 5 distinct Jeju essentials. 0.95 is excellent first-Jeju overview but slightly missing food/beach themes."}, "value_for_money_fit": {"old": 1, "new": 0.85, "reasoning": "Verified fees: Camellia Hill ₩12,000 + others mostly free or ₩2,000. Total ~₩14,000 attraction fees per adult. Strong value but Camellia Hill is the cost driver. 0.85 calibrated."}, "young_kids_fit": {"old": 0.8, "new": 0.55, "reasoning": "DOWNGRADED — Eoseungsaengak 169 m climb taxing for under-7s; Cheonjeyeon stairs same issue. Camellia Hill, Jusangjeolli, O''sulloc all kid-friendly. 3/5 kid-friendly + 1 lunch = 0.55. Mechanical 0.8 overstated."}, "senior_fit": {"old": 0.6, "new": 0.55, "reasoning": "Slight downgrade — Eoseungsaengak climb + Cheonjeyeon stairs excludes mobility-impaired seniors. Active seniors fine; general seniors face real obstacles. 0.55 verified."}, "culture_level": {"old": 0.8, "new": 0.65, "reasoning": "DOWNGRADED — verified: 1 strong cultural anchor (O''sulloc tea museum + Korean tea heritage) + Cheonjeyeon legend. Most of the route is nature/garden. 0.65 calibrated."}}}, "stops_enhanced": 8, "sources": ["VisitKorea", "Visit Jeju", "Ramsar SIS", "AllTrails", "Inside Jeju", "Jeju Tourism Org"]}, "v18_route_change_seogwipo_coast": {"date": "2026-06-24", "description": "Route changed to the South Jeju (Seogwipo) coastal signature loop: Jeongbang Falls → Oedolgae & Olle Trail 7 → Yakcheonsa Temple → Lunch → Osulloc Tea Museum → Hallasan Eoseungsaengak. Pickup/drop-off points unchanged. Replaced Eoseungsaengak-opening / Camellia Hill / Cheonjeyeon / Jusangjeolli content; reused KB POIs (jeongbang_falls, yakcheonsa_temple, osulloc_tea_museum, hallasan_eoseungsaengak); Oedolgae & Olle 7 added as embedded stop (no KB POI image). matching_profile/metadata recalibrated for coast + temple emphasis (unesco_fit 0.95→0.7, ocean_falling_waterfall_fit 0→1, botanical/columnar fits → 0, value_for_money 0.85→0.95, total_admission_krw_per_adult 16500→2000). Price set to listPriceUsd 49 (≈₩72,000). All 6 locales updated.", "stops_changed": 6}}}}'::jsonb
