ama_filming_fit": 0.85, "k_reality_filming_fit": 0.3, "mythology_fit": 0.7, "korean_folklore_fit": 0.75, "qin_dynasty_legend_fit": 1, "yeongjusipgyeong_fit": 0.85, "walking_level_fit": 0.65, "stair_climbing_fit": 0.55, "trail_walking_fit": 0.8, "elevation_gain_total_m": 200, "moderate_mobility_fit": 1, "low_intensity_fit": 0.75, "senior_friendly_fit": 0.8, "stroller_friendly_fit": 0.6, "wheelchair_accessible_anchor_fit": 0.6, "mobility_limited_friendly_fit": 0.65, "first_time_korea_fit": 0.9, "small_family_fit": 0.95, "young_kids_friendly_fit": 0.85, "senior_couple_fit": 0.95, "honeymoon_fit": 0.9, "history_lover_fit": 0.85, "geology_enthusiast_fit": 1, "botanical_enthusiast_fit": 0.2, "tea_enthusiast_fit": 1, "k_drama_fan_fit": 0.7, "photographer_fit": 1, "instagrammable_fit": 1, "group_size_min": 2, "group_size_max": 14, "small_group_van_fit": 1, "calm_pace_fit": 0.95, "active_pace_fit": 0.55, "checkbox_sightseeing_fit": 0.85, "deep_dwell_fit": 0.85, "balanced_pace_fit": 1, "varied_terrain_fit": 1, "language_english_fit": 1, "language_chinese_fit": 0.95, "language_japanese_fit": 0.7, "english_guide_fit": 1, "botanical_guide_fit": 1, "spring_fit": 1, "summer_fit": 0.9, "autumn_fit": 1, "winter_fit": 0.85, "all_year_fit": 1, "off_season_fit": 0.85, "monsoon_fit": 0.7, "best_season_winter_fit": 0.7, "camellia_season_anchor_fit": 0, "year_round_attraction_fit": 1, "indoor_anchor_fit": 0.5, "wind_sensitivity": 0.55, "indoor_fallback_anchor_count": 2, "early_start_fit": 0.85, "late_finish_fit": 0.7, "full_day_fit": 1, "half_day_fit": 0.05, "value_priced_fit": 0.95, "budget_traveler_fit": 0.85, "free_admission_anchor_count": 4, "total_admission_krw_per_adult": 2000, "off_beaten_path_fit": 0.4, "crowd_avoidance_fit": 0.4, "tourist_circuit_fit": 1, "instagram_anchor_count": 4, "minicoach_fit": 1, "max_pax_per_vehicle": 14, "jeju_city_pickup_fit": 1, "airport_pickup_fit": 1, "airport_drop_compatible_fit": 1, "dongmun_market_drop_fit": 0.95, "five_pickup_drop_points_fit": 1, "cruise_shore_excursion_fit": 0.55, "cruise_passenger_fit": 0.7, "korean_food_fit": 0.95, "jeju_local_cuisine_fit": 1, "galchi_fit": 1, "mulhoe_fit": 0.85, "black_pig_heritage_fit": 0.85, "seafood_fit": 0.95, "vegetarian_friendly_fit": 0.75, "halal_friendly_fit": 0.65, "tea_tasting_fit": 1, "photo_anchor_count": 4, "drone_friendly_fit": 0.5, "filming_location_fit": 0.85, "stair_anchor_count": 2, "barrier_free_anchor_fit": 0.65, "accessibility_focus_fit": 0.85, "is_anchor_for_south_jeju_unesco": false, "catalog_position": "south_jeju_seogwipo_signature_loop", "competing_tours_count": 4, "china_mainland_market_fit": 0, "korea_domestic_market_fit": 0, "taiwan_market_fit": 1, "singapore_market_fit": 1, "hong_kong_market_fit": 1, "china_diaspora_overseas_market_fit": 0.95, "se_asia_market_fit": 0.95, "us_market_fit": 0.85, "europe_market_fit": 0.85, "australia_market_fit": 0.85, "japan_market_fit": 0.85, "coastal_scenery_fit": 1, "sea_stack_fit": 1, "seogwipo_coast_fit": 1, "olle_trail_fit": 0.85, "oceanfront_fit": 1, "temple_fit": 1, "buddhist_temple_fit": 1, "largest_temple_east_asia_fit": 1, "templestay_anchor_fit": 0.6, "seobulgwacha_legend_fit": 1, "dae_jang_geum_filming_fit": 1}, "matching_metadata": {"primary_themes": ["jeju", "south_jeju", "seogwipo_coast", "waterfall", "temple_culture", "tea_culture", "olle_trail"], "secondary_themes": ["hallasan_unesco", "oedolgae", "sea_stack", "yeongjusipgyeong", "amorepacific", "jeju_geopark", "honeymoon_classic"], "best_for": ["first_time_jeju", "couples", "honeymooners", "senior_couples", "coastal_scenery_lovers", "temple_culture_travelers", "tea_enthusiasts", "olle_walkers"], "not_recommended_for": ["thrill_seekers", "private_tour_seekers", "guests_demanding_east_coast_coverage", "wheelchair_users_unable_to_climb_eoseungsaengak", "guests_wanting_minimal_walking"], "anchor_pois": ["Jeongbang Falls", "Oedolgae Rock & Olle Trail 7", "Yakcheonsa Temple", "Osulloc Tea Museum", "Hallasan Eoseungsaengak Trail"], "competing_products": ["jeju-west-south-full-day-authentic-tour", "southwest-hallasan-osulloc-aewol", "jeju-grand-highlights-loop", "jeju-eastern-unesco-spots-day-tour"], "anchor_poi_keys": ["jeongbang_falls", "yakcheonsa_temple", "osulloc_tea_museum", "hallasan_eoseungsaengak"], "audit_summary": "South Jeju (Seogwipo) coastal signature loop covering 5 distinct stops in one day: Jeongbang Falls (the only waterfall in Asia that plunges directly into the ocean; one of Jeju''s Yeongjusipgyeong 10 Scenic Wonders and origin of the Seogwipo place-name via the Seobulgwacha legend), Oedolgae sea stack + a short Olle Trail Route 7 coastal walk (Jeju Global Geopark geosite; Dae Jang Geum filming location), Yakcheonsa Temple (one of the largest Buddhist temple complexes in East Asia, 30 m Daejeokgwangjeon hall + 5 m Vairocana Buddha, free), Osulloc Tea Museum (Korea''s largest green-tea field, Seogwang Dawon, free), and Hallasan Eoseungsaengak Trail (UNESCO World Heritage 2007 + Biosphere 2002, free). Counter-clockwise loop: coast in the morning, finishing over the 1100 Road across Hallasan. Almost entirely free admission — only Jeongbang Falls charges (~₩2,000). Sister tours add Camellia Hill / Jusangjeolli (botanical + columnar emphasis) or Songaksan + Hyeopjae (volcano + beach emphasis).", "score_rationale": {"high_scores": {"ocean_falling_waterfall_fit=1.0": "Jeongbang Falls is the only waterfall in Asia falling directly into the ocean", "value_for_money_fit=0.95": "Almost all stops are free; only Jeongbang Falls charges ~₩2,000 — densest free-admission Jeju loop", "coastal_scenery_fit=1.0": "Jeongbang Falls + Oedolgae sea stack + Olle 7 coastal walk = strong Seogwipo coast focus", "tea_enthusiast_fit=1.0": "Osulloc + Seogwang Dawon = Korea''s tea-culture flagship destination", "temple_fit=1.0": "Yakcheonsa — one of the largest Buddhist temple complexes in East Asia", "yeongjusipgyeong_fit=0.85": "Jeongbang Falls + Hallasan are both among Jeju''s 10 Scenic Wonders"}, "low_scores": {"private_tour_fit=0.05": "Format is small-group fixed itinerary only", "east_jeju_fit=0.05": "Loop deliberately south + Seogwipo anchored", "rain_fit=0.4": "Only Osulloc interior and Yakcheonsa hall are reliable rain refuges; most stops are outdoor coast/trail", "botanical_garden_fit=0.0": "No botanical garden on this route (sister tour covers Camellia Hill)"}}, "differentiation_vs_west_south_authentic_sister": "Shares the Osulloc + Hallasan anchors, but leads with the **Seogwipo coastal trio** — Jeongbang Falls (Asia''s only ocean-plunging waterfall), Oedolgae sea stack + Olle Trail 7, and Yakcheonsa (East Asia''s largest temple) — instead of the sister tour''s Jusangjeolli columnar cliff + Cheonjeyeon + Camellia Hill botanical emphasis. This tour = coast + temple + tea + Hallasan UNESCO, almost entirely free admission; sister = waterfalls + columnar geology + year-round flower garden. Pair complementarily for guests with 2 days on Jeju.", "seasonal_window": {"best_months": ["April", "May", "October", "November", "March (cherry start)"], "good_months": ["June", "September", "December", "February"], "caveat_months": ["July (monsoon)", "August (heat + crowds)", "January (Hallasan/1100 Road ice)"], "peak_crowd_months": ["April (cherry)", "October (foliage)"]}, "kb_anchor_version": "1.29"}, "page_sections": [{"id": "hero", "section_html_id": null, "component": "TourHeroSection", "props": {"headlineLine1": "Jeju Southern (Seogwipo) Signature", "headlineLine2": "Day Tour", "hero": {"imageUrl": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "imagePosition": "center 45%", "tagline": "South Jeju Seogwipo''s signature coastal stops in one day — Jeongbang Falls, Oedolgae Olle Trail, Yakcheonsa Temple, O''sulloc, Hallasan. Free admission at almost every stop.", "pills": ["Small group", "Jeju"], "meta": {"duration": "≈ 9 hours (08:30 first pickup, ≈18:00 drop-off)", "region": "South Jeju", "stops": "8 stops", "rating": 0, "ratingStars": 5}}}}, {"id": "subnav", "section_html_id": null, "component": "TourTabsNav", "props": {"subnavItems": [{"id": "overview", "label": "Overview"}, {"id": "itinerary", "label": "Itinerary"}, {"id": "details", "label": "Details"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "Reviews"}]}}, {"id": "overview", "section_html_id": "overview", "component": "TourAtAGlance", "props": {"glanceItems": [{"icon": "camera", "label": "Photo Potential", "value": "High", "level": 5}, {"icon": "mountain", "label": "Scenery", "value": "High", "level": 5}, {"icon": "footprints", "label": "Walking", "value": "Moderate", "level": 3}, {"icon": "cloud-rain", "label": "Rain Suitability", "value": "Limited", "level": 2}, {"icon": "users", "label": "Family Suitability", "value": "Moderate", "level": 3}, {"icon": "gauge", "label": "Pace", "value": "Balanced", "level": 4}]}}, {"id": "atmosphere", "section_html_id": null, "component": "TourAtmosphereGallery", "props": {"galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "Jeongbang Falls", "alt": "Jeongbang Falls — gallery image 1", "caption": "Jeongbang Falls — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "Yakcheonsa Temple", "alt": "Yakcheonsa Temple — gallery image 2", "caption": "Yakcheonsa Temple — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 3", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "Hallasan Eoseungsaengak Trail", "alt": "Hallasan Eoseungsaengak Trail — gallery image 4", "caption": "Hallasan Eoseungsaengak Trail — photo 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "Jeongbang Falls", "alt": "Jeongbang Falls — gallery image 5", "caption": "Jeongbang Falls — photo 5"}, {"id": 6, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "Jeongbang Falls", "alt": "Jeongbang Falls — gallery image 6", "caption": "Jeongbang Falls — photo 6"}, {"id": 7, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 7", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 7"}, {"id": 8, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 8", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 8"}, {"id": 9, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 9", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 9"}, {"id": 10, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "Hallasan Eoseungsaengak Trail", "alt": "Hallasan Eoseungsaengak Trail — gallery image 10", "caption": "Hallasan Eoseungsaengak Trail — photo 10"}, {"id": 11, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "Hallasan Eoseungsaengak Trail", "alt": "Hallasan Eoseungsaengak Trail — gallery image 11", "caption": "Hallasan Eoseungsaengak Trail — photo 11"}, {"id": 12, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "Hallasan 1100 Highland", "alt": "Hallasan 1100 Highland — gallery image 12", "caption": "Hallasan 1100 Highland — photo 12"}, {"id": 13, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Hallasan 1100 Highland", "alt": "Hallasan 1100 Highland — gallery image 13", "caption": "Hallasan 1100 Highland — photo 13"}, {"id": 14, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Hallasan 1100 Highland", "alt": "Hallasan 1100 Highland — gallery image 14", "caption": "Hallasan 1100 Highland — photo 14"}]}}, {"id": "itinerary", "section_html_id": "itinerary", "component": "TourTimelineSection", "props": {"itineraryStops": [{"number": 1, "time": "09:00", "duration": "30 min", "name": "Pickup (4 points across Jeju City)", "category": "Pickup — Jeju City Hotel/Hub Sequence", "description": "**Pickup is consolidated at four central Jeju City points** to minimize morning crisscrossing: **Jeju International Airport (제주공항)** for guests with same-day arrivals; **Jeju City Hall (제주시청)** for the Yeon-dong / Nohyeong / Old Town hotel cluster; **Hagwi-dong (하귀동)** as the westernmost pickup; and **Dongmun Traditional Market (동문시장)** as the optional eastern Jeju City pickup near the Tapdong waterfront. \n\nThe sequence runs Hagwi → Airport → City Hall → Dongmun, then heads south **along Route 5.16 (National Road 1131), crossing the eastern flank of Hallasan toward the southern Seogwipo coast**. The minicoach is **small-group (max ~14 pax)** with an English-speaking guide. \n\nA **bilingual printed itinerary card** is distributed at pickup, and a weather brief is given at the first stop. Because today''s route starts on the Seogwipo coast and **returns to Jeju City at the end of the day by taking Route 1100 back over Hallasan**, a **Route 1100 closure check** is performed before departure — if closed for snow or ice, the final Hallasan Eoseungsaengak stop substitutes to a lower-elevation alternate (typically Mysterious Road or Jeju National Museum).", "image": null, "highlights": ["**4 pickup points** — Airport, City Hall, Hagwi, Dongmun", "West-to-east sequence minimizes morning coach distance", "**Small-group minicoach (max 14 pax)** with English guide", "Bilingual itinerary card + weather brief at first stop", "**Route 1100 closure check** — before departure (for the return Hallasan leg)", "Morning transit Jeju City → Seogwipo Jeongbang Falls: ~60 min (via Route 5.16)"], "timeUsed": ["Hagwi pickup ~09:00 — 5 min", "Airport pickup ~09:10 — 5 min", "City Hall pickup ~09:20 — 5 min", "Dongmun pickup ~09:30 — 5 min", "Southbound Route 5.16 toward Seogwipo coast — ~60 min"], "whyOnRoute": "Four pickup points cover Jeju City''s major hotel and transport hubs (airport, downtown, old town, market district), minimizing the hassle of crossing the city. In the morning the route descends first to the Seogwipo coast to see Jeongbang Falls and Oedolgae before the midday crowds, then crosses Hallasan via Route 1100 at the end of the day to return to Jeju City — an efficient counter-clockwise loop. The **Route 1100 closure protocol** keeps guests informed about winter return conditions before departure.", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "pickup"}, {"number": 2, "time": "≈ 10:10", "duration": "50 min", "name": "Jeongbang Falls (Asia''s only ocean-falling waterfall)", "category": "Coastal Waterfall — Yeongjusipgyeong · Origin of the name Seogwipo", "description": "**Jeongbang Falls (정방, 正房) is known as the only waterfall in Asia that drops directly from a cliff into the sea**, and it is one of Seogwipo''s signature sights. A **23 m-high, roughly 8 m-wide** sheet of water pours down the basalt sea-wall into the deep blue ocean, and on clear days **Seopseom (섶섬) and Munseom (문섬)** sit in the background. \n\nAlong with Hallasan and Cheonjeyeon, Jeongbang is one of the **Yeongjusipgyeong (영주십경, Jeju''s 10 Scenic Wonders)** chosen by Joseon-era literati, and the cliff is inscribed with the **''Seobulgwacha (徐市過此)'' legend** — the story that Seobul, sent by Emperor Qin Shi Huang to find the elixir of immortality, passed this place and turned back to the west. This is said to be the origin of the place name **''Seogwipo (西歸浦)''**. \n\nFrom the ticket office down to the foot of the falls there are **about 130 steps**, and the ground is made of rounded pebbles and rock, so non-slip footwear is essential. Photos with the spray and the sea as a backdrop are popular at the base, while the clifftop observation deck takes in Seopseom and Munseom at a glance.", "image": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "highlights": ["**The only waterfall in Asia that drops directly into the sea** — 23 m high / approx. 8 m wide", "One of the **Yeongjusipgyeong (Jeju''s 10 Scenic Wonders)** — chosen alongside Hallasan and Cheonjeyeon", "**''Seobulgwacha'' legend** — the Qin Shi Huang / elixir-of-immortality tale that gave ''Seogwipo'' its name", "Coastal scenery with **Seopseom and Munseom** as a backdrop on clear days", "**About 130 steps** down to the foot of the falls — non-slip shoes essential", "Admission **₩2,000 adult / ₩1,000 youth / FREE under 7 + over 65**", "Open **09:00–17:40** (last entry 30 min before closing), year-round", "Mind the waves and slippery rocks when shooting on the rocky shelf — safety first"], "timeUsed": ["Ticketing + entrance briefing — ~5 min", "Descent of about 130 steps — ~10 min", "Falls + coastal rock photography — ~20 min", "Climb back up + clifftop observation deck — ~15 min"], "whyOnRoute": "**The opening highlight of the Seogwipo coast.** Visited early in the morning, Jeongbang Falls can be enjoyed quietly at the base before the tour buses arrive. It is a 15-minute drive from Oedolgae and Olle Route 7, so it links efficiently along the Seogwipo coast and opens the day with a striking ocean view.", "_poi_meta": {"poi_key": "jeongbang_falls", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["VisitJeju — Jeongbang Falls official listing", "Seogwipo-si cultural tourism office — Jeongbang Falls", "Jeju Special Self-Governing Province — Yeongjusipgyeong registry", "Cultural Heritage Administration — Seobulgwacha inscription records"]}, "smartNotes": {"photo": "Water plus sea in one frame from the rocky shelf at the base; distant Seopseom and Munseom from the clifftop deck", "facilities": "Restrooms and ticket office at the entrance (before the stair descent); no facilities at the foot of the falls", "tip": "Stairs and rocks are very slippery when wet — non-slip shoes recommended; don''t confuse it with Cheonjiyeon Falls in Seogwipo"}, "convenience": {"restroom": "Available at the entrance/ticketing area", "parking": "Available at the entrance parking lot"}, "visitBasics": {"hours": "Daily 09:00–17:40 (last entry 30 min before closing, minor seasonal variation)", "closed": "Open year-round (may be temporarily closed at high tide or during typhoons)", "admission": "Adult 2,000 KRW / Youth 1,000 KRW (FREE under 7 + over 65)", "walking": "Moderate — about 130 steps down to the falls, uneven rocky ground; mind slipping"}, "images": ["/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp"], "imageCredits": [{"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "Jeongbang Falls (Asia''s only ocean-falling waterfall)", "caption": "Jeongbang Falls (Asia''s only ocean-falling waterfall) — photo 1", "alt": "Jeongbang Falls (Asia''s only ocean-falling waterfall) — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "Jeongbang Falls (Asia''s only ocean-falling waterfall)", "caption": "Jeongbang Falls (Asia''s only ocean-falling waterfall) — photo 2", "alt": "Jeongbang Falls (Asia''s only ocean-falling waterfall) — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "Jeongbang Falls (Asia''s only ocean-falling waterfall)", "caption": "Jeongbang Falls (Asia''s only ocean-falling waterfall) — photo 3", "alt": "Jeongbang Falls (Asia''s only ocean-falling waterfall) — gallery image 3"}]}, {"number": 3, "time": "≈ 11:10", "duration": "50 min", "name": "Oedolgae & Olle Route 7 Coastal Walk", "category": "Coastal Rock Pinnacle + Olle Trail — Jeju Global Geopark geosite", "description": "**Oedolgae (외돌개) is a roughly 20 m-high coastal rock pillar formed by a volcanic eruption about 1.5 million years ago**, standing alone in the open sea — hence the name ''oe (alone) dol (rock) gae''. Also called ''General Rock'' or ''Grandmother Rock'', it is widely known as a **filming location for the K-drama ''Dae Jang Geum''**. Oedolgae and the layered Seogwipo sea cliffs are one of the **official geosites of the Jeju Global Geopark (UNESCO Global Geopark)**. \n\nOedolgae sits on **Jeju Olle Route 7** — a roughly 17.6 km signature coastal Olle running from the Jeju Olle Travelers Center past Beophwan Port to Wolpyeong, with the much-loved ''Subong-ro'' section passing near Oedolgae. \n\nOn this stop you take in the Oedolgae viewpoint and **walk a short part of the Olle Route 7 coastal path.** The trail through the pine forest looks out over Oedolgae, Seopseom and Munseom, and the endless southern sea, offering a wide-open coastal panorama quite different from the waterfall scenery at Jeongbang. **Free admission**; the path is mostly flat with some natural-rock sections.", "image": null, "highlights": ["**Oedolgae** — a roughly 20 m-high coastal rock pillar formed about 1.5 million years ago (''General Rock'')", "Seogwipo coastal scenery famous as a **''Dae Jang Geum'' filming location**", "**Jeju Global Geopark (UNESCO Global Geopark) geosite**", "On **Olle Route 7** — the much-loved ''Subong-ro'' coastal section", "Views of **Oedolgae + Seopseom/Munseom + the southern sea** from the pine-forest path", "**Free admission**, open year-round — about a 15-min drive from Jeongbang Falls", "Path mostly flat, with some natural-rock sections — comfortable shoes recommended"], "timeUsed": ["Parking + entry onto the Olle trail — ~5 min", "Olle Route 7 coastal path — ~25 min", "Oedolgae viewpoint + photography — ~15 min", "Return to coach — ~5 min"], "whyOnRoute": "**The second Seogwipo-coast highlight and an Olle Trail experience.** A 15-minute drive from Jeongbang Falls makes the routing natural, and the scenery shifts from the vertical view of the falls to the wide-open coastal panorama of Oedolgae. The short Olle Route 7 walk lets you taste the essence of ''Jeju on foot'' without overexertion.", "_poi_meta": {"poi_key": "oedolgae_olle7", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Jeju Olle Foundation — Olle Route 7 official (jejuolle.org)", "VisitJeju — Oedolgae Rock official listing", "Jeju Global Geopark — Oedolgae & Seogwipo layered cliff geosite", "KTO — Dae Jang Geum filming location records"]}, "smartNotes": {"photo": "Oedolgae framed with the sea through the pines; distant Seopseom and Munseom from the viewing deck", "facilities": "Restrooms at the entrance parking lot; few facilities along the coastal path", "tip": "Windy days are common, so bring a layer; mind slipping on the natural-rock sections"}, "convenience": {"restroom": "Available at the Oedolgae parking area", "parking": "Available at the Oedolgae public parking lot"}, "visitBasics": {"hours": "Open at all times (coastal path)", "closed": "Open year-round (some sections may close in strong wind or high swell)", "admission": "Free", "walking": "Easy to moderate — coastal path mostly flat, with some natural-rock and stair sections"}, "images": [], "imageCredits": [], "galleryItems": []}, {"number": 4, "time": "≈ 12:10", "duration": "40 min", "name": "Yakcheonsa Temple (East Asia''s largest temple)", "category": "Temple — East Asia''s largest Daejeokgwangjeon hall", "description": "**Yakcheonsa (약천사, 藥泉寺), at 122,100 ㎡, is counted among the largest temples in East Asia** — a vast temple in Daepo-dong, Seogwipo. Its name means ''the temple where medicinal spring water flows'', as it was built on the site of the old ''Yaksuam'' hermitage, where a year-round spring of healing water rises. **Monk Hyein broke ground in 1981 and completed it in 1996.** \n\nThe main hall, the **Daejeokgwangjeon (大寂光殿), reaches about 30 m in height with a total floor area of about 3,305 ㎡** — one of the largest single Buddhist halls in the East, built in the early-Joseon temple-architecture style. Inside, a **5 m-tall Vairocana Buddha (Korea''s largest wooden seated Buddha)** is enshrined on a 4 m pedestal, and tens of thousands of small gilded Buddha statues filling the multi-tiered walls create an overwhelming sight. In front of the hall stands an **18-tonne temple bell**. \n\nYakcheonsa sits at the **junction where Jeju Olle Route 7 (its end point) meets Route 8 (its start point)**, drawing both Olle walkers and tourists, and it has run a **templestay since 2006**. **Free admission**, and the flat grounds are relatively easy to explore.", "image": "/images/tours/yakcheonsa/photo-001.webp", "highlights": ["**One of East Asia''s largest temples** — grounds of about 122,100 ㎡", "**Daejeokgwangjeon** about 30 m high / about 3,305 ㎡ floor area — one of the East''s largest single halls", "**5 m-tall Vairocana Buddha** — Korea''s largest wooden seated Buddha (on a 4 m pedestal)", "**Tens of thousands of gilded Buddhas** filling the multi-tiered walls + an **18-tonne bell** before the hall", "**Monk Hyein broke ground in 1981 → completed 1996**; on the ''Yaksuam'' site (a rising spring)", "At the junction of **Olle Route 7''s end point + Route 8''s start point**", "**Templestay since 2006**", "**Free admission**, flat grounds — about a 15-min drive from the Jeongbang Falls area"], "timeUsed": ["Parking + entry through the Iljumun gate — ~5 min", "Daejeokgwangjeon + Vairocana Buddha + gilded Buddhas — ~20 min", "Temple bell + grounds walk + spring water — ~12 min", "Return to coach — ~3 min"], "whyOnRoute": "**A cultural highlight just before lunch.** After the coastal scenery of Jeongbang Falls and Oedolgae, the overwhelming interior of Yakcheonsa''s Daejeokgwangjeon adds a different texture to the day. It is close to Oedolgae and near the lunch restaurant, so the routing is efficient, and free admission keeps it easy on the wallet. The guide briefs temple etiquette (quiet, dress).", "_poi_meta": {"poi_key": "yakcheonsa_temple", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Yakcheonsa Temple official records", "VisitJeju — Yakcheonsa Temple official listing", "Jeju Olle Foundation — Route 7/8 junction at Yakcheonsa", "Korean Buddhism Templestay — Yakcheonsa program (since 2006)"]}, "smartNotes": {"photo": "The sheer scale of the Daejeokgwangjeon exterior; the Vairocana Buddha and gilded-Buddha walls inside (check on-site signage for photography rules)", "facilities": "Restrooms and parking on the grounds; spring water available to drink", "tip": "Keep quiet inside the hall, remove hats and observe etiquette; please avoid revealing clothing"}, "convenience": {"restroom": "Available on the temple grounds", "parking": "Free temple parking available"}, "visitBasics": {"hours": "Sunrise–sunset (main hall open at all times)", "closed": "Open year-round", "admission": "Free", "walking": "Easy — flat grounds; some steps when entering the main hall"}, "images": ["/images/tours/yakcheonsa/photo-001.webp"], "imageCredits": [{"url": "/images/tours/yakcheonsa/photo-001.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/yakcheonsa/photo-001.webp", "location": "Yakcheonsa Temple (East Asia''s largest temple)", "caption": "Yakcheonsa Temple (East Asia''s largest temple) — photo 1", "alt": "Yakcheonsa Temple (East Asia''s largest temple) — gallery image 1"}]}, {"number": 5, "time": "≈ 13:00", "duration": "60 min", "name": "Lunch — South Jeju Local Meal", "category": "Midday Reset — Seogwipo / Daepo Local Cuisine", "description": "**A 60-minute break between Yakcheonsa and O''sulloc** — the southern Seogwipo coast is one of Korea''s premier seafood landing zones, and the Daepo-Andeok stretch sits close to the next stop. Default rotation: **galchi-jorim (braised cutlassfish)** — Jeju is Korea''s leading cutlassfish source, with the freshest catches along the south coast; **mulhoe (cold raw-fish soup)** in summer (June–September); or **heuk-doeji gui (Jeju black pig BBQ)** year-round (a native Jeju black pig breed designated **Cultural Heritage Material No. 5 in 2015**). \n\n**Vegetarian alternative**: bibim-guksu with seasonal Jeju vegetables. **Halal-friendly options** available at one venue in the rotation — please disclose at pickup. The lunch venue is **about a 25-min coach ride to O''sulloc**.", "image": null, "highlights": ["**South Jeju seafood corridor** — Seogwipo/Daepo coastal restaurants", "**Galchi-jorim** — Jeju is Korea''s largest cutlassfish source", "**Mulhoe** in summer; **heuk-doeji (black pig)** year-round option", "Black pig is a **Cultural Heritage Material No. 5 (2015)** breed", "**Vegetarian + halal-friendly** options on request (please disclose at pickup)", "**About a 25-min coach ride to O''sulloc** — heading inland to the tea fields after lunch"], "timeUsed": ["Coach to lunch venue — ~10 min", "Order + meal — ~45 min", "Coach to O''sulloc — ~25 min"], "whyOnRoute": "A natural mealtime after seeing the Seogwipo coastal sights. Lunch gives a real rest between the morning coastal walk and temple visit and the afternoon tea-field and Hallasan stops, then the route continues inland to the Seogwang tea field.", "smartNotes": {}, "convenience": {}, "visitBasics": {}}, {"number": 6, "time": "≈ 14:25", "duration": "60 min", "name": "O''sulloc Tea Museum + Green Tea Fields", "category": "Tea Culture Museum — Korea''s largest green-tea field (Seogwang Dawon)", "description": "**O''sulloc Tea Museum (O''Sulloc, ''meeting snow + green'')** is the tea-culture flagship of **Amorepacific**, Korea''s largest beauty company. Founder **Chairman Suh Sung-whan personally pioneered the project in 1979**, reclaiming the volcanic-ash farmland of Jeju''s Seogwang plateau into tea fields. Today the **Seogwang Dawon** is **Korea''s largest green-tea field**, producing **~700 tonnes a year** across Amorepacific''s three Jeju estates. \n\nThe museum building **opened in 2001** in the heart of the plantation, and its minimalist design earned it a place among **designboom''s Top 10 art museums in the world**. **Free admission**, open daily, with about **2 million visitors a year**. The visit splits into three parts: **(1) Museum interior** — the tea-making process, an antique tea-ware collection, and a rooftop observation deck; **(2) Tea House cafe** — the signature **green tea rolling cake** and **green tea ice cream**; **(3) Plantation walking paths** — gravel paths between the tea bushes (a sunset photo spot). \n\n**Innisfree Jeju House** (Amorepacific''s natural-cosmetics brand) is a 5-minute walk away, with free admission and an optional tangerine soap DIY workshop (₩15,000).", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**Amorepacific** flagship brand — founder Suh Sung-whan pioneered Jeju tea cultivation in **1979**", "**Seogwang Dawon = Korea''s largest green-tea field**; ~700 tonnes annual production", "Museum **opened 2001** — named to designboom''s Top 10 art museums (architecture)", "**Free admission**, about 2 million visitors a year", "**Green tea rolling cake** + **green tea ice cream** = the cafe''s signature items", "**Innisfree Jeju House** 5-min walk — free admission, optional tangerine soap DIY ₩15,000", "Plantation paths best for photography at **golden hour (16:00–17:00)**", "Rooftop deck + ground-level tea field — two elevations for composing tea-field shots"], "timeUsed": ["Parking + entrance — ~5 min", "Museum interior + tea-ware collection — ~20 min", "Tea House cafe (rolling cake + ice cream) — ~20 min", "Green tea field walking path — ~15 min"], "whyOnRoute": "**The afternoon tea-culture highlight.** After the coastal sights and the temple, O''sulloc''s tea fields and cafe add a gentle break to the day. It is a 25-minute drive inland from the lunch venue and well placed to head on toward Hallasan via Route 1100 — just the right afternoon window to stroll the tea rows and sample tea desserts.", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Osulloc Tea Museum official site (osulloc.com)", "Amorepacific Corporation — Suh Sung-whan tea reclamation history (1979)", "designboom — Top 10 art museums feature", "VisitJeju — Osulloc Tea Museum official listing"]}, "smartNotes": {"photo": "Teacup-shaped museum building with the tea fields behind it; rooftop observation deck; gravel tea-field paths at sunset", "facilities": "Cafe (the green tea ice cream is a must), gift shop, Innisfree Jeju House right next door, observation deck", "tip": "Early afternoon is quieter before the tour buses arrive; allow 1–1.5 hours including the cafe and the walk"}, "convenience": {"restroom": "Well provided throughout the museum", "parking": "Free parking available"}, "visitBasics": {"hours": "Summer (Apr–Oct) 09:00–19:00 / Winter (Nov–Mar) 09:00–18:00", "closed": "Open year-round (may vary temporarily in bad weather)", "admission": "Museum and tea field free; cafe drinks, desserts and classes charged separately", "walking": "Easy — flat paved paths, stroller- and wheelchair-accessible"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 1", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 2", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 3", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "O''sulloc Tea Museum + Green Tea Fields", "caption": "O''sulloc Tea Museum + Green Tea Fields — photo 4", "alt": "O''sulloc Tea Museum + Green Tea Fields — gallery image 4"}]}, {"number": 7, "time": "≈ 15:55", "duration": "75 min", "name": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage)", "category": "UNESCO Volcanic Geology — Hallasan Eoseungsaengak Trail (triple natural designation)", "description": "**Eoseungsaengak (1,169 m)** is a short Hallasan-side volcanic cone (oreum) trail starting near the Eorimok Visitor Center. Hallasan is Korea''s highest peak and a **UNESCO World Natural Heritage site (2007) and Biosphere Reserve (2002)**, and this trail is a manageable way to experience the mountain without attempting the summit climb. \n\nToday''s route places Eoseungsaengak on the way **back over Hallasan to Jeju City from O''sulloc, taking Route 1100 (Jeju''s highest-altitude national road)**. The trail is far shorter than the Seongpanak or Gwaneumsa summit courses, **does not require the summit reservation system**, and consists of wide steps and wooden decking — sneakers are enough (1.3 km one-way / about 200 m elevation gain). \n\nOn clear days the upper deck observation point looks out over **Hallasan''s high-altitude slopes, Jeju''s oreum field, and the northern sea**, and a **1945 Imperial Japanese tochika (pillbox)** remains at the summit. Mountain weather changes quickly, so bringing a layer is recommended. **Free admission**, and the cool mountain air makes an impressive finale to close the day.", "image": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "highlights": ["**Hallasan = triple natural designation**: UNESCO World Heritage 2007 + Biosphere Reserve 2002 + National Park 1970", "**Eoseungsaengak 1,169 m** — a Hallasan-side oreum (parasitic cone)", "**1.3 km one-way / about 200 m gain** — wide steps + wooden decking, sneakers are enough", "Views of **Hallasan''s slopes, the oreum field, and the northern sea** from the deck observation point", "**1945 Imperial Japanese tochika (pillbox)** at the summit — a rare high-altitude relic", "**Free admission** + free parking; no summit reservation needed (the Baengnokdam course is capped at 1,000/day)", "Round-trip about **60–75 min** — on the route back over Hallasan to Jeju City via Route 1100", "High-altitude weather changes fast — bringing a layer recommended"], "timeUsed": ["Eorimok parking + restroom + trail briefing — ~10 min", "1.3 km decking ascent one-way — ~25 min", "Summit deck + photos + tochika viewing — ~15 min", "Descent — ~20 min", "Buffer / regroup — ~5 min"], "whyOnRoute": "**The Hallasan finale of the south-Jeju route.** Eoseungsaengak offers a genuine mountain experience at a scale suited to a day tour, and it sits naturally on the way back from O''sulloc over Hallasan to Jeju City via Route 1100. A day that began on the coast finishes with UNESCO volcanic scenery. If Route 1100 is closed by winter snow, it may switch to a lower-elevation alternate.", "_poi_meta": {"poi_key": "hallasan_eoseungsaengak", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)", "UNESCO Biosphere Reserve — Jeju Island (2002 designation)", "Hallasan National Park Administration — Eoseungsaengak trail official", "Korea National Park Service — Hallasan visitor management records"]}, "smartNotes": {"photo": "Wide-angle shots from the upper observation deck work well; views to Jeju City on clear days; record shots of the tochika relic", "facilities": "Facilities concentrated at the Eorimok entrance; none along the route", "tip": "A focused scenic walk rather than a leisurely stroll; high-altitude weather changes fast — check Route 1100 and the weather before setting off"}, "convenience": {"restroom": "Available at the Eorimok entrance area", "parking": "Available at Eorimok parking (free)"}, "visitBasics": {"hours": "Trail entry from 05:00 (seasonal variation, extended in summer)", "closed": "Weather-dependent (snow, fog, high-wind closures common Nov–Mar)", "admission": "Free", "walking": "Moderate — short distance but with stairs and uphill sections"}, "images": ["/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "/images/tours/hallasan-eoseungsaengak/photo-003.webp"], "imageCredits": [{"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-19.webp", "location": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage)", "caption": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage) — photo 1", "alt": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage) — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/kakaotalk-20260510-230009595-20.webp", "location": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage)", "caption": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage) — photo 2", "alt": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage) — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-eoseungsaengak/photo-003.webp", "location": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage)", "caption": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage) — photo 3", "alt": "Hallasan Eoseungsaengak (UNESCO World Natural Heritage) — gallery image 3"}]}, {"number": 8, "time": "≈ 17:40", "duration": "40 min", "name": "Drop-off (5 points across Jeju City)", "category": "Drop-off — Jeju City Hub Sequence", "description": "**Drop-off follows the same order as the morning pickup, with one added option**: Dongmun Traditional Market → Jeju City Hall → Hagwi-dong → Jeju International Airport, with an optional stop for the Yeon-dong/Nohyeong hotel zone before City Hall (a 5th drop point). From Eoseungsaengak the coach **takes Route 1100 down off Hallasan and back to Jeju City**. Estimated arrival: Dongmun ~18:30, City Hall ~18:40, Yeon-dong ~18:45, Hagwi ~18:55, Airport ~19:05. \n\n**Same-day evening flights from Jeju International Airport** are generally viable (last departure ~21:30). Coach Wi-Fi is available throughout, and the driver coordinates any guest-requested shop/hotel adjustments.", "image": null, "highlights": ["**5 drop-off points** — Dongmun, City Hall, Yeon-dong/Nohyeong, Hagwi, Airport", "**Dongmun Traditional Market** — optional dinner + tangerine product shopping", "Estimated arrival: Dongmun ~18:30 → Airport ~19:05", "**Same-day evening flights from Jeju International Airport** generally viable (last departure ~21:30)", "Coach Wi-Fi + flexible driver coordination for hotel/shop adjustments"], "timeUsed": ["Eoseungsaengak → Route 1100 → Dongmun — ~40 min", "Dongmun drop — 5 min", "→ City Hall — 10 min, drop — 5 min", "→ Yeon-dong → Hagwi → Airport — sequenced"], "whyOnRoute": "Drop-off follows the return road down off Hallasan via Route 1100 back into Jeju City. Guests with evening flights should tell the guide in advance so the final stop time can be coordinated smoothly.", "smartNotes": {}, "convenience": {}, "visitBasics": {}, "_role": "dropoff"}]}}, {"id": "day_flow", "section_html_id": null, "component": "TourDayFlowSection", "props": {"routeFlowStops": [{"name": "Jeju City + airport pickup", "type": "origin", "theme": "Departure"}, {"name": "Jeongbang Falls", "type": "primary", "theme": "Waterfall"}, {"name": "Oedolgae & Olle Route 7", "type": "primary", "theme": "Coast"}, {"name": "Yakcheonsa Temple", "type": "primary", "theme": "Temple"}, {"name": "Lunch", "type": "meal", "theme": "Meal"}, {"name": "O''sulloc Tea Museum", "type": "secondary", "theme": "Culture"}, {"name": "Hallasan Eoseungsaengak (UNESCO)", "type": "primary", "theme": "Volcano"}, {"name": "Jeju City drop-off (5 options)", "type": "return", "theme": "Return"}], "routePhases": [{"phase": "Seogwipo coast morning", "duration": "≈ 2 hours", "description": "Jeongbang Falls (Asia''s only ocean-falling waterfall) and the Oedolgae & Olle Route 7 coastal walk."}, {"phase": "Temple + lunch", "duration": "≈ 1 hour 40 min", "description": "East Asia''s largest temple, Yakcheonsa, followed by a local south Jeju lunch."}, {"phase": "Tea finale", "duration": "≈ 1 hour", "description": "O''sulloc Tea Museum and Korea''s largest Seogwang Dawon tea field."}, {"phase": "Hallasan finale", "duration": "≈ 1 hour 15 min", "description": "The Eoseungsaengak Trail (UNESCO) while crossing Hallasan via Route 1100."}, {"phase": "Return", "duration": "≈ 40 min", "description": "Route 1100 → Jeju City via 5 drop-off points."}], "routeShapeIntro": {"title": "How this day flows", "subtitle": "A counter-clockwise route that descends in the morning to the southern Seogwipo coast for Jeongbang Falls and Oedolgae & the Olle Trail, passes East Asia''s largest temple Yakcheonsa and lunch and the O''sulloc Tea Museum, then crosses Hallasan via Route 1100 at the end of the day to finish on the Eoseungsaengak Trail. A day designed to take in waterfall, coast, temple, tea field, and volcano all at once."}}}, {"id": "details", "section_html_id": "details", "component": "TourFitSection", "props": {"whyTourWorks": {"bestFor": ["First-time visitors to the area", "Couples & honeymooners", "Adult families", "Active travelers who enjoy coastal walks and the Olle Trail", "Travelers interested in Korean culture such as temples and tea"], "lessIdealFor": ["Travelers who want minimal walking", "Groups with strollers", "Travelers with a tight same-day flight buffer"], "routeLogicSections": [{"title": "Why this route is built this way", "icon": "route", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "items": [{"label": "Free admission at almost every stop — only Jeongbang Falls is ₩2,000", "detail": "Oedolgae & Olle Route 7, Yakcheonsa, O''sulloc, and Hallasan Eoseungsaengak are all free, and only the Jeongbang Falls admission (adult ₩2,000) is included in the base price. Unlike most Jeju group tours, which charge ₩15,000–₩20,000 per person in separate admissions, the only real extra cost on the day is lunch (~₩15,000)."}, {"label": "Explicit ''no shopping'' policy", "detail": "The operator publishes an explicit no-shopping clause — there are no ginseng shops, cosmetic-mall detours, or commission lunch stops. Every stop on the route is an actual attraction. The Dongmun Market drop-off is self-guided after the tour ends, not a forced stop."}, {"label": "A route that starts on the coast and finishes on Hallasan", "detail": "See the Seogwipo coast (Jeongbang Falls, Oedolgae) early in the morning before the tour buses arrive, pass through the temple, lunch and tea field, then cross Hallasan via Route 1100 at the end of the day back to Jeju City. A counter-clockwise loop that never retraces the same road."}, {"label": "Mini-coach format, not a 40-person bus", "detail": "The shared mini-coach format keeps groups small enough for personal guide attention on the Oedolgae Olle trail and within the Yakcheonsa grounds. Unlike large commission-bus tours (30–40 people), this runs closer to 12–18 — the sweet spot for ample attention without paying private-tour rates."}]}]}}}, {"id": "practical", "section_html_id": null, "component": "TourPracticalDetails", "props": {"practicalAccordionItems": [{"id": "inclusions", "title": "What''s included", "preview": "Air-conditioned mini-coach, certified English/Chinese-speaking guide, Jeongbang Falls admission…", "content": ["Air-conditioned mini-coach, certified English/Chinese-speaking interpreter guide, Jeongbang Falls admission, fuel/tolls/parking.", "Oedolgae & Olle Route 7, Yakcheonsa, O''sulloc, and Hallasan Eoseungsaengak are all free admission.", "Not included: lunch (~₩15,000), drinks, tips.", "The only real extra cost on the day is lunch — almost every stop is free admission."]}, {"id": "pickup", "title": "Pickup & drop-off", "preview": "Sequential pickup at four points: Ocean Suites Jeju (08:30) → Jeju Airport Gate 3, 3F…", "content": ["Sequential pickup at four points: Ocean Suites Jeju (08:30) → Jeju Airport Gate 3, 3F Domestic Departures (08:45) → LOTTE City Hotel Jeju (08:55) → Shilla Duty-Free Jeju Store (09:05).", "Choose the closest at booking.", "Arrive 10 minutes early; 10+ minute no-shows are non-refundable.", "Day-before WhatsApp confirmation."]}, {"id": "walking", "title": "Walking & terrain", "preview": "Moderate difficulty.", "content": ["Moderate difficulty.", "At Jeongbang Falls you go down and back up about 130 steps to the foot of the falls (mind slipping on the rocky shelf).", "Oedolgae & Olle Route 7 is a mostly flat coastal path with some natural-rock sections.", "Yakcheonsa has flat grounds, with some steps entering the main hall.", "O''sulloc is flat terrain and stroller-accessible.", "Hallasan Eoseungsaengak is a 1.3 km one-way wooden-stair climb, about 60–75 min round-trip.", "Total walking about 4 km.", "Comfortable closed-toe shoes essential; non-slip trekking shoes recommended."]}, {"id": "cancellation", "title": "Cancellation", "preview": "Free cancellation up to 24 hours before pickup.", "content": ["Free cancellation up to 24 hours before pickup.", "Same-day cancellations and no-shows are non-refundable.", "In heavy snow or when the trail or Route 1100 is closed, Hallasan Eoseungsaengak may be substituted for a lower-elevation Hallasan alternate (Mysterious Road or Jeju National Museum)."]}, {"id": "drop", "title": "Drop-off options", "preview": "Five drop-off points: Shilla Duty-Free (≈17:30), LOTTE City Hotel (≈17:35), Jeju Airport…", "content": ["Five drop-off points: Shilla Duty-Free (≈17:30), LOTTE City Hotel (≈17:35), Jeju Airport (≈17:40), Ocean Suites (≈17:45), Dongmun Traditional Market (≈18:00).", "Dongmun is drop-only — the operator does not accompany you into the market.", "Black Pork Street is a 5-minute walk from Dongmun Market."]}, {"id": "children", "title": "Children & accessibility", "preview": "Children of all ages welcome.", "content": ["Children of all ages welcome.", "Jeongbang Falls (steps) and Hallasan Eoseungsaengak (continuous wooden stairs) are not stroller-accessible.", "Oedolgae & the Olle Trail, Yakcheonsa, and O''sulloc are mostly accessible.", "Jeongbang Falls and Eoseungsaengak have limited wheelchair access due to stairs; Yakcheonsa and O''sulloc are mostly OK.", "Please advise any mobility needs at booking."]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "See seasonal notes"}, "tomorrow": {"temp": "—", "label": "See seasonal notes"}, "_seasonalSummary": "Jeju has Korea''s mildest climate — coastal areas rarely freeze in winter, and summers are humid but moderated by sea breeze. The Hallasan trailhead is 5–10°C colder than coastal Jeju year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "8–22°C", "notes": "Cherry blossoms in early April. Great season for the Hallasan Eoseungsaengak trail and the Seogwipo coastal walks (Jeongbang Falls, Oedolgae, Olle 7)."}, {"season": "Summer (Jun–Aug)", "range": "22–30°C", "notes": "Humid; afternoon showers common. Jeongbang Falls and the Oedolgae coast stay cooler with the sea breeze."}, {"season": "Autumn (Sep–Nov)", "range": "10–24°C", "notes": "Best season — clear and mild, with the sharpest Oedolgae coast and Hallasan summit views."}, {"season": "Winter (Dec–Feb)", "range": "3–10°C", "notes": "Mild on the coast; Hallasan upper slopes can have snow and the 1100 Road may close."}]}, "seasonalVariations": [{"season": "Spring", "description": "Cherry blossoms and canola flowers bloom along the Seogwipo coast and across the route, and it is the best season for the Hallasan Eoseungsaengak walk."}, {"season": "Summer", "description": "The Jeongbang Falls and Oedolgae coast are popular summer retreats thanks to the cool sea breeze. Afternoon showers are common, so bring a rain jacket."}, {"season": "Autumn", "description": "Clear and crisp — the best season for photography. The Oedolgae coast and the Hallasan views are at their sharpest."}, {"season": "Winter", "description": "The coast stays mild, but snow can fall on Hallasan''s high slopes. When it snows, Route 1100 and Eoseungsaengak may be closed."}]}}, {"id": "booking_support", "section_html_id": null, "component": "TourBookingSupportSection", "props": {"bookingTrustItems": [{"icon": "check-circle", "title": "Licensed local operator", "description": "Fully insured, authorized Korean tour operator", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600", "body": "Licensed local operator — a great-value route taking in southern Seogwipo''s signature coastal stops in a small group."}, {"icon": "route", "title": "Route specialists", "description": "A hand-designed custom itinerary, not a generic loop", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "body": "Free admission at almost every stop: Oedolgae & Olle Route 7 (free), Yakcheonsa (free), O''sulloc (free), Hallasan Eoseungsaengak (free) — only Jeongbang Falls (₩2,000) included in the base."}, {"icon": "users", "title": "Comfortable group size", "description": "Right-sized for the route", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600", "body": "Run as a small-group minicoach, so you can enjoy the Oedolgae Olle trail, the Yakcheonsa grounds, and the Jeongbang Falls stairs in comfort — clearly different from a large bus tour."}], "bookingSupportSteps": [{"timing": "Immediately", "title": "Instant Confirmation", "detail": "Booking confirmation sent with an itinerary summary", "description": "Instant confirmation including Jeju City hotel pickup details (free within the city; +₩70,000 outside)."}, {"timing": "12 hours before", "title": "12-Hour Reminder", "detail": "Weather update and any route adjustments", "description": "Advance note on Jeongbang Falls / Oedolgae coastal conditions and the Hallasan Route 1100 status."}, {"timing": "Evening before", "title": "Final Pickup Info", "detail": "Exact pickup time and driver contact confirmed", "description": "Final pickup time confirmed the evening before."}, {"timing": "Morning of tour", "title": "Day-of Route Notes", "detail": "Morning briefing based on live conditions", "description": "Morning weather note and an update on the Hallasan Eoseungsaengak / Route 1100 status."}, {"timing": "During tour", "title": "Stop-by-Stop Tips", "detail": "Real-time guidance at each location", "description": "The guide explains the Jeongbang Falls ''Seobulgwacha'' place-name legend, the formation of Oedolgae and its ''Dae Jang Geum'' filming, East Asia''s largest temple Yakcheonsa, the 1979 founding of Amorepacific''s O''sulloc, and Hallasan''s shield-volcano character."}, {"timing": "After tour", "title": "Post-tour Support", "detail": "Follow-up and recommendations", "description": "A tour satisfaction survey request is sent after drop-off."}]}}, {"id": "faq", "section_html_id": "faq", "component": "TourFaqSection", "props": {"staticQuestions": [{"id": "q1", "question": "Is this tour available year-round?", "answer": "Yes. This route runs every day of the year. The atmosphere of the Seogwipo coast and the Hallasan views change with the season, but the day''s pacing stays the same. In winter snow, Hallasan Eoseungsaengak may be substituted for a lower-elevation alternate."}, {"id": "q2", "question": "Is the walking at Jeongbang Falls and Hallasan difficult?", "answer": "At Jeongbang Falls you go down and back up about 130 steps to the foot of the falls, and Hallasan Eoseungsaengak is a 1.3 km one-way wooden-stair climb (about 60–75 min round-trip). Comfortable closed-toe sneakers are enough — no technical hiking gear required. This route does not include the Hallasan summit (Baengnokdam) climb."}, {"id": "q3", "question": "Which sights are included on this route?", "answer": "You take in Jeongbang Falls (Asia''s only ocean-falling waterfall), the Oedolgae and Olle Route 7 coastal walk, East Asia''s largest temple Yakcheonsa, the O''sulloc Tea Museum, and the Hallasan Eoseungsaengak Trail. It is a south Jeju signature route that starts on the Seogwipo coast and finishes on Hallasan."}, {"id": "q4", "question": "Are admissions included?", "answer": "Yes. The Jeongbang Falls admission (adult ₩2,000) is included in the base price. Oedolgae & Olle Route 7, Yakcheonsa, O''sulloc, and Hallasan Eoseungsaengak are all free admission. The only real extra cost on the day is lunch (~₩15,000)."}, {"id": "q5", "question": "Is lunch included?", "answer": "No — lunch is at your own expense (~₩15,000). The guide will recommend a local restaurant, and if you advise at booking we can support vegetarian, vegan, halal, or allergy-related dietary needs."}, {"id": "q6", "question": "Can I bring luggage on the airport pickup?", "answer": "Yes. Please notify the operator of your luggage volume in advance. The mini-coach has dedicated luggage space, and travelers arriving on early-morning flights can join the tour directly with their bags."}, {"id": "first-time", "question": "Is this a good choice for first-time visitors to southern Jeju?", "answer": "Yes — in a single day you get a balanced look at the area''s most distinctive sights, from the Seogwipo coast to the temple, tea field, and Hallasan."}, {"id": "walking", "question": "Is the walking difficult?", "answer": "It is an active day with the Jeongbang Falls stairs and the Hallasan Eoseungsaengak climb, but the Oedolgae Olle trail and Yakcheonsa and O''sulloc are relatively flat."}, {"id": "family", "question": "Is this tour suitable for families?", "answer": "It suits families with children who can handle a full day of moving around. The coastal walks and the temple and tea field are easy for kids to enjoy too."}, {"id": "seniors", "question": "Can older adults join comfortably?", "answer": "Recommended for active seniors comfortable with the Jeongbang Falls stairs and the Eoseungsaengak climb. Oedolgae, Yakcheonsa, and O''sulloc are relatively comfortable."}, {"id": "children", "question": "What''s the recommended minimum age?", "answer": "Best fit is around age 10 and up — children who can handle a full-day itinerary and the walking notes above."}]}}, {"id": "reviews", "section_html_id": "reviews", "component": "TourReviewsSection", "props": {"guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}}}, {"id": "sticky_booking", "section_html_id": null, "component": "TourStickyBookingBar", "props": {"note": "Select your date and group size to check live availability and complete your booking.", "price": {"amountLabel": "59", "originalPriceUsd": 69, "salePriceUsd": 59, "discountPercent": 14, "currency": "USD", "per": "person"}}}], "itinerary_variants": [], "_publication": {"schema_version": "v4_canonical", "last_modified": "2026-06-24", "version_history": ["v11", "v12", "v13", "v14", "v15", "v15.2", "v18"], "fix_passes": {"v12": "P0+P1 — pickup_dropoff Schema A unification, routeFlowStops type-based, competing_products → internal slugs, anchor_poi_keys aligned", "v13": "P1.5 — pickup_dropoff Schema A.2 → A.1; practicalAccordionItems / routePhases / seasonalVariations unified to V4 standard (no Tailwind in data)", "v14": "P2 — _publication uniform; duration formatting standardized; glanceItems Duration added where missing", "v15": "P3 round 1 — SEO trim. seo.pageTitle rewritten to ≤65 chars (was 14/25 over 70); seo.metaDescription rewritten to ≤168 chars (was 25/25 over 170). primaryKeywords and ogImage unchanged. Hero/OG images, POI verification, review imports, and routePhases enrichment deferred to later P3 rounds.", "v15.2_charter_consolidation": "Removed \"jeju-popular-sightseeing-private-car-charter-tour\" from competing_products per Jason''s one-charter-per-region rule (jeju-island-private-car-charter-tour remains as standard Jeju charter).", "v17_schema_unification": {"date": "2026-04-28", "description": "Phase 1: Standardized matching_profile scores to the current 0-1 float scale used by match_tours.matching_profile.", "fields_converted": 43, "fields_skipped": 0, "fields_already_float": 0}, "v17_batch3_enhancement": {"date": "2026-04-28", "description": "Batch 3 deep enhancement — descriptions raised to 700-1100+ chars; KB-backed metadata on all attraction stops; matching_profile recalibrated with verified-fact 0-1 float scores. Indoor ratio computed time-weighted using KB indoor_ratio_at_stop methodology established in Fix 1.", "_score_audit": {"_methodology": "0-1 float scale. Indoor ratio computed time-weighted from KB indoor_ratio_at_stop values per Jason''s correction methodology.", "deltas_applied": {"unesco_fit": {"old": 1, "new": 0.95, "reasoning": "Verified: 2 of 6 stops directly UNESCO — Hallasan UNESCO World Heritage (Eoseungsaengak gateway) + Daepo Jusangjeolli is on UNESCO Global Geopark list. Cheonjeyeon Falls + O''sulloc + Camellia Hill are non-UNESCO. 0.95 reflects strong UNESCO core but not pure UNESCO loop."}, "walking_level": {"old": 0.8, "new": 0.65, "reasoning": "Verified totals: Eoseungsaengak 1.3 km + 169 m gain (steep), Camellia Hill ~2 km flat, Cheonjeyeon ~0.5 km + stair section, Jusangjeolli ~0.5 km flat boardwalk, O''sulloc 1 km flat. Total ~5 km + Eoseungsaengak elevation. Mechanical 0.8 was overstated; verified 0.65 with one moderate climb."}, "scenic_level": {"old": 0.8, "new": 0.9, "reasoning": "Verified 6 distinct landscape types: alpine oreum summit (Eoseungsaengak), botanical color-themed garden (Camellia Hill), three-tier waterfall + nymph bridge (Cheonjeyeon), basalt columnar coast (Jusangjeolli), tea-field rolling hills (O''sulloc). High landscape diversity = 0.9."}, "photo_level": {"old": 0.8, "new": 0.95, "reasoning": "Verified: 6 hero-image spots — Hallasan summit ridge, window-frame camellia (Camellia Hill signature), Seonimgyo nymph bridge over Cheonjeyeon, hexagonal basalt columns, O''sulloc tea fields. 0.95 calibrated."}, "iconic_landmark_fit": {"old": 1, "new": 0.85, "reasoning": "Verified: 3 of 6 stops universally iconic (Hallasan, Jusangjeolli, O''sulloc); Camellia Hill regionally iconic; Cheonjeyeon Falls famous. 0.85 calibrated."}, "stroller_fit": {"old": 0.6, "new": 0.5, "reasoning": "Verified: Camellia Hill flat paved (good), Jusangjeolli boardwalk (good), O''sulloc flat (good), Cheonjeyeon has steep stairs (NOT stroller-friendly), Eoseungsaengak is a 169 m climb (NOT stroller-friendly). 3/5 stroller-friendly = 0.5."}, "mobility_friendly_fit": {"old": 0.6, "new": 0.55, "reasoning": "Same logic as stroller_fit — Eoseungsaengak elevation + Cheonjeyeon stairs limit access. 3/5 stops mobility-friendly = 0.55."}, "indoor_ratio": {"old": 0.6, "new": 0.2, "reasoning": "MAJOR CORRECTION using time-weighted method (per Jason''s methodology): Eoseungsaengak 5%, Camellia Hill 15%, Cheonjeyeon Falls 5%, Jusangjeolli 0%, O''sulloc 50%, time-weighted = 50.25/330 ≈ 0.15 excluding lunch. With lunch (80% indoor) included: 98.25/390 = 0.25. Catalog value 0.20 represents the substantive-attraction average. Mechanical Phase 1 conversion 0.6 was wildly off."}, "weather_sensitivity": {"old": 0.6, "new": 0.8, "reasoning": "UPGRADED — 80% of stop time is outdoor. Eoseungsaengak summit very wind-and-weather exposed. Camellia Hill garden weather-dependent. Songaksan-style. Verified high weather sensitivity."}, "rain_fit": {"old": 0.6, "new": 0.4, "reasoning": "DOWNGRADED — only O''sulloc Tea Museum interior is a reliable rain refuge. Eoseungsaengak, Cheonjeyeon, Jusangjeolli, and most of Camellia Hill are weather-exposed. Verified poor rain hedge."}, "intangible_heritage_fit": {"old": 0.8, "new": 0.55, "reasoning": "Verified: only Cheonjeyeon Falls has direct intangible heritage (Chilseonyeo Festival, Seven Nymphs legend). Hallasan and Jusangjeolli are natural heritage but not intangible. O''sulloc tea ceremony has cultural significance but not registered intangible heritage. 0.55 calibrated."}, "first_time_fit": {"old": 1, "new": 0.95, "reasoning": "Verified: covers Hallasan UNESCO + columnar geopark + iconic waterfall + tea culture + flower garden — 5 distinct Jeju essentials. 0.95 is excellent first-Jeju overview but slightly missing food/beach themes."}, "value_for_money_fit": {"old": 1, "new": 0.85, "reasoning": "Verified fees: Camellia Hill ₩12,000 + others mostly free or ₩2,000. Total ~₩14,000 attraction fees per adult. Strong value but Camellia Hill is the cost driver. 0.85 calibrated."}, "young_kids_fit": {"old": 0.8, "new": 0.55, "reasoning": "DOWNGRADED — Eoseungsaengak 169 m climb taxing for under-7s; Cheonjeyeon stairs same issue. Camellia Hill, Jusangjeolli, O''sulloc all kid-friendly. 3/5 kid-friendly + 1 lunch = 0.55. Mechanical 0.8 overstated."}, "senior_fit": {"old": 0.6, "new": 0.55, "reasoning": "Slight downgrade — Eoseungsaengak climb + Cheonjeyeon stairs excludes mobility-impaired seniors. Active seniors fine; general seniors face real obstacles. 0.55 verified."}, "culture_level": {"old": 0.8, "new": 0.65, "reasoning": "DOWNGRADED — verified: 1 strong cultural anchor (O''sulloc tea museum + Korean tea heritage) + Cheonjeyeon legend. Most of the route is nature/garden. 0.65 calibrated."}}}, "stops_enhanced": 8, "sources": ["VisitKorea", "Visit Jeju", "Ramsar SIS", "AllTrails", "Inside Jeju", "Jeju Tourism Org"]}, "v18_route_change_seogwipo_coast": {"date": "2026-06-24", "description": "Route changed to the South Jeju (Seogwipo) coastal signature loop: Jeongbang Falls → Oedolgae & Olle Trail 7 → Yakcheonsa Temple → Lunch → Osulloc Tea Museum → Hallasan Eoseungsaengak. Pickup/drop-off points unchanged. Replaced Eoseungsaengak-opening / Camellia Hill / Cheonjeyeon / Jusangjeolli content; reused KB POIs 